/**
 * Typed client for the cap-edit-api Worker.
 *
 * In dev, vite proxies /api/* to wrangler dev on :8787 (vite.config.ts).
 * In production, the Worker serves both the SPA static assets and the API
 * on the same origin, so we just hit relative URLs.
 */

export type UserRole = "admin" | "editor" | "viewer";

export interface UserRow {
  email: string;
  role: UserRole;
  display_name?: string | null;
  created_at: string;
  updated_at: string;
}

export interface Me {
  email: string;
  name?: string;
  /** D1-backed role (admin / editor / viewer). Drives UI gating —
   *  Publish button only visible to admin; viewers can't save drafts. */
  role?: UserRole;
  local_dev?: boolean;
}

export interface DraftFields {
  name?: string;
  description?: string;
  sme_tier?: "required" | "preferred" | "advanced" | "deleted";
  in_checklist?: boolean;
  vendor_question?: string;       // Type 1 verbose
  vendor_question_terse?: string; // Type 1.1 single-line
  vendor_question_t2?: string;    // Type 2 umbrella bullet (verb-led summary)
  note?: string;
  /** Umbrella (cluster) override for Mandatory-tier multi-core modules.
   *  Cluster id from `preferred_clusters.required.clusters[].id` or
   *  `_other` for the synthetic tail. Routes into
   *  data/manual_cluster_assignments.yaml at publish time and is consumed
   *  by step19_apply_cluster_overrides.py at canonicalise. */
  cluster_id?: string;
}

export interface Draft {
  module: string;
  cap_id: string;
  fields: DraftFields;
  author: { email: string; name?: string };
  updated_at: string;
}

export interface AuditRow {
  id: number;
  module: string;
  cap_id: string;
  op: "save" | "clear" | "publish";
  fields: DraftFields | Record<string, unknown> | null;
  // Pre-edit values, populated on rows written after schema 0003. NULL on
  // older rows (rendered as "prior not captured" by the diff renderer).
  prior_fields: DraftFields | Record<string, unknown> | null;
  author: { email: string; name?: string };
  created_at: string;
  publish_commit_sha?: string | null;
}

export interface PublishResult {
  ok: boolean;
  applied: number;
  caps?: string[];
  commit_sha?: string;
  commit_url?: string;
  message?: string;
  drafts_applied?: number;
  reorders_applied?: number;
  reorder_modules?: string[];
  reorder_commit_sha?: string | null;
}

/** Module-state pending-reorder row returned by GET /api/audit/pending-reorders.
 *  Surfaced in the Pending edits view so reviewers can see what'll go to
 *  data/manual_reorder_overrides.yaml on Publish. */
export interface PendingReorder {
  synthetic_cap_id: "_cap_order";
  state_key: "cap_order";
  latest_fields: Record<string, unknown> | null;
  prior_fields: Record<string, unknown> | null;
  author: { email: string; name?: string };
  updated_at: string;
}

class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
  }
}

/**
 * GH Pages deploys have no /api/* backend. Two flavours:
 *   - VITE_VIEWER_ONLY=true   — read-only bridge build
 *   - VITE_GITHUB_NATIVE=true — v2 GitHub-API-direct build
 *
 * Both cases short-circuit the legacy editor API calls to safe stubs so the
 * SPA doesn't 404 itself before AuthContext renders. v2's real edit path
 * lives in src/lib/githubClient.ts; this module's stubs are just to keep the
 * legacy `api.me()` / `api.listDrafts()` etc. usable as no-ops during transition.
 */
const _viewerOnly = import.meta.env.VITE_VIEWER_ONLY === "true";
const _githubNative = import.meta.env.VITE_GITHUB_NATIVE === "true";
export const VIEWER_ONLY = _viewerOnly || _githubNative;

async function request<T>(path: string, init: RequestInit = {}): Promise<T> {
  const res = await fetch(path, {
    ...init,
    headers: {
      "content-type": "application/json",
      ...(init.headers || {}),
    },
  });
  if (!res.ok) {
    const body = await res.text();
    throw new ApiError(res.status, `${res.status}: ${body.slice(0, 200)}`);
  }
  return res.json() as Promise<T>;
}

// Static stub returned by api.me() in VIEWER_ONLY mode. role=viewer hides the
// Publish button + BUILD-tools admin nav entries via the existing role gates,
// so the SPA collapses to a clean read-only surface with no additional code
// changes in the UI layer.
const VIEWER_ME: Me = { email: "guest@gh-pages", name: "Guest viewer", role: "viewer" };

export const api = {
  me: () => VIEWER_ONLY ? Promise.resolve(VIEWER_ME) : request<Me>("/api/me"),

  listDrafts: () =>
    VIEWER_ONLY
      ? Promise.resolve([] as Draft[])
      : request<{ drafts: Draft[] }>("/api/drafts").then(r => r.drafts),

  getDraft: (mod: string, capId: string) =>
    VIEWER_ONLY
      ? Promise.reject(new ApiError(404, "viewer-only: no drafts"))
      : request<Draft>(`/api/drafts/${encodeURIComponent(mod)}/${encodeURIComponent(capId)}`),

  saveDraft: (mod: string, capId: string, fields: DraftFields) =>
    VIEWER_ONLY
      ? Promise.reject(new ApiError(403, "viewer-only: editing disabled"))
      : request<Draft>(
          `/api/drafts/${encodeURIComponent(mod)}/${encodeURIComponent(capId)}`,
          { method: "PUT", body: JSON.stringify({ fields }) },
        ),

  clearDraft: (mod: string, capId: string) =>
    VIEWER_ONLY
      ? Promise.reject(new ApiError(403, "viewer-only: editing disabled"))
      : request<{ ok: true }>(
          `/api/drafts/${encodeURIComponent(mod)}/${encodeURIComponent(capId)}`,
          { method: "DELETE" },
        ),

  publish: () =>
    VIEWER_ONLY
      ? Promise.reject(new ApiError(403, "viewer-only: publish disabled"))
      : request<PublishResult>("/api/publish", { method: "POST" }),

  // ── User management (admin only — server enforces) ────────────────
  listUsers: () =>
    request<{ users: UserRow[]; default_role: UserRole }>("/api/users"),

  setUserRole: (email: string, role: UserRole, displayName?: string | null) =>
    request<{ ok: true; email: string; role: UserRole; display_name: string | null }>(
      `/api/users/${encodeURIComponent(email)}`,
      { method: "PUT", body: JSON.stringify({ role, display_name: displayName ?? null }) },
    ),

  removeUser: (email: string) =>
    request<{ ok: true; email: string; removed: true; default_role: UserRole }>(
      `/api/users/${encodeURIComponent(email)}`,
      { method: "DELETE" },
    ),

  /** Admin-only — D1 row counts + latest-activity timestamps. */
  d1Health: () =>
    request<{
      ok: boolean;
      tables: Record<string, { table: string; count: number | null; ok: boolean; error?: string }>;
      latest: { draft_updated_at: string | null; audit_log_created_at: string | null };
      checked_at: string;
    }>("/api/health/d1"),

  audit: (filters: { module?: string; cap_id?: string; author?: string; limit?: number } = {}) => {
    if (VIEWER_ONLY) return Promise.resolve([] as AuditRow[]);
    const qs = new URLSearchParams();
    for (const [k, v] of Object.entries(filters)) {
      if (v !== undefined && v !== null) qs.set(k, String(v));
    }
    const suffix = qs.toString() ? `?${qs}` : "";
    return request<{ rows: AuditRow[] }>(`/api/audit${suffix}`).then(r => r.rows);
  },

  /** Pending reorder rows for one module — used by Pending edits view. */
  pendingReorders: (mod: string) =>
    VIEWER_ONLY
      ? Promise.resolve([] as PendingReorder[])
      : request<{ pending: PendingReorder[] }>(
          `/api/audit/pending-reorders?module=${encodeURIComponent(mod)}`,
        ).then(r => r.pending),
};

export { ApiError };
