/**
 * Per-user module-state CRUD on GitHub branches.
 *
 * Mirrors the draft model: each user has a `drafts/<github-username>` branch
 * holding their work-in-progress for non-cap state — `cap_order` per
 * umbrella and `ai_features_response` per module.
 *
 *   drafts/<user>/cap_order/<module>.json
 *     {
 *       "umbrellaKey1": ["cap_id_1", "cap_id_2", ...],
 *       "umbrellaKey2": [...]
 *     }
 *
 *   drafts/<user>/ai_features/<module>.json
 *     { "checkedTitles": [...], "othersText": "..." }
 *
 * Published values live on main:
 *   data/manual_reorder_overrides.yaml   ← cap_order (multi-module, multi-user merge)
 *   data/_state/ai_features_<module>.json ← AI features response (publisher-wins)
 *
 * Each user sees their own working copy; Publish promotes it to main.
 */
import {
  ensureBranch,
  getFileWithSha,
  putFile,
  type GitHubAuth,
} from "./githubClient";
import type { AiFeaturesResponse } from "./aiFeatures";

const DRAFT_BRANCH_PREFIX = "drafts/";

function draftBranch(username: string): string {
  return `${DRAFT_BRANCH_PREFIX}${username}`;
}

function capOrderPath(username: string, module: string): string {
  return `drafts/${username}/cap_order/${module}.json`;
}

function aiFeaturesPath(username: string, module: string): string {
  return `drafts/${username}/ai_features/${module}.json`;
}

function publishedCapOrderPath(): string {
  return `data/manual_reorder_overrides.yaml`;
}

function publishedAiFeaturesPath(module: string): string {
  return `data/_state/ai_features_${module}.json`;
}

export type CapOrderMap = Record<string, string[]>;

// ── Cap order ─────────────────────────────────────────────────────────────

export async function getUserCapOrder(
  auth: GitHubAuth,
  username: string,
  module: string,
): Promise<CapOrderMap> {
  const file = await getFileWithSha(auth, capOrderPath(username, module), draftBranch(username));
  if (!file) return {};
  try {
    const parsed = JSON.parse(file.text) as Record<string, unknown>;
    // Tombstone written by clearUserCapOrder — treat as no draft so the
    // Reorder pending pill goes away and Publish stops counting it.
    if (parsed && parsed._discarded === true) return {};
    return parsed as CapOrderMap;
  } catch {
    return {};
  }
}

export async function putUserCapOrder(
  auth: GitHubAuth,
  username: string,
  module: string,
  value: CapOrderMap,
): Promise<void> {
  await ensureBranch(auth, draftBranch(username), "main");
  const path = capOrderPath(username, module);
  const branch = draftBranch(username);
  const existing = await getFileWithSha(auth, path, branch);
  const body = JSON.stringify(value, null, 2) + "\n";
  const message = existing
    ? `editor(state): update cap_order ${module} (by ${username})`
    : `editor(state): set cap_order ${module} (by ${username})`;
  await putFile(auth, branch, path, body, message, existing?.sha);
}

// ── AI features response ──────────────────────────────────────────────────

export async function getUserAiFeatures(
  auth: GitHubAuth,
  username: string,
  module: string,
): Promise<AiFeaturesResponse | null> {
  const file = await getFileWithSha(auth, aiFeaturesPath(username, module), draftBranch(username));
  if (!file) return null;
  try {
    const parsed = JSON.parse(file.text) as Partial<AiFeaturesResponse> & { _discarded?: boolean };
    if (parsed?._discarded === true) return null;
    return {
      checkedTitles: Array.isArray(parsed.checkedTitles) ? parsed.checkedTitles : [],
      othersText: typeof parsed.othersText === "string" ? parsed.othersText : "",
    };
  } catch {
    return null;
  }
}

export async function putUserAiFeatures(
  auth: GitHubAuth,
  username: string,
  module: string,
  value: AiFeaturesResponse,
): Promise<void> {
  await ensureBranch(auth, draftBranch(username), "main");
  const path = aiFeaturesPath(username, module);
  const branch = draftBranch(username);
  const existing = await getFileWithSha(auth, path, branch);
  const body = JSON.stringify(value, null, 2) + "\n";
  const message = existing
    ? `editor(state): update ai_features ${module} (by ${username})`
    : `editor(state): set ai_features ${module} (by ${username})`;
  await putFile(auth, branch, path, body, message, existing?.sha);
}

// ── Tombstone-based discard for module-state JSON files ───────────────────
// Same shape as the cap-field draft tombstone (`_discarded: true`) — kept
// out of Publish + Pending edits view by the read-side filters. Writing a
// tombstone instead of DELETE-ing the file mirrors clearDraft (drafts.ts):
// the GitHub Contents API DELETE was historically unreliable across the
// proxies sitting between the SPA and api.github.com, and tombstone PUTs
// just work.

const DISCARDED_JSON = JSON.stringify({ _discarded: true }, null, 2) + "\n";

export async function clearUserCapOrder(
  auth: GitHubAuth,
  username: string,
  module: string,
): Promise<void> {
  await ensureBranch(auth, draftBranch(username), "main");
  const path = capOrderPath(username, module);
  const branch = draftBranch(username);
  const existing = await getFileWithSha(auth, path, branch);
  // No file → nothing to discard. (Should not happen if the user could see
  // a Pending card for this entry; guards against double-clicks.)
  if (!existing) return;
  const message = `editor(state): discard cap_order ${module} (by ${username})`;
  await putFile(auth, branch, path, DISCARDED_JSON, message, existing.sha);
}

export async function clearUserAiFeatures(
  auth: GitHubAuth,
  username: string,
  module: string,
): Promise<void> {
  await ensureBranch(auth, draftBranch(username), "main");
  const path = aiFeaturesPath(username, module);
  const branch = draftBranch(username);
  const existing = await getFileWithSha(auth, path, branch);
  if (!existing) return;
  const message = `editor(state): discard ai_features ${module} (by ${username})`;
  await putFile(auth, branch, path, DISCARDED_JSON, message, existing.sha);
}

// ── Published state (read-only fallback when no user draft exists) ────────

/** Read the published cap_order for a module from main. Falls back to {}
 *  when the YAML doesn't exist or the module isn't yet in it. */
export async function getPublishedCapOrder(
  auth: GitHubAuth,
  module: string,
): Promise<CapOrderMap> {
  const file = await getFileWithSha(auth, publishedCapOrderPath(), "main");
  if (!file) return {};
  // Minimal YAML extraction — we own the file format from the worker, but
  // here we just need the cap_order map for one module. Cheap regex extract
  // saves pulling a yaml library into the bundle for this read.
  try {
    return parseCapOrderFromYaml(file.text, module);
  } catch {
    return {};
  }
}

function parseCapOrderFromYaml(yaml: string, module: string): CapOrderMap {
  // The published file is auto-generated by the worker's
  // buildReorderOverridesYaml (workers/cap-edit-api/src/index.js). Format:
  //   modules:
  //     <module>:
  //       cap_order:
  //         '<umbrella>':
  //           - cap_id_1
  //           - cap_id_2
  const out: CapOrderMap = {};
  const lines = yaml.split("\n");
  let inModule = false;
  let inCapOrder = false;
  let currentUmbrella: string | null = null;
  for (const line of lines) {
    if (/^modules:/.test(line)) continue;
    const modMatch = line.match(/^  ([\w]+):\s*$/);
    if (modMatch) {
      inModule = modMatch[1] === module;
      inCapOrder = false;
      currentUmbrella = null;
      continue;
    }
    if (!inModule) continue;
    if (/^    cap_order:/.test(line)) { inCapOrder = true; continue; }
    if (/^    [\w_]+:/.test(line) && !/^    cap_order:/.test(line)) {
      // Sibling key under the module block (e.g. sub_module_order if we ever
      // re-add it) — exits cap_order context.
      inCapOrder = false;
      continue;
    }
    if (!inCapOrder) continue;
    const umbrellaMatch = line.match(/^      '([^']+)':\s*$/);
    if (umbrellaMatch) {
      currentUmbrella = umbrellaMatch[1];
      out[currentUmbrella] = [];
      continue;
    }
    const idMatch = line.match(/^        - '?([\w.]+)'?\s*$/);
    if (idMatch && currentUmbrella) {
      out[currentUmbrella].push(idMatch[1]);
    }
  }
  return out;
}

/** Read the published AI features response for a module from main. */
export async function getPublishedAiFeatures(
  auth: GitHubAuth,
  module: string,
): Promise<AiFeaturesResponse | null> {
  const file = await getFileWithSha(auth, publishedAiFeaturesPath(module), "main");
  if (!file) return null;
  try {
    const parsed = JSON.parse(file.text) as Partial<AiFeaturesResponse>;
    return {
      checkedTitles: Array.isArray(parsed.checkedTitles) ? parsed.checkedTitles : [],
      othersText: typeof parsed.othersText === "string" ? parsed.othersText : "",
    };
  } catch {
    return null;
  }
}

export const _internal = {
  draftBranch, capOrderPath, aiFeaturesPath,
  publishedCapOrderPath, publishedAiFeaturesPath,
  parseCapOrderFromYaml,
};
