import { useEffect, useMemo, useState } from "react";
import type { Capability, SmeTier } from "../types/canonical";
import { api, type Draft, type PendingReorder } from "../lib/api";
import { useDrafts } from "../contexts/DraftsContext";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import { useModuleState } from "../contexts/ModuleStateContext";
import { listAllPendingModuleState, type PendingModuleStateEntry } from "../lib/drafts";
import { clearUserCapOrder, clearUserAiFeatures } from "../lib/moduleState";
import { tierLabel } from "../lib/tier";
import "./PendingEditsView.css";

export interface Props {
  module: string;
  caps: Capability[];
}

interface FieldDiffRow {
  field: string;
  before: unknown;
  after: unknown;
}

function canonicalValue(c: Capability, field: string): unknown {
  if (field === "name") return c.name;
  if (field === "description") return c.description;
  if (field === "sme_tier") return c.sme_tier;
  if (field === "in_checklist") return c.in_checklist !== false;
  if (field === "vendor_question") return c.vendor_questions?.question;
  if (field === "vendor_question_terse") return c.vendor_questions?.question_terse;
  if (field === "vendor_question_t2") return c.vendor_questions?.question_t2;
  if (field === "note") return undefined;
  return undefined;
}

function diffOf(c: Capability, draft: Draft): FieldDiffRow[] {
  const out: FieldDiffRow[] = [];
  for (const [field, after] of Object.entries(draft.fields)) {
    const before = canonicalValue(c, field);
    if (before === after) continue;
    out.push({ field, before, after });
  }
  return out;
}

function formatValue(v: unknown, field?: string): string {
  if (v === undefined || v === null || v === "") return "(none)";
  if (typeof v === "boolean") return v ? "true" : "false";
  if (typeof v === "object") return JSON.stringify(v);
  // Tier values get the friendly canonical label (Mandatory / Preferred / Advanced).
  if (field === "sme_tier") return tierLabel(String(v));
  return String(v);
}

function formatTime(iso: string): string {
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    return d.toISOString().replace("T", " ").slice(0, 16) + " UTC";
  } catch {
    return iso;
  }
}

function summariseReorder(value: Record<string, unknown> | null): string {
  if (!value || typeof value !== "object") return "(no payload)";
  const inner = value.cap_order;
  if (!inner || typeof inner !== "object") return "(empty)";
  const entries = Object.entries(inner as Record<string, unknown>);
  if (entries.length === 0) return "(empty)";
  const parts = entries.map(([umbrella, arr]) => {
    const count = Array.isArray(arr) ? arr.length : 0;
    return `${umbrella} (${count})`;
  });
  if (parts.length <= 3) return parts.join(", ");
  return `${parts.slice(0, 3).join(", ")} +${parts.length - 3} more`;
}

export function PendingEditsView({ module, caps }: Props) {
  const { draftsByCap, loading, error, clearDraft } = useDrafts();
  const { auth: ghAuth, user: ghUser } = useAuth();
  // Listening to ModuleStateContext so the view re-fetches when the user
  // saves a reorder / AI features toggle. flushStatus updates whenever a
  // PUT lands, which is the right "the underlying data just changed"
  // signal for the cap-order + AI features files on GitHub.
  const { flushStatus } = useModuleState();
  const [pendingReorders, setPendingReorders] = useState<PendingReorder[]>([]);
  // v2-only: per-user reorder + AI features pending entries enumerated
  // across all draft branches. Empty in v1 (CF Worker exposes a different
  // shape via api.pendingReorders).
  const [v2ModuleState, setV2ModuleState] = useState<PendingModuleStateEntry[]>([]);
  const [reorderError, setReorderError] = useState<string | null>(null);
  // Manual refresh button increments this; effect re-runs.
  const [refreshTick, setRefreshTick] = useState(0);

  // Re-fetch on focus too — user came back from another tab where they
  // might have edited drafts (or another reviewer pushed new state).
  useEffect(() => {
    const onFocus = () => setRefreshTick(t => t + 1);
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, []);

  // Bump refresh when any flushStatus entry transitions to "saved" — that's
  // exactly the moment a reorder / AI features save landed on GitHub.
  const savedFingerprint = useMemo(
    () => Object.entries(flushStatus).filter(([, v]) => v === "saved").map(([k]) => k).sort().join(","),
    [flushStatus],
  );
  useEffect(() => {
    if (savedFingerprint) setRefreshTick(t => t + 1);
  }, [savedFingerprint]);

  useEffect(() => {
    let cancelled = false;
    if (GITHUB_NATIVE) {
      if (!ghAuth) {
        setPendingReorders([]);
        setV2ModuleState([]);
        return;
      }
      listAllPendingModuleState(ghAuth, module)
        .then(entries => { if (!cancelled) setV2ModuleState(entries); })
        .catch(e => { if (!cancelled) setReorderError(e instanceof Error ? e.message : String(e)); });
    } else {
      api.pendingReorders(module)
        .then(rows => { if (!cancelled) setPendingReorders(rows); })
        .catch(e => { if (!cancelled) setReorderError(e instanceof Error ? e.message : String(e)); });
    }
    return () => { cancelled = true; };
  }, [module, ghAuth, refreshTick]);

  const handleDiscard = async (capId: string, capName: string) => {
    const ok = window.confirm(
      `Discard draft for "${capName}"?\n\nThis cannot be undone — the unpublished changes will be lost.`,
    );
    if (!ok) return;
    try {
      await clearDraft(module, capId);
    } catch (e) {
      window.alert(`Failed to discard draft: ${(e as Error).message || e}`);
    }
  };

  // Discard a pending reorder for the SIGNED-IN user (the only branch the
  // SPA can write to). Writes a tombstone JSON; the Pending list filters it
  // out + the canonical view re-falls-back to the published order on next
  // refresh.
  const handleDiscardReorder = async (username: string) => {
    if (!ghAuth) return;
    if (!window.confirm("Discard this pending reorder? The published cap_order on main is unaffected.")) return;
    try {
      await clearUserCapOrder(ghAuth, username, module);
      setRefreshTick(t => t + 1);
    } catch (e) {
      window.alert(`Failed to discard reorder: ${(e as Error).message || e}`);
    }
  };

  const handleDiscardAi = async (username: string) => {
    if (!ghAuth) return;
    if (!window.confirm("Discard pending AI Features changes? The published response on main is unaffected.")) return;
    try {
      await clearUserAiFeatures(ghAuth, username, module);
      setRefreshTick(t => t + 1);
    } catch (e) {
      window.alert(`Failed to discard AI features: ${(e as Error).message || e}`);
    }
  };

  const capById = useMemo(() => {
    const m = new Map<string, Capability>();
    for (const c of caps) m.set(c.id, c);
    return m;
  }, [caps]);

  // Collect drafts that belong to this module AND map to a real cap.
  const pending = useMemo(() => {
    const items: Array<{ cap: Capability; draft: Draft; diff: FieldDiffRow[] }> = [];
    draftsByCap.forEach(d => {
      if (d.module !== module) return;
      const cap = capById.get(d.cap_id);
      if (!cap) return;
      items.push({ cap, draft: d, diff: diffOf(cap, d) });
    });
    items.sort((a, b) => (b.draft.updated_at || "").localeCompare(a.draft.updated_at || ""));
    return items;
  }, [draftsByCap, capById, module]);

  if (loading) {
    return <div className="pe-msg muted">Loading drafts…</div>;
  }
  if (error) {
    return <div className="pe-msg error">Failed to load drafts: {error}</div>;
  }

  const v2ReorderCount = v2ModuleState.filter(e => e.cap_order && Object.keys(e.cap_order).length > 0).length;
  const v2AiCount = v2ModuleState.filter(e => e.ai_features).length;
  const reorderRowCount = pendingReorders.length + v2ReorderCount;
  const aiRowCount = v2AiCount;
  const totalPending = pending.length + reorderRowCount + aiRowCount;
  if (totalPending === 0) {
    return (
      <div className="pe-msg muted">
        No pending edits in this module — every cap's published canonical state matches its draft, and no
        reorder or AI features change is awaiting publish.
      </div>
    );
  }

  const summaryParts: string[] = [];
  if (pending.length > 0) summaryParts.push(`${pending.length} cap edit${pending.length === 1 ? "" : "s"}`);
  if (reorderRowCount > 0) summaryParts.push(`${reorderRowCount} reorder${reorderRowCount === 1 ? "" : "s"}`);
  if (aiRowCount > 0) summaryParts.push(`${aiRowCount} AI features change${aiRowCount === 1 ? "" : "s"}`);

  return (
    <div className="pe-list">
      <p className="pe-summary muted small">
        {totalPending} pending change{totalPending === 1 ? "" : "s"}
        {summaryParts.length > 0 ? ` (${summaryParts.join(" + ")})` : ""}.
        Click <strong>Publish</strong> in the bottom-right to commit to YAML.
      </p>

      {reorderError && (
        <div className="pe-msg error">Failed to load reorder state: {reorderError}</div>
      )}

      {/* v1: pendingReorders rows from /api/audit/pending-reorders (CF Worker). */}
      {pendingReorders.map(r => (
        <article key={r.synthetic_cap_id} className="pe-card pe-reorder-card">
          <header className="pe-card-head">
            <code className="pe-cap-id">{r.synthetic_cap_id}</code>
            <h4 className="pe-cap-name">Cap order changes</h4>
            <span className="pe-author">
              {r.author?.email || "?"} · {formatTime(r.updated_at)}
            </span>
          </header>
          <div className="pe-noop">
            Umbrellas with new order: <code>{summariseReorder(r.latest_fields)}</code>
          </div>
        </article>
      ))}

      {/* v2: per-user reorder + AI features pending entries from GitHub branches. */}
      {v2ModuleState.map(entry => {
        const isOwn = !!ghUser && entry.username === ghUser.login;
        return (
          <article key={`v2-state-${entry.username}`} className="pe-card pe-reorder-card">
            <header className="pe-card-head">
              <code className="pe-cap-id">@{entry.username}</code>
              <h4 className="pe-cap-name">
                {entry.cap_order ? "Cap order" : ""}
                {entry.cap_order && entry.ai_features ? " + " : ""}
                {entry.ai_features ? "AI features" : ""} changes
              </h4>
              <span className="pe-author">{entry.username}</span>
            </header>
            {entry.cap_order && (
              <div className="pe-state-row">
                <div className="pe-state-detail">
                  <strong>New cap order — </strong>
                  {Object.entries(entry.cap_order).map(([umbrella, ids]) => (
                    <div key={umbrella} className="pe-state-umbrella">
                      <code className="pe-state-umbrella-key">{umbrella}</code>
                      <ol className="pe-state-cap-list">
                        {(ids as string[]).map((capId, idx) => (
                          <li key={capId}>
                            <span className="pe-state-cap-pos">{String(idx + 1).padStart(2, "0")}.</span>
                            <code className="pe-state-cap-id">{capId}</code>
                          </li>
                        ))}
                      </ol>
                    </div>
                  ))}
                </div>
                {isOwn && (
                  <button
                    type="button"
                    className="pe-discard"
                    onClick={() => handleDiscardReorder(entry.username)}
                    title="Discard this pending reorder (cannot be undone)"
                    aria-label="Discard pending reorder"
                  >
                    ✕
                  </button>
                )}
              </div>
            )}
            {entry.ai_features && (
              <div className="pe-state-row">
                <div className="pe-state-detail">
                  AI features: {entry.ai_features.checkedTitles.length} checked
                  {entry.ai_features.othersText.trim().length > 0 ? " + custom text" : ""}
                </div>
                {isOwn && (
                  <button
                    type="button"
                    className="pe-discard"
                    onClick={() => handleDiscardAi(entry.username)}
                    title="Discard pending AI Features changes"
                    aria-label="Discard pending AI Features"
                  >
                    ✕
                  </button>
                )}
              </div>
            )}
          </article>
        );
      })}

      {pending.map(({ cap, draft, diff }) => (
        <article key={cap.id} className="pe-card">
          <header className="pe-card-head">
            <code className="pe-cap-id">{cap.id}</code>
            <h4 className="pe-cap-name">{cap.name}</h4>
            <span className="pe-author">
              {draft.author?.email || "?"} · {formatTime(draft.updated_at)}
            </span>
            <button
              type="button"
              className="pe-discard"
              onClick={() => handleDiscard(cap.id, cap.name || cap.id)}
              title="Discard this draft (cannot be undone)"
              aria-label={`Discard draft for ${cap.name || cap.id}`}
            >
              ✕
            </button>
          </header>
          {diff.length === 0 ? (
            <div className="pe-noop muted small">
              Draft fields all match canonical — publishing this draft would be a no-op.
            </div>
          ) : (
            <div className="pe-diff">
              {diff.map(d => (
                <div key={d.field} className="pe-diff-row">
                  <code className="pe-field">{d.field}</code>
                  <span className="pe-now">
                    <span className="pe-label">Now:</span>
                    <span className="pe-now-value">{formatValue(d.before, d.field)}</span>
                  </span>
                  <span className="pe-arrow">→</span>
                  <span className="pe-draft">
                    <span className="pe-label">Draft:</span>
                    <span className="pe-draft-value">{formatValue(d.after, d.field)}</span>
                  </span>
                </div>
              ))}
            </div>
          )}
        </article>
      ))}
    </div>
  );
}

// Re-export helpers used in tests for clarity.
export { diffOf as _diffOf, formatValue as _formatValue };
export type { FieldDiffRow as _FieldDiffRow };
// SmeTier kept exported in case downstream type checks need it.
export type { SmeTier };
