import type { Capability } from "../types/canonical";
import { CapEditor } from "./CapEditor";
import "./QuickEditPane.css";

export interface Props {
  module: string;
  caps: Capability[];
  signedInEmail?: string;
}

/**
 * Side-by-side bulk-edit pane. Reuses CapEditor with a no-op onClose so the
 * editor stays mounted after a save; the user can keep editing more caps in
 * sequence without a hide/show round trip. CanonicalPage renders this as the
 * right-hand pane; the left pane stays the chosen Final preview (Type 2 /
 * Type 1.1) so authors can see the deliverable shape while editing.
 */
export function QuickEditPane({ module, caps, signedInEmail: _signedInEmail }: Props) {
  if (caps.length === 0) {
    return (
      <div className="quickedit-pane quickedit-pane-empty">
        <p>No caps to edit in this view.</p>
      </div>
    );
  }
  return (
    <div className="quickedit-pane">
      <h3 className="quickedit-pane-heading">
        Bulk edit · <span className="quickedit-count">{caps.length}</span> caps
      </h3>
      <div className="quickedit-list">
        {caps.map(cap => (
          <article key={cap.id} className="quickedit-card">
            <header className="quickedit-card-head">
              <code className="quickedit-cap-id">{cap.id}</code>
              <h4 className="quickedit-cap-name">{cap.name}</h4>
            </header>
            <CapEditor
              module={module}
              cap={cap}
              onClose={() => {
                // No-op: in Quick Edit the editor is always exposed. Save
                // succeeds → CapEditor calls onClose → we leave the editor
                // mounted so the user can refine fields further.
              }}
            />
          </article>
        ))}
      </div>
    </div>
  );
}
