import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import { api, type Draft, type DraftFields } from "../lib/api";
import { GITHUB_NATIVE, useAuth } from "./AuthContext";
import * as gh from "../lib/drafts";
import { publishUserDrafts } from "../lib/publish";

/**
 * Centralised draft state for the SPA.
 *
 * Two backing stores, picked by the build-time GITHUB_NATIVE flag:
 *
 *   v1 (CF Worker)         — drafts live in D1 (`drafts` table). Reads/writes
 *                            via `api.listDrafts() / saveDraft() / clearDraft()`
 *                            which hit the Worker's /api/drafts/* routes.
 *
 *   v2 (GitHub-native)     — drafts live on per-user git branches
 *                            (`drafts/<github-username>`). Reads/writes go
 *                            through `src/lib/drafts.ts` directly to
 *                            api.github.com. Auth comes from AuthContext.
 *
 * The DraftsContext interface (draftsByCap / saveDraft / clearDraft / publish)
 * is identical across both surfaces so consumers (CapEditor, PendingEditsView,
 * PublishButton) don't branch.
 */

interface DraftsContextValue {
  draftsByCap: Map<string, Draft>;
  /** Count of pending module-state files (cap_order + ai_features) on
   *  the signed-in user's draft branch. These are NOT in draftsByCap
   *  but DO need to be published. PublishButton + Pending edits use this
   *  to decide whether to surface a Publish action when only module-state
   *  has changed (e.g. just a reorder, no cap edits). */
  moduleStatePendingCount: number;
  loading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
  getDraft: (module: string, capId: string) => Draft | undefined;
  getDraftFields: (module: string, capId: string) => DraftFields | undefined;
  saveDraft: (module: string, capId: string, fields: DraftFields) => Promise<void>;
  clearDraft: (module: string, capId: string) => Promise<void>;
  publish: () => Promise<{ ok: boolean; applied: number; commit_url?: string; message?: string }>;
}

const DraftsContext = createContext<DraftsContextValue | null>(null);

function key(module: string, capId: string) {
  return `${module}:${capId}`;
}

function draftFromGhRecord(rec: gh.DraftRecord): Draft {
  // Drafts library uses the email + username from the YAML frontmatter; the
  // existing UI shape only carries `author.email`, so we stash the username
  // inside `author.name` so the existing rendering ("draft by @username")
  // gets a real label.
  return {
    module: rec.module,
    cap_id: rec.cap_id,
    fields: rec.fields,
    author: {
      email: rec.author_email || rec.author_username,
      name: rec.author_username || undefined,
    },
    updated_at: rec.updated_at,
  };
}

export function DraftsProvider({ children }: { children: ReactNode }) {
  const auth = useAuth();
  const [draftsByCap, setDraftsByCap] = useState<Map<string, Draft>>(new Map());
  const [moduleStatePendingCount, setModuleStatePendingCount] = useState<number>(0);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Effective auth identity (v2 only). `signedInUser` is null when we're
  // not signed in yet OR when running v1. v2 callers that need the username
  // can guard on this.
  const ghAuth = GITHUB_NATIVE ? auth.auth : null;
  const ghUser = GITHUB_NATIVE ? auth.user : null;

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      if (GITHUB_NATIVE) {
        if (!ghAuth) {
          // Not signed in yet — empty draft set, no API calls.
          setDraftsByCap(new Map());
          setModuleStatePendingCount(0);
          return;
        }
        const records = await gh.listAllDrafts(ghAuth);
        const next = new Map<string, Draft>();
        for (const r of records) next.set(key(r.module, r.cap_id), draftFromGhRecord(r));
        setDraftsByCap(next);
        // Count module-state pending entries for the SIGNED-IN user only
        // (PublishButton publishes the signed-in user's branch — counting
        // other users' module-state would mislead the button gating).
        if (ghUser?.login) {
          gh.countModuleStateForUser(ghAuth, ghUser.login)
            .then(setModuleStatePendingCount)
            .catch(() => setModuleStatePendingCount(0));
        }
      } else {
        const drafts = await api.listDrafts();
        const next = new Map<string, Draft>();
        for (const d of drafts) next.set(key(d.module, d.cap_id), d);
        setDraftsByCap(next);
        setModuleStatePendingCount(0); // v1 has no separate module-state path
      }
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      setError(msg);
      console.warn("[drafts] refresh failed:", msg);
    } finally {
      setLoading(false);
    }
  }, [ghAuth]);

  // Initial load + on focus refresh
  useEffect(() => {
    refresh();
    const onFocus = () => { refresh(); };
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, [refresh]);

  const getDraft = useCallback(
    (module: string, capId: string) => draftsByCap.get(key(module, capId)),
    [draftsByCap],
  );

  const getDraftFields = useCallback(
    (module: string, capId: string) => draftsByCap.get(key(module, capId))?.fields,
    [draftsByCap],
  );

  const saveDraft = useCallback(async (module: string, capId: string, fields: DraftFields) => {
    if (!fields || Object.keys(fields).length === 0) return;

    // Optimistic update — UI reflects the change immediately.
    setDraftsByCap(prev => {
      const next = new Map(prev);
      const existing = next.get(key(module, capId));
      next.set(key(module, capId), {
        module, cap_id: capId, fields,
        author: existing?.author || {
          email: ghUser?.email || ghUser?.login || "(you)",
          name: ghUser?.login,
        },
        updated_at: new Date().toISOString(),
      });
      return next;
    });

    try {
      if (GITHUB_NATIVE) {
        if (!ghAuth || !ghUser) {
          throw new Error("Not signed in — sign in to save drafts.");
        }
        const rec = await gh.saveDraft(
          ghAuth,
          ghUser.login,
          ghUser.email || ghUser.login,
          module, capId, fields,
        );
        setDraftsByCap(prev => {
          const next = new Map(prev);
          next.set(key(module, capId), draftFromGhRecord(rec));
          return next;
        });
      } else {
        const saved = await api.saveDraft(module, capId, fields);
        setDraftsByCap(prev => {
          const next = new Map(prev);
          next.set(key(module, capId), saved);
          return next;
        });
      }
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      console.warn("[drafts] save failed, refetching:", msg);
      await refresh();
      throw e;
    }
  }, [refresh, ghAuth, ghUser]);

  const clearDraft = useCallback(async (module: string, capId: string) => {
    setDraftsByCap(prev => {
      const next = new Map(prev);
      next.delete(key(module, capId));
      return next;
    });
    try {
      if (GITHUB_NATIVE) {
        if (!ghAuth || !ghUser) {
          throw new Error("Not signed in — sign in to clear drafts.");
        }
        await gh.clearDraft(ghAuth, ghUser.login, module, capId);
      } else {
        await api.clearDraft(module, capId);
      }
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      console.warn("[drafts] clear failed, refetching:", msg);
      await refresh();
      throw e;
    }
  }, [refresh, ghAuth, ghUser]);

  const publish = useCallback(async () => {
    if (GITHUB_NATIVE) {
      if (!ghAuth || !ghUser) {
        return {
          ok: false, applied: 0,
          message: "Not signed in — sign in to publish.",
        };
      }
      const result = await publishUserDrafts(
        ghAuth, ghUser.login, ghUser.email || ghUser.login,
      );
      if (result.ok && result.applied > 0) {
        // Branch was deleted; clear local cache + soft-refresh in case
        // another user has new drafts staged.
        setDraftsByCap(new Map());
        setTimeout(() => { refresh(); }, 1500);
      }
      return result;
    }
    const result = await api.publish();
    if (result.ok) {
      setDraftsByCap(new Map());
      setTimeout(() => { refresh(); }, 1500);
    }
    return result;
  }, [refresh, ghAuth, ghUser]);

  const value = useMemo<DraftsContextValue>(() => ({
    draftsByCap,
    moduleStatePendingCount,
    loading,
    error,
    refresh,
    getDraft,
    getDraftFields,
    saveDraft,
    clearDraft,
    publish,
  }), [draftsByCap, moduleStatePendingCount, loading, error, refresh, getDraft, getDraftFields, saveDraft, clearDraft, publish]);

  return <DraftsContext.Provider value={value}>{children}</DraftsContext.Provider>;
}

export function useDrafts() {
  const ctx = useContext(DraftsContext);
  if (!ctx) throw new Error("useDrafts must be inside DraftsProvider");
  return ctx;
}
