import { useAuth } from "../contexts/AuthContext";
import { useIsInPreview } from "../lib/useEffectiveRole";
import "./PreviewBanner.css";

/**
 * Yellow strip across the top of the SPA when the signed-in user is
 * previewing as a lower-permission role (e.g. an admin previewing as a
 * viewer to check what colleagues will see).
 *
 * Renders nothing in normal (non-preview) state.
 */
export function PreviewBanner() {
  const { previewRole, setPreviewRole, user } = useAuth();
  const inPreview = useIsInPreview();
  if (!inPreview || !previewRole) return null;
  const actualLabel = user?.app_role
    ? user.app_role.charAt(0).toUpperCase() + user.app_role.slice(1)
    : "your account";
  return (
    <div className="preview-banner" role="status">
      <span className="preview-banner-icon" aria-hidden="true">👁</span>
      <span className="preview-banner-text">
        Previewing as <strong>{previewRole}</strong> · your real role is <strong>{actualLabel}</strong>
      </span>
      <button
        type="button"
        className="preview-banner-exit"
        onClick={() => setPreviewRole(null)}
      >
        Exit preview
      </button>
    </div>
  );
}
