import "./ComplianceBaselineSection.css";
import type { ComplianceBaselinePayload } from "../lib/stakeholdersData";

/**
 * Cross-module regulatory + cybersecurity baseline. PSG pre-approval
 * mandates CEM + PDPA + VA/PT regardless of which ERP module the vendor
 * ships — surfaces on every module's canonical checklist so reviewers
 * don't miss the floor.
 *
 * Data source: output/compliance_baseline.json (built by the pipeline
 * from PSG sol-cat scrapes — questions that appear in ≥50% of sol cats
 * get promoted to the baseline rather than module-specific caps).
 */
export function ComplianceBaselineSection({
  data,
}: {
  data: ComplianceBaselinePayload | null | undefined;
}) {
  if (!data || !Array.isArray(data.groups) || data.groups.length === 0) return null;
  return (
    <section className="cbs-section">
      <h2 className="section-heading">Baseline compliance</h2>
      <p className="muted small">
        {data.description ||
          "Cross-module regulatory + cybersecurity floor PSG pre-approval mandates for every vendor — independent of module scope."}
      </p>
      {data.groups.map(g => (
        <div key={g.id} className={`cbs-group cbs-group-${g.id}`}>
          <header className="cbs-group-head">
            <h3 className="cbs-group-name">{g.name}</h3>
            {typeof g.total_sol_cat_occurrences === "number" && (
              <span className="cbs-group-meta">
                {g.total_sol_cat_occurrences} sol-cat occurrence{g.total_sol_cat_occurrences === 1 ? "" : "s"}
              </span>
            )}
          </header>
          {g.description && <p className="cbs-group-desc">{g.description}</p>}
          <ol className="cbs-checklist">
            {g.checklist.map((item, i) => (
              <li key={i} className="cbs-item">
                <div className="cbs-item-text">{item.text}</div>
                {item.rationale && (
                  <div className="cbs-item-rationale muted small">{item.rationale}</div>
                )}
              </li>
            ))}
          </ol>
        </div>
      ))}
    </section>
  );
}
