import { useEffect, useMemo, useState } from "react";
import {
  loadPricingCoverage,
  filterPricingRows,
  type PricingCoveragePayload,
  type PricingFilter,
} from "../lib/pricingCoverage";
import { TabHelp } from "./TabHelp";
import "./MissingPricingPanel.css";

/**
 * "Missing Pricing" panel — surfaces vendors with feature evidence but
 * no pricing entries in data/vendor_pricing/manual_pricing_overrides.yaml.
 *
 * Read-only B1 build. Per-row inline paste-form (B2) lands in a
 * follow-up commit. For now: filter + search + display, with an
 * explicit "enter pricing via Claude Code chat" hint until B2 ships.
 */
export function MissingPricingPanel() {
  const [data, setData] = useState<PricingCoveragePayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [filter, setFilter] = useState<PricingFilter>("missing");
  const [query, setQuery] = useState("");

  useEffect(() => {
    loadPricingCoverage()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  const visible = useMemo(() => {
    if (!data) return [];
    return filterPricingRows(data.vendors, filter, query);
  }, [data, filter, query]);

  if (error) {
    return (
      <div className="mp-msg error">
        Failed to load pricing coverage: {error}
        <p className="mp-hint">
          Did you run <code>python3 scripts/build_pricing_coverage_snapshot.py</code> recently?
        </p>
      </div>
    );
  }
  if (!data) return <div className="mp-msg muted">Loading pricing coverage…</div>;

  const m = data._meta;
  return (
    <div className="mp-panel">
      <TabHelp hint="Vendors with feature evidence (we know what they do) but no pricing entry in manual_pricing_overrides.yaml. Filter to find the gap, click a vendor to see its source. B1 is read-only — entry happens via Claude Code chat for now ('add pricing for X — quote text: ...'); B2 will add an inline paste form here.">
        <strong>{m.missing}</strong> of <strong>{m.with_evidence}</strong> evidenced vendors are
        missing pricing entries. <strong>{m.quote_only}</strong> are flagged quote-on-request
        (manual entry is the only path). <strong>{m.with_pricing}</strong> have pricing in.
      </TabHelp>

      <div className="mp-filters">
        <label className="mp-filter">
          <span>Show:</span>
          <select value={filter} onChange={e => setFilter(e.target.value as PricingFilter)}>
            <option value="missing">Missing pricing ({m.missing})</option>
            <option value="quote_only">Quote-only + missing ({m.quote_only})</option>
            <option value="covered">Has pricing ({m.with_pricing})</option>
            <option value="all">All vendors ({m.vendor_count})</option>
          </select>
        </label>
        <label className="mp-filter mp-filter-wide">
          <span>Search:</span>
          <input
            type="search"
            value={query}
            onChange={e => setQuery(e.target.value)}
            placeholder="vendor id, name, tier, type, module…"
          />
        </label>
        <span className="mp-count">{visible.length} shown</span>
      </div>

      {visible.length === 0 ? (
        <div className="mp-msg muted">No vendors match the active filter.</div>
      ) : (
        <table className="mp-table">
          <thead>
            <tr>
              <th>Vendor</th>
              <th>Tier</th>
              <th>Type</th>
              <th>Modules</th>
              <th>Status</th>
              <th>Pricing source</th>
            </tr>
          </thead>
          <tbody>
            {visible.map(r => {
              const status = r.is_missing
                ? (r.is_quote_only ? "quote-only · MISSING" : "MISSING")
                : (r.n_pricings > 0 ? `${r.n_pricings} plan${r.n_pricings > 1 ? "s" : ""}` : r.has_evidence ? "—" : "no-evidence");
              const statusCls = r.is_missing ? "mp-status mp-status-missing"
                : r.n_pricings > 0 ? "mp-status mp-status-ok"
                : "mp-status mp-status-other";
              return (
                <tr key={r.vendor_id} className={r.is_missing ? "mp-row-missing" : ""}>
                  <td className="mp-vendor">
                    <div className="mp-vendor-name">{r.name}</div>
                    <code className="mp-vendor-id">{r.vendor_id}</code>
                  </td>
                  <td>{r.tier}</td>
                  <td>{r.type}</td>
                  <td className="mp-modules">
                    {r.modules.length === 0 ? <span className="muted">—</span> : r.modules.join(", ")}
                  </td>
                  <td><span className={statusCls}>{status}</span></td>
                  <td className="mp-source">
                    {r.pricing_url ? (
                      <a href={r.pricing_url} target="_blank" rel="noopener noreferrer">
                        public page
                      </a>
                    ) : r.pricing_status === "quote_on_request" ? (
                      <span className="muted">quote-on-request</span>
                    ) : (
                      <span className="muted">—</span>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      )}

      <div className="mp-footnote">
        <strong>To add pricing for a missing vendor</strong>: in Claude Code chat, say
        <code>add pricing for &lt;vendor_id&gt; — quote text: ...</code> and Claude will
        write the YAML. B2 will replace this with an inline paste form here.
      </div>
    </div>
  );
}
