import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { api } from "../lib/api";
import { GITHUB_NATIVE } from "../contexts/AuthContext";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type AuditSummary,
} from "../lib/stakeholdersData";
import { useEffectiveRole } from "../lib/useEffectiveRole";
import { TabHelp } from "../components/TabHelp";
import "./AdminHealthPage.css";

interface D1Health {
  ok: boolean;
  tables: Record<string, { table: string; count: number | null; ok: boolean; error?: string }>;
  latest: { draft_updated_at: string | null; audit_log_created_at: string | null };
  checked_at: string;
}

/**
 * Dev-side health dashboard at /admin/health. Admin-only — shows pipeline
 * audit counts (P0 / P1), last-pipeline-run timestamp, and live D1 row
 * counts so we can spot drift between what's deployed and what's authored.
 *
 * Off the public Methodology page on purpose — audit counts on a
 * stakeholder-facing surface generate worry, not trust.
 */
export function AdminHealthPage() {
  // useEffectiveRole resolves the real role across v1 (CF Worker /api/me)
  // and v2 (GitHub OAuth users.json) — important because v2 builds stub
  // out api.me() to a viewer-default, which would falsely block actual
  // admins signed in via GitHub.
  const role = useEffectiveRole();
  const [summary, setSummary] = useState<StakeholdersSummary | null>(null);
  const [d1, setD1] = useState<D1Health | null>(null);
  const [d1Error, setD1Error] = useState<string | null>(null);
  const [d1Loading, setD1Loading] = useState(false);

  useEffect(() => {
    loadStakeholdersSummary().then(setSummary).catch(() => setSummary(null));
    // D1 backend was retired in the 2026-05-13 overnight session (CF
    // Worker + D1 unhosted; revivable via `wrangler deploy` from
    // workers/cap-edit-api/). In v2 (GITHUB_NATIVE) the row-count
    // probe would 404 against the now-unbound URL, so skip the call.
    if (!GITHUB_NATIVE) refreshD1();
  }, []);

  const refreshD1 = async () => {
    setD1Loading(true);
    setD1Error(null);
    try {
      const r = await api.d1Health();
      setD1(r);
    } catch (e) {
      setD1Error(e instanceof Error ? e.message : String(e));
    } finally {
      setD1Loading(false);
    }
  };

  // Soft gate — server enforces too. While role is undefined (loading)
  // render nothing rather than flashing the deny screen.
  if (role === undefined) return null;
  if (role !== "admin") {
    return (
      <section className="health-page">
        <header className="health-header">
          <h1>Admin · Health</h1>
        </header>
        <div className="health-deny">
          <h2>You're signed in as <code>{role}</code></h2>
          <p>Only admins can view the health dashboard.</p>
          <Link to="/" className="health-back">← back to Home</Link>
        </div>
      </section>
    );
  }

  return (
    <section className="health-page">
      <header className="health-header">
        <span className="health-eyebrow">Admin</span>
        <h1>Health</h1>
      </header>
      <TabHelp hint="P0 = blocks-publish failures; P1 = warnings worth review. Numbers come from output/*audit*.json — refreshed by the pipeline + Publish flow.">
        Operational dashboard — pipeline audits, last pipeline run, and D1
        row counts. Use this to spot drift between authored data and what's
        deployed; surface here is intentionally off the public Methodology
        page so audit numbers don't generate stakeholder worry.
      </TabHelp>

      {/* Pipeline section */}
      <h2 className="health-section-h">Pipeline</h2>
      <div className="health-grid">
        <div className="health-tile">
          <div className="health-tile-label">Last pipeline run</div>
          <div className="health-tile-value">
            {summary?.last_pipeline_run
              ? formatTimestamp(summary.last_pipeline_run)
              : <span className="muted">—</span>}
          </div>
          <div className="health-tile-foot">latest <code>step16_applied_at</code> across all canonicals</div>
        </div>
        <div className="health-tile">
          <div className="health-tile-label">Stakeholders summary</div>
          <div className="health-tile-value">
            {summary?.generated_at
              ? formatTimestamp(summary.generated_at)
              : <span className="muted">—</span>}
          </div>
          <div className="health-tile-foot">SPA payload regenerated by build_stakeholders_summary.py</div>
        </div>
      </div>

      {/* Audits section */}
      <h2 className="health-section-h">Audits</h2>
      {summary?.audit_summary
        ? <AuditTable audit={summary.audit_summary} />
        : <p className="muted">Loading audit summary…</p>}

      {/* D1 section — only meaningful in v1 (CF Worker still bound).
          In v2 (GITHUB_NATIVE) the D1 backend was retired, so render a
          single-line stub explaining the state instead of probing a
          dead endpoint and surfacing a noisy 404. Revivable: `cd
          workers/cap-edit-api && npx wrangler deploy`. */}
      <h2 className="health-section-h">
        D1 backend
        {!GITHUB_NATIVE && (
          <button
            type="button"
            className="health-refresh"
            onClick={refreshD1}
            disabled={d1Loading}
            title="Re-query the worker for live row counts"
          >
            {d1Loading ? "refreshing…" : "↻ refresh"}
          </button>
        )}
      </h2>
      {GITHUB_NATIVE ? (
        <p className="muted small">
          Retired in v2 — drafts + audit log now live on GitHub branches
          (<code>drafts/&lt;user&gt;</code>) instead of D1. Revive with
          {" "}<code>cd workers/cap-edit-api &amp;&amp; npx wrangler deploy</code>
          {" "}if the Worker is needed again.
        </p>
      ) : (
        <>
          {d1Error && <div className="health-error">D1 query failed: {d1Error}</div>}
          {!d1 && !d1Error && <p className="muted">Loading…</p>}
          {d1 && <D1Section d1={d1} />}
        </>
      )}
    </section>
  );
}

function AuditTable({ audit }: { audit: AuditSummary }) {
  const rows: Array<{ label: string; p0: number | null | undefined; p1?: number | null; note?: string }> = [
    {
      label: "Sol-cat join",
      p0: audit.solcat_p0,
      p1: audit.solcat_p1,
      note: "Coverage of PSG sol cats across modules + sub-modules.",
    },
    {
      label: "Checklist format (Type 1)",
      p0: audit.checklist_p0,
      p1: audit.checklist_p1,
      note: `${audit.checklist_modules_audited ?? "?"} modules audited against docs/imda_checklist_formats.md`,
    },
    {
      label: "Use cases",
      p0: audit.uc_p0,
      p1: undefined,
      note: `${audit.uc_total?.toLocaleString() ?? "?"} UCs scanned`,
    },
    {
      label: "Flow atoms",
      p0: audit.flow_p0_any ? 1 : 0,
      p1: audit.flow_total_violations,
      note: "Workflows + proposed flows against docs/solcat_writing_guide.md",
    },
  ];

  return (
    <table className="health-audit-table">
      <thead>
        <tr><th>Audit</th><th className="num">P0</th><th className="num">P1</th><th>Notes</th></tr>
      </thead>
      <tbody>
        {rows.map(r => (
          <tr key={r.label}>
            <td>{r.label}</td>
            <td className={`num ${countClass(r.p0)}`}>{formatCount(r.p0)}</td>
            <td className={`num ${countClass(r.p1, true)}`}>{formatCount(r.p1)}</td>
            <td className="muted small">{r.note}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

function D1Section({ d1 }: { d1: D1Health }) {
  return (
    <>
      <table className="health-d1-table">
        <thead>
          <tr><th>Table</th><th className="num">Rows</th><th>Status</th></tr>
        </thead>
        <tbody>
          {Object.values(d1.tables).map(t => (
            <tr key={t.table}>
              <td><code>{t.table}</code></td>
              <td className="num">{t.count?.toLocaleString() ?? "—"}</td>
              <td>
                {t.ok ? (
                  <span className="health-pill ok">OK</span>
                ) : (
                  <span className="health-pill fail" title={t.error}>FAIL</span>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <div className="health-grid">
        <div className="health-tile">
          <div className="health-tile-label">Latest draft saved</div>
          <div className="health-tile-value">
            {d1.latest.draft_updated_at
              ? formatTimestamp(d1.latest.draft_updated_at)
              : <span className="muted">no drafts</span>}
          </div>
        </div>
        <div className="health-tile">
          <div className="health-tile-label">Latest audit-log entry</div>
          <div className="health-tile-value">
            {d1.latest.audit_log_created_at
              ? formatTimestamp(d1.latest.audit_log_created_at)
              : <span className="muted">no entries</span>}
          </div>
        </div>
      </div>
      <p className="muted small">Checked {formatTimestamp(d1.checked_at)}</p>
    </>
  );
}

function countClass(n: number | null | undefined, p1 = false): string {
  if (n === null || n === undefined) return "muted";
  if (n === 0) return "ok";
  return p1 ? "warn" : "fail";
}

function formatCount(n: number | null | undefined): string {
  if (n === null || n === undefined) return "—";
  return n.toLocaleString();
}

function formatTimestamp(iso: string): string {
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    return new Intl.DateTimeFormat("en-SG", {
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      timeZone: "Asia/Singapore",
      timeZoneName: "short",
    }).format(d);
  } catch {
    return iso;
  }
}
