/** Loader + types for the multi-core validation matrix.
 *
 * Reads three derived files into a single browser-friendly payload:
 *   - psg_core_classification.json   — per-PSG-sol verdict per core
 *   - known_erp_core_packaging.json  — how reference ERPs package each core
 *   - core_split_proposals.json      — Haiku-proposed revisions on boundary mismatch
 *
 * Each file is YAML on disk for human-editability; the deploy workflow
 * (or a tiny build step) converts them to JSON colocated with the SPA
 * bundle. Until that step lands, the SPA fetches the YAML files via
 * the same BASE_URL prefix and parses client-side.
 */

const BASE_URL = (import.meta.env.BASE_URL || "/").replace(/\/+$/, "/");

export type SolutionVerdict =
  | "single_core_full"
  | "multi_core_full"
  | "partial_only"
  | "unclassified";

export type ModuleVerdict =
  | "validated_specialty"
  | "theoretical_only"
  | "boundary_mismatch"
  | "data_thin"
  | "mixed"
  | "no_data";

export interface CoreDef {
  id: string;
  name: string;
  cap_count?: number;
  /** List of canonical cap IDs in this core. Populated by
   *  scripts/classify_psg_solutions_per_core.py from
   *  config/preferred_clusters.yaml. Used by the panel to expand
   *  a solution row into per-cap coverage heatmap. */
  caps?: string[];
}

export interface SolutionClassification {
  vendor_name: string | null;
  solution_name: string | null;
  category: string | null;
  classified_at?: string;
  by_core?: Record<string, {
    covered_caps?: string[];
    partial_caps?: string[];
    verdict?: "full" | "partial" | "none";
    reason?: string;
  }>;
  verdict: SolutionVerdict;
  summary_reason?: string;
  error?: string;
}

export interface ModuleClassification {
  cores: CoreDef[];
  classifications: Record<string, SolutionClassification>;
  /** Human-authored explanation of why this module is split into these
   *  specific cores. Lifted from config/preferred_clusters.yaml's
   *  `modules.<slug>.required.rationale` field. The SPA renders this
   *  above the matrix so the WHY of the split is obvious.
   *
   *  Plain text (newlines preserved as paragraph breaks). May be missing
   *  on modules where the YAML doesn't include rationale yet. */
  rationale?: string;
}

export interface ErpPackagingForModule {
  name: string;
  tier: string;
  packaging_per_core?: Record<string, {
    model?: "separate" | "bundled" | "partial" | "absent" | "unknown";
    sku_name?: string;
    pricing_unit?: string;
    sources?: string[];
    notes?: string;
  }>;
  overall_summary?: string;
  error?: string;
  researched_at?: string;
}

export interface ModuleErpOverlay {
  cores: CoreDef[];
  erps: Record<string, ErpPackagingForModule>;
}

export interface SplitProposal {
  cores: { id: string; name: string; caps: string[] }[];
  rationale: string;
  backing_evidence: { psg_id: string; reason: string }[];
}

export interface ModuleProposal {
  current_split: CoreDef[];
  stats: {
    total_classified: number;
    counts: Record<string, number>;
    pct: Record<string, number>;
  };
  verdict: ModuleVerdict;
  proposed_revisions?: SplitProposal[];
}

export interface MultiCorePayload {
  classification: Record<string, ModuleClassification>;
  erp_overlay: Record<string, ModuleErpOverlay>;
  proposals: Record<string, ModuleProposal>;
}

async function fetchJson<T>(filename: string): Promise<T | null> {
  const url = `${BASE_URL}${filename}`;
  try {
    const r = await fetch(url, { cache: "no-store" });
    if (!r.ok) return null;
    return (await r.json()) as T;
  } catch {
    return null;
  }
}

interface RawClassificationDoc {
  modules?: Record<string, ModuleClassification>;
}
interface RawErpDoc {
  modules?: Record<string, ModuleErpOverlay>;
}
interface RawProposalsDoc {
  modules?: Record<string, ModuleProposal>;
}

let cache: MultiCorePayload | null = null;
let inflight: Promise<MultiCorePayload> | null = null;

export async function loadMultiCorePayload(): Promise<MultiCorePayload> {
  if (cache) return cache;
  if (inflight) return inflight;
  inflight = (async () => {
    const [cls, erp, prop] = await Promise.all([
      fetchJson<RawClassificationDoc>("psg_core_classification.json"),
      fetchJson<RawErpDoc>("known_erp_core_packaging.json"),
      fetchJson<RawProposalsDoc>("core_split_proposals.json"),
    ]);
    const out: MultiCorePayload = {
      classification: cls?.modules || {},
      erp_overlay: erp?.modules || {},
      proposals: prop?.modules || {},
    };
    cache = out;
    inflight = null;
    return out;
  })();
  return inflight;
}

export function moduleVerdictBadge(v: ModuleVerdict): { label: string; tone: string } {
  switch (v) {
    case "validated_specialty": return { label: "Split validated", tone: "good" };
    case "theoretical_only":    return { label: "Theoretical only", tone: "neutral" };
    case "boundary_mismatch":   return { label: "Boundary mismatch", tone: "warn" };
    case "data_thin":           return { label: "Data thin", tone: "muted" };
    case "mixed":               return { label: "Mixed signal", tone: "neutral" };
    default:                    return { label: "No data", tone: "muted" };
  }
}

export function solutionVerdictBadge(v: SolutionVerdict): { label: string; tone: string } {
  switch (v) {
    case "single_core_full":  return { label: "Single core", tone: "good" };
    case "multi_core_full":   return { label: "Full suite", tone: "neutral" };
    case "partial_only":      return { label: "Partial", tone: "warn" };
    default:                  return { label: "Out of scope", tone: "muted" };
  }
}
