import { useMemo, useState } from "react";
import type {
  CapEvidence,
  CoverageMatrixCap,
  CoverageMatrixCellGlyph,
  CoverageMatrixVendor,
  StakeholdersSummary,
} from "../lib/stakeholdersData";
import { tierLabel, tierClass } from "../lib/tier";
import "./CapSolutionsCoverageTable.css";

/**
 * Cap Library → Solutions Coverage sub-tab.
 *
 * Per-cap layout:
 *   [cap name + family + tier badge]   [Updated: 2026-05-15 (hover for sources)]
 *   [In-base (N)]  [Add-on (N)]  [FP-only (N)]  [Not covered (N)]  (last collapsed)
 *
 * Source: coverage_matrix.modules[cap.module].vendors[].cells[cap.id].glyph.
 * Caps without a coverage_matrix entry (advanced tier, in_checklist=false,
 * etc.) render with "—" in every group and no timestamp.
 *
 * Filters are inherited from the parent CapLibraryPage — this component
 * just renders the already-filtered list of caps.
 */

interface Props {
  caps: CapEvidence[];
  summary: StakeholdersSummary;
}

interface VendorGroup {
  label: string;
  className: string;
  glyphs: CoverageMatrixCellGlyph[];
  vendors: { vendor_id: string; vendor_name: string }[];
}

function buildGroups(matrixCap: CoverageMatrixCap | undefined, vendors: CoverageMatrixVendor[] | undefined): VendorGroup[] {
  // Order: In-base (the strongest signal) → Add-on → FP-only → Not covered.
  const groups: VendorGroup[] = [
    { label: "In-base coverage", className: "in_base", glyphs: ["in_base", "in_base_pro", "in_base_top"], vendors: [] },
    { label: "Paid add-on", className: "add_on", glyphs: ["add_on"], vendors: [] },
    { label: "Feature-page only", className: "evidenced", glyphs: ["evidenced"], vendors: [] },
    { label: "Not covered", className: "not_covered", glyphs: ["not_covered"], vendors: [] },
  ];
  if (!matrixCap || !vendors) return groups;
  for (const v of vendors) {
    const cell = v.cells[matrixCap.cap_id];
    if (!cell || cell.glyph === "no_data") continue;
    const g = cell.glyph;
    const target = groups.find(grp => grp.glyphs.includes(g));
    if (target) target.vendors.push({ vendor_id: v.vendor_id, vendor_name: v.vendor_name });
  }
  return groups;
}

function formatDate(iso: string | undefined): string {
  if (!iso) return "—";
  // ISO-8601 → YYYY-MM-DD (drop the time + timezone for compactness)
  return iso.slice(0, 10);
}

function formatSourcesTooltip(matrixCap: CoverageMatrixCap | undefined): string {
  const src = matrixCap?.last_updated_sources;
  if (!src) return "";
  const parts: string[] = [];
  if (src.pipeline_at) parts.push(`Canonical pipeline: ${src.pipeline_at.slice(0, 10)}`);
  if (src.feature_evidence_at) parts.push(`Feature-page refresh: ${src.feature_evidence_at.slice(0, 10)}`);
  return parts.join("\n") || "(no source timestamps available)";
}

function CapSolutionsRow({
  cap,
  matrixCap,
  matrixVendors,
  collapsedNotCovered,
  onToggleNotCovered,
}: {
  cap: CapEvidence;
  matrixCap: CoverageMatrixCap | undefined;
  matrixVendors: CoverageMatrixVendor[] | undefined;
  collapsedNotCovered: boolean;
  onToggleNotCovered: () => void;
}) {
  const groups = useMemo(
    () => buildGroups(matrixCap, matrixVendors),
    [matrixCap, matrixVendors],
  );
  const inMatrix = matrixCap !== undefined;
  return (
    <article className="csc-row">
      <header className="csc-row-head">
        <div className="csc-cap">
          <div className="csc-cap-name">{cap.name}</div>
          <code className="csc-cap-id">{cap.id}</code>
          {cap.family && <span className="csc-family">{cap.family}</span>}
        </div>
        <div className="csc-meta">
          <span className={`csc-tier tier-${tierClass(cap.sme_tier)}`}>{tierLabel(cap.sme_tier)}</span>
          <span
            className="csc-updated"
            title={formatSourcesTooltip(matrixCap)}
          >
            Updated: {formatDate(matrixCap?.last_updated)}
          </span>
        </div>
      </header>
      <div className="csc-groups">
        {groups.map(grp => {
          const isNotCov = grp.className === "not_covered";
          const collapsed = isNotCov && collapsedNotCovered;
          const empty = grp.vendors.length === 0;
          return (
            <div key={grp.className} className={`csc-group csc-group-${grp.className}${empty ? " csc-group-empty" : ""}`}>
              <div className="csc-group-head">
                {isNotCov ? (
                  <button
                    type="button"
                    className="csc-group-toggle"
                    onClick={onToggleNotCovered}
                    disabled={empty}
                  >
                    <span className="csc-group-label">{grp.label}</span>
                    <span className="csc-group-count">{grp.vendors.length}</span>
                    {!empty && <span className="csc-group-caret">{collapsed ? "▸" : "▾"}</span>}
                  </button>
                ) : (
                  <>
                    <span className="csc-group-label">{grp.label}</span>
                    <span className="csc-group-count">{grp.vendors.length}</span>
                  </>
                )}
              </div>
              {!collapsed && !empty && (
                <ul className="csc-vendor-list">
                  {grp.vendors.map(v => (
                    <li key={v.vendor_id} className="csc-vendor-pill">{v.vendor_name}</li>
                  ))}
                </ul>
              )}
            </div>
          );
        })}
      </div>
      {!inMatrix && (
        <div className="csc-note">
          No vendor coverage data — this cap is outside the Coverage Matrix's
          scope (e.g. advanced tier or excluded from the checklist).
        </div>
      )}
    </article>
  );
}

export function CapSolutionsCoverageTable({ caps, summary }: Props) {
  // One toggle state for "Not covered" per cap (default collapsed). Stored
  // as a Set of cap_ids whose Not-Covered section is EXPANDED (inverted
  // default keeps the most common state cheap — empty set means all
  // collapsed).
  const [expandedNotCov, setExpandedNotCov] = useState<Set<string>>(new Set());
  const toggle = (cap_id: string) => {
    setExpandedNotCov(prev => {
      const next = new Set(prev);
      if (next.has(cap_id)) next.delete(cap_id);
      else next.add(cap_id);
      return next;
    });
  };

  // coverage_matrix is keyed by canonical module slug. Lookup index for fast
  // per-cap retrieval: { cap_id → {matrixCap, vendors} }.
  const capLookup = useMemo(() => {
    const map = new Map<string, { matrixCap: CoverageMatrixCap; vendors: CoverageMatrixVendor[] }>();
    const matrixModules = summary.coverage_matrix?.modules || {};
    for (const mod of Object.values(matrixModules)) {
      for (const c of mod.caps) {
        map.set(c.cap_id, { matrixCap: c, vendors: mod.vendors });
      }
    }
    return map;
  }, [summary]);

  if (caps.length === 0) {
    return (
      <div className="csc-empty">
        No caps match the current filters.
      </div>
    );
  }

  return (
    <div className="csc-wrap">
      <p className="csc-intro muted">
        Per-cap vendor coverage. <strong>In-base</strong> = vendor delivers the
        cap on a pricing-resolved plan (any tier). <strong>Add-on</strong> =
        available but separately priced. <strong>Feature-page only</strong> =
        marketed on the product page, no pricing tier known yet.
        <strong> Not covered</strong> = vendor lists pricing but the cap is
        absent. Hover the <em>Updated</em> pill for source-by-source timestamps.
      </p>
      {caps.map(cap => {
        const entry = capLookup.get(cap.id);
        return (
          <CapSolutionsRow
            key={cap.id}
            cap={cap}
            matrixCap={entry?.matrixCap}
            matrixVendors={entry?.vendors}
            collapsedNotCovered={!expandedNotCov.has(cap.id)}
            onToggleNotCovered={() => toggle(cap.id)}
          />
        );
      })}
    </div>
  );
}
