/**
 * User-added cap requirements (v2).
 *
 * Stored on each user's draft branch at:
 *   drafts/<github-username>/_additions/<module>/<cap_id>.yaml
 *
 * The cap_id is auto-generated: `<modulePrefix>.user_<slug>_<short>` where
 * <modulePrefix> matches the existing per-module prefix in canonical
 * (fin / hr / sales / sc / mfg / asset / fsm / fleet / proj / other) and
 * <short> is a 4-char random suffix to avoid collisions.
 *
 * Published into `data/manual_cap_additions.yaml`; a pipeline step
 * (step18_apply_cap_additions) merges them into canonical at canonicalise
 * time.
 *
 * Note the parallel-but-distinct schema from cap-field DRAFTS: a cap
 * draft modifies an EXISTING cap; an ADDITION creates a NEW cap. Different
 * file paths so the two paths don't interfere.
 */
import {
  ensureBranch,
  getFileWithSha,
  putFile,
  type GitHubAuth,
} from "./githubClient";

const DRAFT_BRANCH_PREFIX = "drafts/";

export const MODULE_TO_PREFIX: Record<string, string> = {
  financial_management: "fin",
  human_resources_management: "hr",
  sales_and_crm: "sales",
  supply_chain_and_inventory: "sc",
  manufacturing_management: "mfg",
  asset_management: "asset",
  field_service_management: "fsm",
  fleet_management: "fleet",
  project_management: "proj",
  others: "other",
};

export type AppTier = "required" | "preferred" | "advanced";

export interface AdditionFields {
  name: string;
  description?: string;
  sme_tier: AppTier;
  sub_module_id?: string;
  /** Umbrella (cluster) assignment for Mandatory tier on multi-core modules.
   *  Optional — only set when the user picks one in the modal. Mandatory tier
   *  on multi-core modules (mfg / asset / sc / hr) shows the picker; all other
   *  combinations leave this null. When set, step18 (cap additions) writes
   *  the cap, then step19 (cluster overrides) routes it into the chosen
   *  umbrella via data/manual_cluster_assignments.yaml. */
  cluster_id?: string;
  /** Required (verbose). */
  vendor_question: string;
  /** Optional terse single-line. */
  vendor_question_terse?: string;
  /** Optional Type 2 single-bullet rewording. */
  vendor_question_t2?: string;
  /** Free text — IMDA Q ref (e.g., "Q5, Q12"). Pipeline picks this up
   *  for traceability metadata. */
  imda_q_ref?: string;
  /** Free text — related existing cap ids, comma-separated. */
  source_cap_mapping?: string;
  /** Free text — reason / context for adding this cap. */
  note?: string;
}

export interface AdditionRecord {
  module: string;
  cap_id: string;
  fields: AdditionFields;
  author_email: string;
  author_username: string;
  updated_at: string;
  /** Blob SHA on the draft branch (set after save / on read). */
  sha?: string;
}

function draftBranch(username: string): string {
  return `${DRAFT_BRANCH_PREFIX}${username}`;
}

function additionPath(username: string, module: string, capId: string): string {
  return `drafts/${username}/_additions/${module}/${capId}.yaml`;
}

/** Slugify a free-text name to a cap-id-safe suffix. */
export function slugifyForCapId(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 40) || "new";
}

/** Generate a unique cap_id for a new addition. Format:
 *  <prefix>.user_<slug>_<rand> — always contains `user_` so the pipeline
 *  + viewer can identify user-added caps and badge them. */
export function generateCapId(module: string, name: string): string {
  const prefix = MODULE_TO_PREFIX[module] || module.split("_")[0];
  const slug = slugifyForCapId(name);
  // 4-char random suffix — short, readable, low collision risk for a
  // single user's additions over time.
  const rand = Math.floor(Math.random() * 0x10000).toString(16).padStart(4, "0");
  return `${prefix}.user_${slug}_${rand}`;
}

function yamlScalar(v: string): string {
  if (v.includes("\n")) {
    const indented = v.split("\n").map(line => `  ${line}`).join("\n");
    return `|\n${indented}`;
  }
  return `'${v.replace(/'/g, "''")}'`;
}

function emitYaml(rec: AdditionRecord): string {
  const f = rec.fields;
  const lines: string[] = [
    `# Addition — new cap requested by user, will be injected into canonical on next pipeline run.`,
    `cap_id: ${yamlScalar(rec.cap_id)}`,
    `module: ${yamlScalar(rec.module)}`,
    `name: ${yamlScalar(f.name)}`,
    `sme_tier: ${f.sme_tier}`,
  ];
  if (f.description) lines.push(`description: ${yamlScalar(f.description)}`);
  if (f.sub_module_id) lines.push(`sub_module_id: ${yamlScalar(f.sub_module_id)}`);
  if (f.cluster_id) lines.push(`cluster_id: ${yamlScalar(f.cluster_id)}`);
  if (f.vendor_question) lines.push(`vendor_question: ${yamlScalar(f.vendor_question)}`);
  if (f.vendor_question_terse) lines.push(`vendor_question_terse: ${yamlScalar(f.vendor_question_terse)}`);
  if (f.vendor_question_t2) lines.push(`vendor_question_t2: ${yamlScalar(f.vendor_question_t2)}`);
  if (f.imda_q_ref) lines.push(`imda_q_ref: ${yamlScalar(f.imda_q_ref)}`);
  if (f.source_cap_mapping) lines.push(`source_cap_mapping: ${yamlScalar(f.source_cap_mapping)}`);
  if (f.note) lines.push(`note: ${yamlScalar(f.note)}`);
  lines.push(`author: ${rec.author_email}`);
  lines.push(`author_username: ${rec.author_username}`);
  lines.push(`edited_at: ${yamlScalar(rec.updated_at)}`);
  return lines.join("\n") + "\n";
}

function parseYaml(text: string): Record<string, string> {
  const out: Record<string, string> = {};
  const lines = text.split("\n");
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    if (line.startsWith("#") || line.trim() === "") { i++; continue; }
    const m = line.match(/^([a-z_]+):\s*(.*)$/);
    if (!m) { i++; continue; }
    const [, key, rest] = m;
    if (rest === "|") {
      const acc: string[] = [];
      i++;
      while (i < lines.length && /^\s{2,}/.test(lines[i])) {
        acc.push(lines[i].replace(/^\s{2}/, ""));
        i++;
      }
      out[key] = acc.join("\n");
      continue;
    }
    if (rest.startsWith("'") && rest.endsWith("'")) {
      out[key] = rest.slice(1, -1).replace(/''/g, "'");
    } else {
      out[key] = rest;
    }
    i++;
  }
  return out;
}

function recordFromYaml(text: string): AdditionRecord | null {
  const p = parseYaml(text);
  if (!p.cap_id || !p.module || !p.name || !p.sme_tier) return null;
  const tier = p.sme_tier as AppTier;
  if (tier !== "required" && tier !== "preferred" && tier !== "advanced") return null;
  return {
    module: p.module,
    cap_id: p.cap_id,
    fields: {
      name: p.name,
      description: p.description,
      sme_tier: tier,
      sub_module_id: p.sub_module_id,
      cluster_id: p.cluster_id,
      vendor_question: p.vendor_question ?? "",
      vendor_question_terse: p.vendor_question_terse,
      vendor_question_t2: p.vendor_question_t2,
      imda_q_ref: p.imda_q_ref,
      source_cap_mapping: p.source_cap_mapping,
      note: p.note,
    },
    author_email: p.author ?? "",
    author_username: p.author_username ?? "",
    updated_at: p.edited_at ?? "",
  };
}

export async function ensureUserDraftBranch(
  auth: GitHubAuth,
  username: string,
): Promise<void> {
  await ensureBranch(auth, draftBranch(username), "main");
}

/** Save a new addition (or update an existing one if cap_id collides). */
export async function saveAddition(
  auth: GitHubAuth,
  username: string,
  authorEmail: string,
  module: string,
  fields: AdditionFields,
  /** Pass to overwrite a specific existing addition; else a new cap_id is generated. */
  capIdOverride?: string,
): Promise<AdditionRecord> {
  await ensureUserDraftBranch(auth, username);
  const branch = draftBranch(username);
  const capId = capIdOverride || generateCapId(module, fields.name);
  const path = additionPath(username, module, capId);
  const existing = await getFileWithSha(auth, path, branch);
  const updated_at = new Date().toISOString();
  const rec: AdditionRecord = {
    module, cap_id: capId, fields,
    author_email: authorEmail, author_username: username, updated_at,
  };
  const body = emitYaml(rec);
  const message = existing
    ? `editor(addition): update ${module}/${capId} (by ${username})`
    : `editor(addition): create ${module}/${capId} (by ${username})`;
  const result = await putFile(auth, branch, path, body, message, existing?.sha);
  return { ...rec, sha: result.sha };
}

/** Non-module additions — for Solution / Workflows / Integration / AI tabs.
 *  Stored at `drafts/<user>/_additions/_<tab>/<id>.yaml`.
 *  Backing pipeline step for non-module additions is TODO; for now drafts
 *  accumulate on the user's branch and the morning-review surface lists them.
 */
export type NonModuleTab = "compliance" | "workflows" | "integration" | "ai";

export interface NonModuleAdditionFields {
  /** Free-form title — required. */
  name: string;
  /** Optional description / context. */
  description?: string;
  /** Required for compliance: which regulator/framework (PDPA, CEM, VA-PT). */
  regulator?: string;
  /** Required for workflows: cross-module workflow name (O2C, P2P, etc.). */
  workflow_name?: string;
  /** Required for integration: which two caps does this declare? */
  cap_pair?: string;
  /** Free-form fields per tab. */
  vendor_question?: string;
  note?: string;
  /** Mandatory flag (compliance only). */
  mandatory?: boolean;
}

export interface NonModuleAdditionRecord {
  tab: NonModuleTab;
  item_id: string;
  fields: NonModuleAdditionFields;
  author_email: string;
  author_username: string;
  updated_at: string;
  sha?: string;
}

function nonModuleAdditionPath(username: string, tab: NonModuleTab, itemId: string): string {
  return `drafts/${username}/_additions/_${tab}/${itemId}.yaml`;
}

export function generateNonModuleId(tab: NonModuleTab, name: string): string {
  const slug = slugifyForCapId(name);
  const rand = Math.floor(Math.random() * 0x10000).toString(16).padStart(4, "0");
  return `${tab}_${slug}_${rand}`;
}

function emitNonModuleYaml(rec: NonModuleAdditionRecord): string {
  const f = rec.fields;
  const lines: string[] = [
    `# Non-module addition (${rec.tab}) — drafts/<user>/_additions/_${rec.tab}/<id>.yaml`,
    `tab: ${rec.tab}`,
    `item_id: ${yamlScalar(rec.item_id)}`,
    `name: ${yamlScalar(f.name)}`,
  ];
  if (f.description) lines.push(`description: ${yamlScalar(f.description)}`);
  if (f.regulator) lines.push(`regulator: ${yamlScalar(f.regulator)}`);
  if (f.workflow_name) lines.push(`workflow_name: ${yamlScalar(f.workflow_name)}`);
  if (f.cap_pair) lines.push(`cap_pair: ${yamlScalar(f.cap_pair)}`);
  if (f.vendor_question) lines.push(`vendor_question: ${yamlScalar(f.vendor_question)}`);
  if (f.mandatory !== undefined) lines.push(`mandatory: ${f.mandatory}`);
  if (f.note) lines.push(`note: ${yamlScalar(f.note)}`);
  lines.push(`author: ${rec.author_email}`);
  lines.push(`author_username: ${rec.author_username}`);
  lines.push(`edited_at: ${yamlScalar(rec.updated_at)}`);
  return lines.join("\n") + "\n";
}

export async function saveNonModuleAddition(
  auth: GitHubAuth,
  username: string,
  authorEmail: string,
  tab: NonModuleTab,
  fields: NonModuleAdditionFields,
  itemIdOverride?: string,
): Promise<NonModuleAdditionRecord> {
  await ensureUserDraftBranch(auth, username);
  const branch = draftBranch(username);
  const itemId = itemIdOverride || generateNonModuleId(tab, fields.name);
  const path = nonModuleAdditionPath(username, tab, itemId);
  const existing = await getFileWithSha(auth, path, branch);
  const updated_at = new Date().toISOString();
  const rec: NonModuleAdditionRecord = {
    tab, item_id: itemId, fields,
    author_email: authorEmail, author_username: username, updated_at,
  };
  const body = emitNonModuleYaml(rec);
  const message = existing
    ? `editor(addition): update _${tab}/${itemId} (by ${username})`
    : `editor(addition): create _${tab}/${itemId} (by ${username})`;
  const result = await putFile(auth, branch, path, body, message, existing?.sha);
  return { ...rec, sha: result.sha };
}

export async function clearAddition(
  auth: GitHubAuth,
  username: string,
  module: string,
  capId: string,
): Promise<void> {
  // Discard pattern matches drafts.ts.clearDraft — write a tombstone YAML
  // so we don't trip the DELETE/Trees-API quirks.
  await ensureUserDraftBranch(auth, username);
  const branch = draftBranch(username);
  const path = additionPath(username, module, capId);
  const updated_at = new Date().toISOString();
  const tombstone = [
    `# Tombstone — addition was discarded.`,
    `cap_id: ${yamlScalar(capId)}`,
    `module: ${yamlScalar(module)}`,
    `_discarded: true`,
    `author_username: ${yamlScalar(username)}`,
    `edited_at: ${yamlScalar(updated_at)}`,
    ``,
  ].join("\n");
  const message = `editor(addition): discard ${module}/${capId} (by ${username})`;
  for (let attempt = 0; attempt < 3; attempt++) {
    const existing = await getFileWithSha(auth, path, branch);
    if (!existing) return;
    try {
      await putFile(auth, branch, path, tombstone, message, existing.sha);
      return;
    } catch (e) {
      if (attempt < 2) continue;
      throw e;
    }
  }
}

export { recordFromYaml as _recordFromYaml, emitYaml as _emitYaml };
