import type { PricingDetailPlan } from "./pricingData";

/**
 * Per-vendor feature × plan matrix builder.
 *
 * Today's pricingData renders Haiku-parsed plans as a vertical list with
 * features stacked per plan — useful as a dump, hard to compare. The
 * matrix builder transposes that view: rows = unique features, columns
 * = plans (sorted cheapest → priciest), cells flag the strongest tag.
 *
 * Inputs that vary across plans for the SAME feature are normalised by
 * lowercased+trimmed `text` so "GL & CoA" and "GL & CoA " both collapse.
 * That's imperfect (won't catch paraphrases) but matches the way Haiku
 * tends to emit consistent phrasing within a vendor's parsed page.
 */
export type CellKind = "included" | "add_on" | "absent";

export interface MatrixPlan {
  /** Stable column id — index in the plan array. */
  id: number;
  /** Display name. Falls back to "Plan N" when the source name is empty. */
  name: string;
  /** Display string for the price column header. Never undefined — empty
   *  source rolls up to a single em-dash. */
  priceDisplay: string;
  /** Numeric amount used for column ordering (null = price-less plans
   *  drop to the right). */
  amount: number | null;
  /** Source unit ("/mo", "per user/year", etc.). */
  unit?: string;
}

export interface MatrixRow {
  /** The canonical feature label (first occurrence wins for casing). */
  feature: string;
  /** Per-plan cell tag, indexed by MatrixPlan.id. */
  cells: CellKind[];
  /** True iff the feature is included in every priced plan — used to
   *  surface "tier-independent baseline" features at the top of the
   *  matrix without needing a separate section. */
  universal: boolean;
}

export interface FeatureMatrix {
  plans: MatrixPlan[];
  rows: MatrixRow[];
}

function normaliseKey(text: string): string {
  return text.toLowerCase().replace(/\s+/g, " ").trim();
}

function priceDisplay(plan: PricingDetailPlan): string {
  const p = plan.price;
  if (!p) return "—";
  const parts: string[] = [];
  if (typeof p.amount === "number") parts.push(p.amount.toLocaleString());
  if (p.currency) parts.push(p.currency);
  const head = parts.length > 0 ? parts.join(" ") : "—";
  return p.unit ? `${head} ${p.unit}` : head;
}

/** Build the feature × plan matrix for a vendor's parsed plans. */
export function buildFeatureMatrix(plans: PricingDetailPlan[]): FeatureMatrix {
  if (plans.length === 0) return { plans: [], rows: [] };

  // Sort plans by price ascending; nulls trail so unpriced plans sit at
  // the right where they don't crowd out the comparison columns.
  const indexed = plans.map((p, i) => ({ src: p, srcIndex: i }));
  indexed.sort((a, b) => {
    const aa = a.src.price?.amount;
    const bb = b.src.price?.amount;
    if (aa == null && bb == null) return a.srcIndex - b.srcIndex;
    if (aa == null) return 1;
    if (bb == null) return -1;
    return aa - bb;
  });

  const matrixPlans: MatrixPlan[] = indexed.map((entry, colIdx) => ({
    id: colIdx,
    name: entry.src.name || `Plan ${entry.srcIndex + 1}`,
    priceDisplay: priceDisplay(entry.src),
    amount: entry.src.price?.amount ?? null,
    unit: entry.src.price?.unit,
  }));

  // Walk every plan once, accumulate (canonical-label, perPlanTag) map.
  type FeatureRow = { label: string; cells: CellKind[] };
  const byKey = new Map<string, FeatureRow>();
  const ensure = (key: string, label: string): FeatureRow => {
    let r = byKey.get(key);
    if (!r) {
      r = { label, cells: new Array(matrixPlans.length).fill("absent") };
      byKey.set(key, r);
    }
    return r;
  };

  for (let colIdx = 0; colIdx < indexed.length; colIdx++) {
    const plan = indexed[colIdx].src;
    for (const f of plan.included_features || []) {
      const key = normaliseKey(f.text);
      if (!key) continue;
      ensure(key, f.text).cells[colIdx] = "included";
    }
    for (const f of plan.add_on_features || []) {
      const key = normaliseKey(f.text);
      if (!key) continue;
      // Don't downgrade an "included" cell to "add_on" if the same feature
      // appears in both lists for the same plan — included wins.
      const row = ensure(key, f.text);
      if (row.cells[colIdx] === "absent") row.cells[colIdx] = "add_on";
    }
  }

  const universal = (cells: CellKind[]): boolean =>
    cells.length > 0 && cells.every(c => c === "included");

  const includedCount = (cells: CellKind[]): number =>
    cells.filter(c => c === "included").length;

  const rows: MatrixRow[] = Array.from(byKey.values())
    .map(r => ({ feature: r.label, cells: r.cells, universal: universal(r.cells) }))
    .sort((a, b) => {
      // Universal features first (the "baseline" every plan delivers).
      if (a.universal !== b.universal) return a.universal ? -1 : 1;
      // Then by inclusion breadth (features in more plans before niche ones).
      const aCount = includedCount(a.cells);
      const bCount = includedCount(b.cells);
      if (aCount !== bCount) return bCount - aCount;
      // Finally alphabetical for stable output.
      return a.feature.localeCompare(b.feature);
    });

  return { plans: matrixPlans, rows };
}
