// ── Coverage Matrix (Dashboard Perspective C) ────────────────────────────
// Per-module sol-cat × cap + vendor × cap. Built by
// scripts/build_coverage_matrix.py.

export type CoverageMatrixCellGlyph =
  | "in_base"
  | "in_base_pro"
  | "in_base_top"
  | "add_on"
  | "evidenced"
  | "not_covered"
  | "no_data";

/** Where the cell's coverage signal came from.
 *   - "pricing_plan": resolved against the vendor's pricing-page plan
 *     mapping (in_base*, add_on, not_covered).
 *   - "feature_page": resolved against feature_cap_mappings.yaml (the
 *     vendor's product-feature page evidence). Maps to the `evidenced`
 *     glyph — no pricing tier is known.
 *   - "none": no signal in either pipeline. Maps to `no_data`. */
export type CoverageMatrixCoverageSource = "pricing_plan" | "feature_page" | "none";

export interface CoverageMatrixCap {
  cap_id: string;
  name: string;
  sme_tier: "required" | "preferred";
  sub_module?: string | null;
  /** Sub-module slug from config/sub_modules.yaml (e.g. "sales_transactions"). */
  sub_module_id?: string | null;
  /** Family / umbrella name (e.g. "Sales Transactions" or "CRM & Relationship").
   *  Caps order is family → sub_module → cap_order within each tier. */
  family?: string | null;
  /** Cluster id resolved from canonical `preferred_clusters` (multi-core
   *  modules) or the synthetic `<tier>:all` for single-core. */
  cluster_id: string;
  /** Human-readable cluster name (e.g. "Production & Shop Floor", "Other",
   *  or "Mandatory" for single-mode). */
  cluster_name: string;
  /** ISO-8601 aggregate timestamp: max(canonical pipeline run, latest
   *  feature_cap_mappings refresh touching this cap). Surfaced as
   *  "Updated: <date>" in the CapLibrary Solutions Coverage sub-tab. */
  last_updated?: string;
  /** Per-source timestamps for the hover-tooltip breakdown.
   *   - pipeline_at: canonical step16_applied_at (module-level)
   *   - feature_evidence_at: latest feature_cap_mappings mapping_at for any
   *     vendor that evidenced THIS cap (empty if no FP evidence) */
  last_updated_sources?: {
    pipeline_at?: string;
    feature_evidence_at?: string;
  };
}

export interface CoverageMatrixSolCat {
  sol_cat: string;
  slug: string;
  vertical?: string | null;
  /** Number of module caps this sol cat marks as Mandatory (confidence:high). */
  mandate_count: number;
  /** cap_id → "mandatory" | "preferred". Missing key = sol cat doesn't reference. */
  cap_priorities: Record<string, "mandatory" | "preferred">;
}

export interface CoverageMatrixVendorCell {
  glyph: CoverageMatrixCellGlyph;
  tier_first_in_base?: "cheapest" | "mid" | "top" | null;
  /** Where the signal came from. New cells (post-feature-page wiring,
   *  2026-05-17) always carry this. Older payload regenerations may omit
   *  it — treat absence as `pricing_plan` for backwards compat. */
  coverage_source?: CoverageMatrixCoverageSource;
  /** Haiku confidence for `evidenced` cells. Absent for pricing-resolved
   *  cells (pricing-plan mapping has its own confidence inside the YAML
   *  but isn't surfaced here). */
  confidence?: "high" | "medium" | "low";
}

export interface CoverageMatrixVendor {
  vendor_id: string;
  vendor_name: string;
  vendor_type: string;
  vendor_tier: string;
  /** PSG id (when PSG-listed). Null = non-PSG (Workday, NetSuite, etc.). */
  psg_id?: string | null;
  /** PSG sol cat tag (full name). Null = non-PSG. */
  psg_sol_cat?: string | null;
  psg_sol_cat_short?: string | null;
  /** What kind of extract data backs this vendor.
   *   - "psg_pdf": vendor has a PSG-PDF extract with packages
   *   - "web": vendor has scraped pricing-page plans
   *   - "feature_only": vendor extract exists but no pricing tiers
   *   - "feature_page": no extract at all, but feature-page evidence
   *     exists (cells will use the `evidenced` glyph)
   *   - "no_data": neither pricing nor feature evidence */
  data_source: "psg_pdf" | "web" | "feature_only" | "feature_page" | "no_data";
  has_extract: boolean;
  cells: Record<string, CoverageMatrixVendorCell>;
}

/** Cluster definition for one tier in one module. Multi-core modules
 *  carry N named clusters + a tail `<tier>:other`; single-core modules
 *  carry one synthetic `<tier>:all`. */
export interface CoverageMatrixCluster {
  cluster_id: string;
  cluster_name: string;
  tier: "Mandatory" | "Preferred";
  order: number;
}

export interface CoverageMatrixModule {
  module_short: string;
  caps: CoverageMatrixCap[];
  /** Cluster definitions per tier, declaration-ordered. The SPA uses this
   *  to render named umbrellas under each tier for multi-core modules. */
  clusters_by_tier?: { required?: CoverageMatrixCluster[]; preferred?: CoverageMatrixCluster[] };
  /** `multi` (named clusters) vs `single` (one synthetic cluster) per tier.
   *  Drives whether the SPA shows a cluster sub-heading or collapses to a
   *  single "Mandatory umbrella" / "Preferred umbrella" heading. */
  cluster_mode_by_tier?: { required?: "multi" | "single"; preferred?: "multi" | "single" };
  sol_cats: CoverageMatrixSolCat[];
  vendors: CoverageMatrixVendor[];
}

export interface CoverageMatrixPayload {
  _meta?: { generated_by?: string; modules_in_scope?: string[] };
  modules: Record<string, CoverageMatrixModule>;
}

export interface StakeholdersSummary {
  generated_at: string;
  /** ISO-8601 of the most recent canonical mutation (latest
   *  step16_applied_at across all output/canonical/*.json). Used by the
   *  /admin/health dashboard to surface pipeline freshness. */
  last_pipeline_run?: string | null;
  kpis: StakeholdersKPIs;
  modules: ModuleEntry[];
  pipeline_stages: PipelineStage[];
  audit_summary: AuditSummary;
  sol_cats: SolCatRow[];
  excluded_sol_cats: ExcludedSolCat[];
  exclusion_groups: Record<string, string>;
  submodule_specificity: Record<string, SubModuleSpecificity>;
  caps_index: CapEvidence[];
  module_imda_questions: Record<string, ModuleImdaQuestion[]>;
  module_imda_summary: Record<string, ModuleImdaSummary>;
  solcat_questions: Record<string, SolcatQuestion[]>;
  solcat_scope: Record<string, SolcatScopeRow[]>;
  proxy_id_to_name: Record<string, string>;
  solcat_fulfilment: SolCatFulfilmentRow[];
  solcat_fulfilment_realistic_meta: FulfilmentMeta;
  proxy_fulfilment: ProxyFulfilmentPayload;
  per_module_views: Record<string, PerModuleView>;
  /** Vendor pricing data — null if scripts/build_vendor_pricing_summary.py
   *  hasn't been run, or if the JSON file is missing on disk. */
  vendor_pricing?: VendorPricingPayload | null;
  /** Cross-module baseline compliance requirements (CEM / PDPA / VA-PT).
   *  PSG pre-approval mandates these for every vendor regardless of which
   *  module they ship. Surfaced on each module's checklist page below
   *  the regular Mandatory/Preferred caps. Source:
   *  output/compliance_baseline.json. */
  compliance_baseline?: ComplianceBaselinePayload | null;
  /** Per-module sol-cat × cap + vendor × cap coverage matrix.
   *  Drives Dashboard Perspective C. Built by
   *  scripts/build_coverage_matrix.py from solcat_expected_caps +
   *  vendor extracts. Null if the build hasn't run. */
  coverage_matrix?: CoverageMatrixPayload | null;
  /** LLM-expanded "what caps an industry-real product in this sol cat
   *  should provide" — per-sol-cat target list. Empty if expansion script
   *  hasn't run. Source: data/_derived/solcat_expected_caps.yaml. */
  solcat_expected_caps?: SolcatExpectedPayload | null;
  // Trailing index signature kept for forward compatibility with payload
  // fields the SPA hasn't typed yet.
  [key: string]: unknown;
}

let _cache: StakeholdersSummary | null = null;
let _inflight: Promise<StakeholdersSummary> | null = null;

export async function loadStakeholdersSummary(): Promise<StakeholdersSummary> {
  if (_cache) return _cache;
  if (_inflight) return _inflight;
  _inflight = fetch(`${import.meta.env.BASE_URL}stakeholders_summary.json`, { credentials: "same-origin" })
    .then(res => {
      if (!res.ok) throw new Error(`stakeholders_summary fetch failed: ${res.status}`);
      return res.json() as Promise<StakeholdersSummary>;
    })
    .then(payload => {
      _cache = payload;
      _inflight = null;
      return payload;
    })
    .catch(e => {
      _inflight = null;
      throw e;
    });
  return _inflight;
}

export function _resetStakeholdersSummaryCache(): void {
  _cache = null;
  _inflight = null;
}
