import { useEffect, useState } from "react";
import { loadStakeholdersSummary, type StakeholdersSummary } from "../lib/stakeholdersData";
import { MethodologySection } from "../components/MethodologySection";
import { CapComparison } from "../components/CapComparison";
import { TabHelp } from "../components/TabHelp";
import "./StakeholdersPage.css";

/**
 * Methodology page — narrative + cap-comparison view.
 *
 * Two sections only:
 *   §1 MethodologySection — two-anchor lineage + 6-stage pipeline + principles
 *   §2 CapComparison      — per-module breakdown of IMDA-backed vs proxy-only caps
 *
 * Everything else (sub-module verdict chips, evidence drill, fulfilment matrix,
 * ERP scoreboard, pipeline deep-dive table, per-module deep-dive) was retired
 * 2026-05-10 because Coverage / Cap library / canonical / BUILD-tools cover the
 * same surface at higher fidelity.
 */
export function StakeholdersPage() {
  const [summary, setSummary] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setSummary)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  if (error) {
    return (
      <section className="stakeholders-page error">
        <h1>Methodology</h1>
        <p>Failed to load summary: {error}</p>
      </section>
    );
  }

  if (!summary) {
    return (
      <section className="stakeholders-page">
        <p className="muted">Loading methodology summary…</p>
      </section>
    );
  }

  return (
    <section className="stakeholders-page">
      <TabHelp hint="§1 = the two evidence anchors (IMDA mandatory Qs + reference ERPs) + 6-stage pipeline lineage. §2 = per-module breakdown: how many caps are IMDA-backed vs proxy-only.">
        Methodology view for stakeholders / auditors. Explains where caps come
        from (PSG sol cat mandates + reference ERP convention) and how every
        cap maps back to evidence. No editing happens here — this is the
        trust-chain page.
      </TabHelp>
      <MethodologySection summary={summary} />
      <CapComparison
        modules={summary.modules}
        capsIndex={summary.caps_index}
        moduleImdaSummary={summary.module_imda_summary}
        moduleImdaQuestions={summary.module_imda_questions}
      />
    </section>
  );
}
