import { GENERIC, type SectorFilter as SectorFilterValue } from "../lib/sectorFilter";
import "./SectorFilter.css";

export interface SectorFilterProps {
  sector: SectorFilterValue;
  applicableSectors: string[];
  onChange: (next: SectorFilterValue) => void;
}

export function SectorFilter({ sector, applicableSectors, onChange }: SectorFilterProps) {
  const isGeneric = sector === GENERIC;
  const isAll = sector === null;
  return (
    <div className="sector-filter" role="group" aria-label="Sector filter">
      <span className="sector-filter-label">Sector:</span>
      <Pill name="Generic" active={isGeneric} onClick={() => onChange(GENERIC)} />
      <Pill name="All" active={isAll} onClick={() => onChange(null)} />
      {applicableSectors.map(s => (
        <Pill key={s} name={s} active={sector === s} onClick={() => onChange(s)} />
      ))}
    </div>
  );
}

function Pill({ name, active, onClick }: { name: string; active: boolean; onClick: () => void }) {
  return (
    <button
      type="button"
      className={`sector-pill${active ? " active" : ""}`}
      aria-pressed={active}
      onClick={onClick}
    >
      {name}
    </button>
  );
}
