/**
 * Typed GitHub REST API client for the v2 GitHub-native editor.
 *
 * Replaces the CF Worker + D1 backend with direct browser → api.github.com
 * calls. The browser holds a user-supplied PAT (or future OAuth token)
 * and signs every request with it.
 *
 * Design notes:
 *  - All methods take an explicit `auth` param rather than reading from a
 *    closure / module-level singleton. Easier to test, harder to leak.
 *  - Errors throw a typed `GitHubApiError` with status + GH-side message.
 *    Callers can branch on status (401 → invalid token, 403 → rate-limit
 *    or forbidden, 404 → not found, 422 → validation, 5xx → retry).
 *  - Rate-limit detection: when 403 with `X-RateLimit-Remaining: 0`, we
 *    surface the reset time so the UI can show "rate limited until HH:MM".
 *  - Content >1MB: GitHub's Contents API returns metadata with `content: ""`
 *    and a `download_url`. The `getContents()` helper auto-follows the
 *    download_url when content is empty.
 *
 * Not yet implemented (W1 scope = reads only): write paths (PUT contents,
 * create blob/tree/commit, ref updates). Those land in W2.
 */

const GH_API_BASE = "https://api.github.com";

export interface GitHubAuth {
  /** Either a PAT (`github_pat_...`) or an OAuth access token. Same Bearer
   *  shape on the wire. The `kind` tag is informational so future code can
   *  branch on auth source (e.g. PAT rotation reminders). */
  token: string;
  kind: "pat" | "oauth";
  /** The repo this auth was minted for. Reads/writes outside this scope
   *  are blocked at validation time. */
  repoOwner: string;
  repoName: string;
}

export interface GitHubUser {
  login: string;
  id: number;
  name: string | null;
  email: string | null;
  avatar_url: string;
}

export interface ContentsResponse {
  type: "file" | "dir" | "submodule" | "symlink";
  encoding?: "base64";
  size: number;
  name: string;
  path: string;
  sha: string;
  /** base64-encoded payload — empty string when size >1MB; use download_url. */
  content?: string;
  download_url: string | null;
}

export class GitHubApiError extends Error {
  constructor(
    public status: number,
    public method: string,
    public path: string,
    message: string,
    /** Populated when GH returned a structured response. */
    public githubMessage?: string,
    /** Populated when GH 403'd us for rate-limit reasons. UNIX epoch seconds. */
    public rateLimitReset?: number,
  ) {
    super(message);
    this.name = "GitHubApiError";
  }

  get isAuthError(): boolean {
    return this.status === 401;
  }
  get isRateLimit(): boolean {
    return this.status === 403 && this.rateLimitReset !== undefined;
  }
  get isNotFound(): boolean {
    return this.status === 404;
  }
}

async function ghFetch(
  auth: GitHubAuth | null,
  method: string,
  path: string,
  body?: unknown,
): Promise<Response> {
  const url = path.startsWith("http") ? path : `${GH_API_BASE}${path}`;
  const headers: Record<string, string> = {
    "Accept": "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
  };
  if (auth?.token) {
    headers["Authorization"] = `Bearer ${auth.token}`;
  }
  if (body !== undefined) {
    headers["Content-Type"] = "application/json";
  }
  // `cache: "no-store"` prevents the browser from serving a stale cached
  // response. The SHAs in Contents API responses are checked against
  // GitHub's current state on subsequent PUT/DELETE calls; a stale SHA
  // returns 409 "does not match". Disabling cache forces a fresh round-trip.
  const res = await fetch(url, {
    method,
    headers,
    cache: "no-store",
    body: body !== undefined ? JSON.stringify(body) : undefined,
  });

  if (!res.ok) {
    let githubMessage: string | undefined;
    try {
      const j = await res.clone().json() as { message?: string };
      githubMessage = j?.message;
    } catch {
      // non-JSON error body; leave undefined
    }
    const rateLimitRemaining = res.headers.get("x-ratelimit-remaining");
    const rateLimitReset = res.headers.get("x-ratelimit-reset");
    const isRateLimit =
      res.status === 403 && rateLimitRemaining === "0" && rateLimitReset !== null;
    throw new GitHubApiError(
      res.status,
      method,
      path,
      `${method} ${path} → ${res.status}${githubMessage ? `: ${githubMessage}` : ""}`,
      githubMessage,
      isRateLimit ? parseInt(rateLimitReset!, 10) : undefined,
    );
  }
  return res;
}

// ── Read-side methods (W1) ────────────────────────────────────────────────

/** Verify a token + return the authenticated user. Throws GitHubApiError on
 *  401/403. Used by AuthContext on sign-in to validate before persisting. */
export async function getAuthenticatedUser(auth: GitHubAuth): Promise<GitHubUser> {
  const res = await ghFetch(auth, "GET", "/user");
  return res.json() as Promise<GitHubUser>;
}

export interface RepoInvitation {
  id: number;
  repository: { full_name: string; html_url: string };
  invitee: { login: string };
  inviter: { login: string };
  permissions: "read" | "triage" | "write" | "maintain" | "admin";
  html_url: string;
  created_at: string;
}

/** List pending repository invitations for the authenticated user.
 *
 *  GitHub returns 404 from /repos/{owner}/{name} for private repos the
 *  caller has no access to — but if they have a *pending* invite, this
 *  endpoint surfaces it. Used by AuthContext to produce a precise
 *  "you have an unaccepted invite — click here" error instead of the
 *  generic "can't see the repo" message.
 *
 *  Returns [] on any error (the call is purely diagnostic). */
export async function listPendingInvitations(
  auth: GitHubAuth,
): Promise<RepoInvitation[]> {
  try {
    const res = await ghFetch(auth, "GET", "/user/repository_invitations");
    return (await res.json()) as RepoInvitation[];
  } catch {
    return [];
  }
}

/** Check whether the authenticated user has push access to the target repo.
 *  Used as the role gate (push access → editor; read-only → viewer). */
export async function checkRepoAccess(auth: GitHubAuth): Promise<{
  permissions: { admin: boolean; push: boolean; pull: boolean };
  private: boolean;
}> {
  const res = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}`,
  );
  const data = await res.json() as {
    permissions?: { admin?: boolean; push?: boolean; pull?: boolean };
    private?: boolean;
  };
  return {
    permissions: {
      admin: !!data.permissions?.admin,
      push: !!data.permissions?.push,
      pull: !!data.permissions?.pull,
    },
    private: !!data.private,
  };
}

/** Decode a base64 string back to a UTF-8 string. atob alone breaks multi-byte
 *  characters (em-dashes, accented letters, etc.) because it returns a binary
 *  latin-1 string. We round-trip through Uint8Array + TextDecoder to preserve
 *  UTF-8 correctly.
 *
 *  Used by both getFileText and getFileWithSha so saved drafts containing
 *  any non-ASCII char read back correctly. */
function decodeBase64Utf8(b64: string): string {
  const binary = atob(b64.replace(/\n/g, ""));
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new TextDecoder("utf-8").decode(bytes);
}

/** Fetch a single file's contents. Two paths:
 *    - Contents API returns the content inline (base64) for files ≤1MB.
 *    - For files >1MB Contents API returns empty content + a download_url.
 *      We deliberately AVOID the download_url path — its embedded token is
 *      flaky for cross-origin browser fetches on private repos. Instead we
 *      use the Git Blobs API which authenticates cleanly via the Bearer
 *      header and supports up to 100MB.
 */
export async function getFileText(
  auth: GitHubAuth,
  path: string,
  ref: string = "main",
): Promise<string> {
  const res = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/contents/${path}?ref=${encodeURIComponent(ref)}`,
  );
  const meta = await res.json() as ContentsResponse;
  if (meta.encoding === "base64" && meta.content) {
    return decodeBase64Utf8(meta.content);
  }
  // Large file (>1MB) — Contents API returned metadata only. Fall back
  // to the Git Blobs API with the same SHA.
  if (meta.sha) {
    return getBlobText(auth, meta.sha);
  }
  throw new GitHubApiError(
    500, "GET", path,
    `unexpected Contents API shape: no inline content, no SHA for blob fallback`,
  );
}

/** Fetch a blob's content via the Git Data API. Always authenticated by
 *  Bearer header, supports up to 100MB, no download_url-token quirks. */
async function getBlobText(auth: GitHubAuth, sha: string): Promise<string> {
  const res = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/blobs/${sha}`,
  );
  const data = await res.json() as { content: string; encoding: string };
  if (data.encoding !== "base64") {
    throw new GitHubApiError(500, "GET", sha, `unexpected blob encoding: ${data.encoding}`);
  }
  return decodeBase64Utf8(data.content);
}

/** Convenience wrapper — parse a JSON file from the repo. */
export async function getFileJson<T = unknown>(
  auth: GitHubAuth,
  path: string,
  ref: string = "main",
): Promise<T> {
  const text = await getFileText(auth, path, ref);
  return JSON.parse(text) as T;
}

/** Like getFileText but also returns the blob's SHA (needed for subsequent
 *  PUTs that update the file). Returns null when the file doesn't exist. */
export interface FileWithSha {
  text: string;
  sha: string;
}
export async function getFileWithSha(
  auth: GitHubAuth,
  path: string,
  ref: string = "main",
): Promise<FileWithSha | null> {
  try {
    const res = await ghFetch(auth, "GET",
      `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/contents/${path}?ref=${encodeURIComponent(ref)}`,
    );
    const meta = await res.json() as ContentsResponse;
    let text: string;
    if (meta.encoding === "base64" && meta.content) {
      text = decodeBase64Utf8(meta.content);
    } else if (meta.sha) {
      // >1MB file — fall back to Git Blobs API (Bearer-authed, no
      // download_url cross-origin token quirks).
      text = await getBlobText(auth, meta.sha);
    } else {
      throw new GitHubApiError(500, "GET", path, "unexpected Contents API shape");
    }
    return { text, sha: meta.sha };
  } catch (e) {
    if (e instanceof GitHubApiError && e.isNotFound) return null;
    throw e;
  }
}

/** List a directory's contents on a given ref. Returns null when the dir
 *  doesn't exist (Contents API returns 404 for missing paths). */
export interface DirEntry {
  type: "file" | "dir";
  name: string;
  path: string;
  sha: string;
  size: number;
}
export async function listDirectory(
  auth: GitHubAuth,
  path: string,
  ref: string = "main",
): Promise<DirEntry[] | null> {
  try {
    const res = await ghFetch(auth, "GET",
      `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/contents/${path}?ref=${encodeURIComponent(ref)}`,
    );
    const data = await res.json();
    if (!Array.isArray(data)) {
      // Path is a file, not a directory — treat as empty for our purposes.
      return null;
    }
    return (data as Array<{ type: string; name: string; path: string; sha: string; size: number }>)
      .filter(d => d.type === "file" || d.type === "dir")
      .map(d => ({
        type: d.type as "file" | "dir",
        name: d.name,
        path: d.path,
        sha: d.sha,
        size: d.size ?? 0,
      }));
  } catch (e) {
    if (e instanceof GitHubApiError && e.isNotFound) return null;
    throw e;
  }
}

// ── Write-side methods (W2) ───────────────────────────────────────────────

/** Branch ops — wraps the Git Refs API. */
export interface BranchHead {
  ref: string;       // "refs/heads/<name>"
  sha: string;       // commit SHA at the branch head
}

export async function getBranchHead(
  auth: GitHubAuth,
  branch: string,
): Promise<BranchHead | null> {
  try {
    const res = await ghFetch(auth, "GET",
      `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/ref/heads/${encodeURIComponent(branch)}`,
    );
    const data = await res.json() as { ref: string; object: { sha: string } };
    return { ref: data.ref, sha: data.object.sha };
  } catch (e) {
    if (e instanceof GitHubApiError && e.isNotFound) return null;
    throw e;
  }
}

/** Create a new branch pointing at the head of an existing one (default: main).
 *  Idempotent — if the branch already exists, returns its current head. */
export async function ensureBranch(
  auth: GitHubAuth,
  newBranch: string,
  fromBranch: string = "main",
): Promise<BranchHead> {
  const existing = await getBranchHead(auth, newBranch);
  if (existing) return existing;
  const source = await getBranchHead(auth, fromBranch);
  if (!source) {
    throw new GitHubApiError(404, "GET", fromBranch, `source branch ${fromBranch} not found`);
  }
  const res = await ghFetch(auth, "POST",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/refs`,
    { ref: `refs/heads/${newBranch}`, sha: source.sha },
  );
  const data = await res.json() as { ref: string; object: { sha: string } };
  return { ref: data.ref, sha: data.object.sha };
}

/** Delete a branch by name. Used by publish() to drain a user's draft branch
 *  after merging it into main. */
export async function deleteBranch(
  auth: GitHubAuth,
  branch: string,
): Promise<void> {
  await ghFetch(auth, "DELETE",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/refs/heads/${encodeURIComponent(branch)}`,
  );
}

/** Write a single file via Contents API. Creates the file if `sha` omitted;
 *  updates it (matching the blob's current SHA) if provided. Returns the new
 *  blob SHA for chaining. */
export async function putFile(
  auth: GitHubAuth,
  branch: string,
  path: string,
  content: string,
  message: string,
  sha?: string,
): Promise<{ sha: string; commit_sha: string }> {
  const body: Record<string, unknown> = {
    message,
    content: btoa(unescape(encodeURIComponent(content))),
    branch,
  };
  if (sha) body.sha = sha;
  const res = await ghFetch(auth, "PUT",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/contents/${path}`,
    body,
  );
  const data = await res.json() as {
    content: { sha: string };
    commit: { sha: string };
  };
  return { sha: data.content.sha, commit_sha: data.commit.sha };
}

/** Delete a file via Contents API. SHA must match the current blob.
 *
 *  Note: deleteFileViaTreeRebuild is the recommended path for v2 since
 *  some networks strip request bodies from DELETE calls, and the Trees
 *  API's sha:null trick can fail with GitRPC::BadObjectState on nested
 *  paths. Keeping this function for v1 / API parity but new code should
 *  prefer deleteFileViaTreeRebuild. */
export async function deleteFile(
  auth: GitHubAuth,
  branch: string,
  path: string,
  sha: string,
  message: string,
): Promise<{ commit_sha: string }> {
  const res = await ghFetch(auth, "DELETE",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/contents/${path}`,
    { message, branch, sha },
  );
  const data = await res.json() as { commit: { sha: string } };
  return { commit_sha: data.commit.sha };
}

/**
 * Robust file delete using the Git Data API — survives DELETE-body
 * stripping AND the BadObjectState quirk of `tree: [{sha: null}]` on
 * nested paths.
 *
 * Algorithm:
 *   1. Fetch the branch's recursive tree (every blob on the branch).
 *   2. Filter out the file path we want to delete.
 *   3. POST a new tree with the remaining entries (no base_tree — every
 *      blob is listed explicitly so GitHub doesn't try to reconcile).
 *   4. POST a commit pointing at the new tree with the current branch
 *      HEAD as the only parent.
 *   5. PATCH the branch ref to the new commit.
 *
 * Cost: 4 sequential API calls + one tree POST that includes every blob
 * in the branch (~few hundred KB for our repo). Worth the reliability.
 */
export async function deleteFileViaTreeRebuild(
  auth: GitHubAuth,
  branch: string,
  path: string,
  message: string,
): Promise<{ commit_sha: string }> {
  // 1. Branch HEAD + its tree SHA.
  const head = await getBranchHead(auth, branch);
  if (!head) {
    throw new GitHubApiError(404, "GET", branch, `branch ${branch} not found`);
  }
  const commitRes = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/commits/${head.sha}`,
  );
  const baseTreeSha = (await commitRes.json() as { tree: { sha: string } }).tree.sha;

  // 2. Recursive tree → every blob.
  const treeRes = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/trees/${baseTreeSha}?recursive=1`,
  );
  const treeData = await treeRes.json() as {
    truncated: boolean;
    tree: Array<{ path: string; mode: string; type: string; sha: string }>;
  };
  if (treeData.truncated) {
    // 100k entry hard cap from GitHub — our repo is well under, but guard
    // against silent partial trees.
    throw new GitHubApiError(
      500, "GET", "git/trees",
      "tree was truncated by GitHub (>100k entries); cannot safely rebuild",
    );
  }
  const filtered = treeData.tree.filter(e => e.type === "blob" && e.path !== path);
  if (filtered.length === treeData.tree.filter(e => e.type === "blob").length) {
    // File wasn't in the tree to begin with — treat as already deleted.
    return { commit_sha: head.sha };
  }

  // 3. POST new tree, no base_tree.
  const newTreeRes = await ghFetch(auth, "POST",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/trees`,
    {
      tree: filtered.map(e => ({
        path: e.path,
        mode: e.mode,
        type: "blob",
        sha: e.sha,
      })),
    },
  );
  const newTreeSha = (await newTreeRes.json() as { sha: string }).sha;

  // 4. New commit.
  const newCommitRes = await ghFetch(auth, "POST",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/commits`,
    { message, tree: newTreeSha, parents: [head.sha] },
  );
  const newCommitSha = (await newCommitRes.json() as { sha: string }).sha;

  // 5. Move the ref.
  await ghFetch(auth, "PATCH",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/refs/heads/${encodeURIComponent(branch)}`,
    { sha: newCommitSha, force: false },
  );

  return { commit_sha: newCommitSha };
}

// ── Atomic multi-file commit (Git Data API) ──────────────────────────────
// For publish-style operations that touch many files and must not tear,
// we use the lower-level Trees + Commits + Refs API. One commit, all files,
// no in-between state. Costs 4 + N API calls where N = number of file blobs.

export interface AtomicWriteItem {
  path: string;
  /** Content of the file. null/undefined = delete the file. */
  content: string | null;
}

export async function atomicMultiFileCommit(
  auth: GitHubAuth,
  branch: string,
  items: AtomicWriteItem[],
  message: string,
  /** Max times to retry on concurrent-push 422 from the ref update. Each
   *  retry re-fetches the branch head + rebuilds the tree on top of it.
   *  Bounded so a sustained write-storm doesn't loop forever. */
  maxRetries: number = 3,
): Promise<{ commit_sha: string; retries: number }> {
  if (items.length === 0) {
    throw new GitHubApiError(400, "POST", "atomicMultiFileCommit", "no items provided");
  }
  let retries = 0;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return { ...await singleAtomicAttempt(auth, branch, items, message), retries };
    } catch (e) {
      if (e instanceof GitHubApiError && e.status === 422 && attempt < maxRetries) {
        // Concurrent push moved the ref forward between our read and our
        // PATCH. Re-fetch HEAD + try again — our commit will sit on top
        // of the newer branch state. Linear backoff (50ms × attempt) to
        // avoid hammering a hot branch.
        retries++;
        await new Promise(r => setTimeout(r, 50 * (attempt + 1)));
        continue;
      }
      throw e;
    }
  }
  throw new GitHubApiError(
    422, "PATCH", `refs/heads/${branch}`,
    `atomic commit failed after ${maxRetries} retries — branch is under heavy concurrent write`,
  );
}

async function singleAtomicAttempt(
  auth: GitHubAuth,
  branch: string,
  items: AtomicWriteItem[],
  message: string,
): Promise<{ commit_sha: string }> {
  // 1. Get the branch head SHA + its tree SHA.
  const head = await getBranchHead(auth, branch);
  if (!head) {
    throw new GitHubApiError(404, "GET", branch, `branch ${branch} not found`);
  }
  const commitRes = await ghFetch(auth, "GET",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/commits/${head.sha}`,
  );
  const commitData = await commitRes.json() as { tree: { sha: string } };
  const baseTreeSha = commitData.tree.sha;

  // 2. Create blobs for non-null content. Deletes are signaled in the tree
  //    via `sha: null` (no blob needed).
  const blobs: Array<{ path: string; sha: string | null; mode: string }> = [];
  for (const item of items) {
    if (item.content === null) {
      blobs.push({ path: item.path, sha: null, mode: "100644" });
      continue;
    }
    const blobRes = await ghFetch(auth, "POST",
      `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/blobs`,
      {
        content: btoa(unescape(encodeURIComponent(item.content))),
        encoding: "base64",
      },
    );
    const blobData = await blobRes.json() as { sha: string };
    blobs.push({ path: item.path, sha: blobData.sha, mode: "100644" });
  }

  // 3. Create a new tree with base = the current tree, overrides from blobs.
  const treeRes = await ghFetch(auth, "POST",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/trees`,
    {
      base_tree: baseTreeSha,
      tree: blobs.map(b => ({
        path: b.path,
        mode: b.mode,
        type: "blob",
        sha: b.sha,
      })),
    },
  );
  const treeData = await treeRes.json() as { sha: string };

  // 4. Create the commit pointing at the new tree.
  const newCommitRes = await ghFetch(auth, "POST",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/commits`,
    {
      message,
      tree: treeData.sha,
      parents: [head.sha],
    },
  );
  const newCommitData = await newCommitRes.json() as { sha: string };

  // 5. Update the branch ref atomically. If a concurrent edit pushed to the
  //    branch since step 1, the ref update fails with 422 — caller's retry
  //    loop handles it.
  await ghFetch(auth, "PATCH",
    `/repos/${encodeURIComponent(auth.repoOwner)}/${encodeURIComponent(auth.repoName)}/git/refs/heads/${encodeURIComponent(branch)}`,
    { sha: newCommitData.sha, force: false },
  );

  return { commit_sha: newCommitData.sha };
}
