import { useEffect, useState, type ReactNode } from "react";
import { useNavigate } from "react-router-dom";
import { useDrafts } from "../contexts/DraftsContext";
import { api, type UserRole } from "../lib/api";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import {
  preflightPublishConflicts,
  previewPendingChanges,
  type OverwriteConflict,
  type PendingChangesSummary,
} from "../lib/publish";
import "./PublishButton.css";

/**
 * Floating bottom-right button: hidden when there are no drafts to publish.
 * Click → 2-step modal:
 *   Step 1: review list of pending drafts (cap_id + author + when)
 *   Step 2: confirm — repo / branch / aggregate counts
 *   Confirm → POST /api/publish; on success drafts drain server-side and
 *   the local cache empties via the context.
 */
type Step = "review" | "preflight" | "conflicts" | "confirm" | "running" | "done" | "error";

export function PublishButton() {
  const { draftsByCap, moduleStatePendingCount, publish } = useDrafts();
  const { user: ghUser, auth: ghAuth } = useAuth();
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState<Step>("review");
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<{ applied: number; commit_url?: string } | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [conflicts, setConflicts] = useState<OverwriteConflict[]>([]);
  // Full summary across all 5 change types — fetched on modal open so the
  // review can enumerate every change (additions, reorders, AI features,
  // cluster moves) instead of just D1 cap drafts.
  const [summary, setSummary] = useState<PendingChangesSummary | null>(null);
  const [summaryLoading, setSummaryLoading] = useState(false);

  useEffect(() => {
    if (GITHUB_NATIVE) {
      // v2 uses AuthContext role. Mapped from app_role; only admins publish.
      setRole((ghUser?.app_role as UserRole | undefined) ?? null);
      return;
    }
    api.me()
      .then(me => setRole(me.role || "editor"))
      .catch(() => setRole("editor"));
  }, [ghUser]);

  // Fetch the full pending-changes summary every time the modal opens.
  // Cap-field drafts are already cached in DraftsContext but additions /
  // reorders / AI features live on the GitHub draft branch and need a
  // fresh fetch — same primitives the publish flow itself uses.
  //
  // MUST sit above the early returns below — otherwise the hook ordering
  // changes between renders (first render: total === 0 → early return,
  // second render after drafts load: hook fires) and React unmounts the
  // tree with "Rendered more hooks than during the previous render".
  useEffect(() => {
    if (!open) return;
    if (!GITHUB_NATIVE || !ghAuth || !ghUser) {
      // v1 doesn't have additions / reorders / AI features as separate
      // GitHub paths — the draftsByCap map already covers everything.
      setSummary({
        capEdits: Array.from(draftsByCap.values()).map(d => ({
          module: d.module, cap_id: d.cap_id, fields: d.fields as Record<string, unknown>,
          author_email: d.author?.email || "", updated_at: d.updated_at || "",
        })),
        clusterMoves: [], additions: [], reordersByModule: {}, aiFeaturesByModule: {},
      });
      return;
    }
    setSummaryLoading(true);
    previewPendingChanges(ghAuth, ghUser.login)
      .then(s => { setSummary(s); })
      .catch(e => {
        console.warn("[publish] previewPendingChanges failed:", e);
        // Fallback: at least show D1 cap drafts so the modal isn't blank.
        setSummary({
          capEdits: Array.from(draftsByCap.values()).map(d => ({
            module: d.module, cap_id: d.cap_id, fields: d.fields as Record<string, unknown>,
            author_email: d.author?.email || "", updated_at: d.updated_at || "",
          })),
          clusterMoves: [], additions: [], reordersByModule: {}, aiFeaturesByModule: {},
        });
      })
      .finally(() => setSummaryLoading(false));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  const drafts = Array.from(draftsByCap.values()).sort((a, b) => {
    return (b.updated_at || "").localeCompare(a.updated_at || "");
  });
  const capDraftCount = drafts.length;
  // The Publish button needs to surface for BOTH cap-level drafts AND
  // module-state changes (cap_order overrides + ai_features responses).
  // Hiding when only module-state is pending was the bug that made users
  // unable to publish a reorder-only or AI-features-only change.
  const total = capDraftCount + moduleStatePendingCount;
  if (total === 0) return null;
  // Non-admins still see drafts in Pending edits + can save them, but the
  // Publish button is hidden so they don't push to main without rights.
  if (role !== "admin") return null;

  const close = () => {
    setOpen(false);
    setStep("review");
    setError(null);
    setResult(null);
    setConflicts([]);
    setSummary(null);
  };

  // Click a row → close modal + deep-link to the cap's module page. The
  // CanonicalPage reads the `cap` query param on mount and scrolls to the
  // matching row (see CanonicalPage.tsx:138 useSearchParams reader).
  // MUST use `?cap=...` not `#cap=...`: the router is HashRouter, so a
  // second `#` would land in the page hash and bypass the route's search
  // params — the deep-link silently no-ops.
  const openCap = (module: string, capId: string) => {
    close();
    navigate(`/canonical/${module}?cap=${encodeURIComponent(capId)}`);
  };

  // v2: between Review and Confirm, run a preflight check for overwrite
  // conflicts on reorder + AI-features files. v1 skips this (the CF Worker
  // handled concurrency server-side).
  const handleReviewNext = async () => {
    if (!GITHUB_NATIVE || !ghAuth || !ghUser) {
      setStep("confirm");
      return;
    }
    setStep("preflight");
    setError(null);
    try {
      const found = await preflightPublishConflicts(ghAuth, ghUser.login);
      setConflicts(found);
      if (found.length > 0) {
        setStep("conflicts");
      } else {
        setStep("confirm");
      }
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
      setStep("error");
    }
  };

  const handleConfirm = async () => {
    setStep("running");
    setError(null);
    try {
      const r = await publish();
      if (r.ok) {
        setResult({ applied: r.applied, commit_url: r.commit_url });
        setStep("done");
      } else {
        setError(r.message || "Publish returned no-op.");
        setStep("error");
      }
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
      setStep("error");
    }
  };

  const fieldList = (fields: Record<string, unknown>): ReactNode[] =>
    Object.keys(fields).map(k => <code key={k}>{k}</code>).reduce((acc, el, i) => {
      return acc.concat(i > 0 ? [" ", el] : [el]);
    }, [] as ReactNode[]);

  return (
    <>
      <button
        className="publish-fab"
        onClick={() => setOpen(true)}
        title="Publish all drafts to data/manual_cap_overrides.yaml"
      >
        Publish <span className="publish-fab-count">{total}</span> draft{total === 1 ? "" : "s"} → repo
      </button>

      {open && (
        <div className="publish-modal-spa" role="dialog" aria-modal="true">
          <div className="publish-modal-inner">
            <div className="publish-modal-head">
              <h3>
                {step === "review" && `Publish ${total} draft${total === 1 ? "" : "s"} to repo`}
                {step === "preflight" && "Checking for conflicts…"}
                {step === "conflicts" && `Conflict warning — ${conflicts.length} file${conflicts.length === 1 ? "" : "s"} recently changed by others`}
                {step === "confirm" && "Confirm publish"}
                {step === "running" && "Publishing…"}
                {step === "done" && "Published ✓"}
                {step === "error" && "Publish failed"}
              </h3>
              <button className="publish-modal-close" onClick={close}>×</button>
            </div>

            <div className="publish-modal-body">
              {step === "review" && (
                <>
                  <p className="publish-help">
                    Review every change below — click any row to re-open its
                    editor without losing the queue. Clicking <b>Publish</b>{" "}
                    commits everything to <code>main</code> and triggers the
                    rebuild workflow.
                  </p>
                  {summaryLoading && !summary && (
                    <p className="publish-running">Loading pending changes…</p>
                  )}
                  {summary && (
                    <ReviewSections summary={summary} fieldList={fieldList}
                      onOpenCap={openCap} />
                  )}
                  <div className="publish-actions">
                    <button className="publish-btn-primary"
                      onClick={handleReviewNext}
                      disabled={summaryLoading && !summary}>
                      Publish to repo →
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>Cancel</button>
                  </div>
                </>
              )}

              {step === "preflight" && (
                <p className="publish-running">
                  Checking whether anyone else has touched the files you're about to overwrite…
                </p>
              )}

              {step === "conflicts" && (
                <>
                  <p className="publish-help">
                    The files below were modified on <code>main</code> after the most
                    recent change you'd be overwriting. <b>Your publish will replace
                    their work for these files.</b> Review carefully before continuing.
                  </p>
                  <ul className="publish-conflict-list">
                    {conflicts.map(c => (
                      <li key={c.file} className="publish-conflict-item">
                        <code className="publish-conflict-file">{c.file}</code>
                        <span className="publish-conflict-meta">
                          last edited by <b>@{c.last_commit_author_login}</b>
                          {" "}at {new Date(c.last_commit_at).toLocaleString()}
                          {" "}·{" "}
                          <a href={c.last_commit_url} target="_blank" rel="noopener noreferrer">
                            view commit ↗
                          </a>
                        </span>
                      </li>
                    ))}
                  </ul>
                  <p className="publish-confirm-warn">
                    Cap-field edits compose safely — they're not affected by this warning.
                    Only the listed <i>overwrite</i> files would clobber other users' work.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-confirm" onClick={() => setStep("confirm")}>
                      I understand — continue
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>
                      Cancel
                    </button>
                  </div>
                </>
              )}

              {step === "confirm" && (
                <>
                  <p>You're about to commit <b>{total}</b> draft{total === 1 ? "" : "s"} to:</p>
                  <ul className="publish-confirm-target">
                    <li>Repo: <code>jersgcodes/erp-mapper</code></li>
                    <li>File: <code>data/manual_cap_overrides.yaml</code></li>
                    <li>Branch: <code>main</code></li>
                  </ul>
                  <p className="publish-confirm-warn">
                    This commits to <b>main</b> and dispatches the
                    {" "}<code>apply-published-overrides</code> workflow. The rebuild
                    auto-deploys to <code>mapper.jersgcodes.com</code> in ~1-2 min.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-confirm" onClick={handleConfirm}>
                      Yes, publish to repo
                    </button>
                    <button className="publish-btn-cancel" onClick={() => setStep("review")}>
                      ← Back
                    </button>
                  </div>
                </>
              )}

              {step === "running" && (
                <p className="publish-running">Committing YAML + dispatching workflow…</p>
              )}

              {step === "done" && result && (
                <>
                  <p className="publish-done">
                    Published <b>{result.applied}</b> draft{result.applied === 1 ? "" : "s"}.
                    {result.commit_url && (
                      <>
                        {" "}
                        <a href={result.commit_url} target="_blank" rel="noopener noreferrer">
                          View commit ↗
                        </a>
                      </>
                    )}
                  </p>
                  <p className="muted small">
                    The CI workflow is rebuilding viewers. Refresh in ~30 s to see the
                    changes baked into the canonical baseline.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-primary" onClick={close}>Close</button>
                  </div>
                </>
              )}

              {step === "error" && (
                <>
                  <p className="publish-error">Publish failed: {error}</p>
                  <div className="publish-actions">
                    <button className="publish-btn-primary" onClick={() => setStep("review")}>
                      ← Back
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>Cancel</button>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
}

function shortAuthor(email: string | undefined): string {
  if (!email) return "?";
  const at = email.indexOf("@");
  return at > 0 ? email.slice(0, at) : email;
}

interface ReviewSectionsProps {
  summary: PendingChangesSummary;
  fieldList: (f: Record<string, unknown>) => ReactNode[];
  onOpenCap: (module: string, capId: string) => void;
}

/** Sectioned breakdown of every pending change. Each row is clickable
 *  where re-opening makes sense: cap edits, cluster moves, and additions
 *  all deep-link to the cap on its module page. Reorders + AI features
 *  deep-link to the module page itself (no per-cap target). */
function ReviewSections({ summary, fieldList, onOpenCap }: ReviewSectionsProps) {
  const reorderModules = Object.keys(summary.reordersByModule).sort();
  const aiModules = Object.keys(summary.aiFeaturesByModule).sort();
  const total = summary.capEdits.length + summary.clusterMoves.length
    + summary.additions.length + reorderModules.length + aiModules.length;
  if (total === 0) {
    return <p className="muted">No pending changes to publish.</p>;
  }
  return (
    <div className="publish-sections">
      {summary.capEdits.length > 0 && (
        <section className="publish-section">
          <h4>Cap edits <span className="publish-section-count">{summary.capEdits.length}</span></h4>
          <table className="publish-table">
            <thead>
              <tr><th>Cap</th><th>Fields</th><th>Author</th></tr>
            </thead>
            <tbody>
              {summary.capEdits.map(d => (
                <tr key={`edit:${d.module}:${d.cap_id}`}
                  className="publish-row-clickable"
                  onClick={() => onOpenCap(d.module, d.cap_id)}
                  title="Click to open this cap in its module's editor">
                  <td><code>{d.cap_id}</code></td>
                  <td className="pub-fields">{fieldList(d.fields)}</td>
                  <td className="pub-author">{shortAuthor(d.author_email)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      )}

      {summary.clusterMoves.length > 0 && (
        <section className="publish-section">
          <h4>Umbrella moves <span className="publish-section-count">{summary.clusterMoves.length}</span></h4>
          <table className="publish-table">
            <thead>
              <tr><th>Cap</th><th>New umbrella</th><th>Source</th></tr>
            </thead>
            <tbody>
              {summary.clusterMoves.map(m => (
                <tr key={`cluster:${m.module}:${m.cap_id}`}
                  className="publish-row-clickable"
                  onClick={() => onOpenCap(m.module, m.cap_id)}
                  title="Click to open this cap in its module's editor">
                  <td><code>{m.cap_id}</code></td>
                  <td><code>{m.cluster_id}</code></td>
                  <td className="muted small">
                    {m.source === "addition" ? "from new cap" : "from draft"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      )}

      {summary.additions.length > 0 && (
        <section className="publish-section">
          <h4>New caps <span className="publish-section-count">{summary.additions.length}</span></h4>
          <table className="publish-table">
            <thead>
              <tr><th>Cap</th><th>Name</th><th>Tier</th><th>Author</th></tr>
            </thead>
            <tbody>
              {summary.additions.map(a => (
                <tr key={`add:${a.module}:${a.cap_id}`}
                  className="publish-row-clickable"
                  onClick={() => onOpenCap(a.module, a.cap_id)}
                  title="Click to open this cap in its module's editor">
                  <td><code>{a.cap_id}</code></td>
                  <td>{a.name}</td>
                  <td className="muted small">{a.sme_tier}</td>
                  <td className="pub-author">{shortAuthor(a.author)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      )}

      {reorderModules.length > 0 && (
        <section className="publish-section">
          <h4>Cap reorders <span className="publish-section-count">{reorderModules.length} module{reorderModules.length === 1 ? "" : "s"}</span></h4>
          <ul className="publish-modules-list">
            {reorderModules.map(mod => {
              const umbrellas = Object.keys(summary.reordersByModule[mod] || {});
              return (
                <li key={`reorder:${mod}`}
                  className="publish-row-clickable"
                  onClick={() => { /* deep-link to module page */
                    onOpenCap(mod, ""); // capId empty → scrolls to top of module
                  }}>
                  <code>{mod}</code>
                  <span className="muted small"> · {umbrellas.length} umbrella{umbrellas.length === 1 ? "" : "s"} reordered</span>
                </li>
              );
            })}
          </ul>
        </section>
      )}

      {aiModules.length > 0 && (
        <section className="publish-section">
          <h4>AI Features responses <span className="publish-section-count">{aiModules.length} module{aiModules.length === 1 ? "" : "s"}</span></h4>
          <ul className="publish-modules-list">
            {aiModules.map(mod => (
              <li key={`ai:${mod}`}
                className="publish-row-clickable"
                onClick={() => onOpenCap(mod, "")}>
                <code>{mod}</code>
              </li>
            ))}
          </ul>
        </section>
      )}
    </div>
  );
}
