import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { TabHelp } from "../components/TabHelp";
import {
  loadPricingPayload,
  type PricingPayload,
  type PricingVendor,
  type PricingPackage,
  moduleLabel,
} from "../lib/pricingData";
import { fuzzyFilter } from "../lib/fuzzy";
import { useTableSort } from "../lib/useTableSort";
import {
  aggregateVendor,
  flattenForComparison,
  tierBadge,
  type VendorRowAggregate,
  type PackageComparisonRow,
} from "../lib/pricingComparison";
import { SortHeader } from "../components/SortHeader";
import { FeaturePlanMatrix } from "../components/FeaturePlanMatrix";
import { MissingPricingPanel } from "../components/MissingPricingPanel";
import "./PricingLibraryPage.css";

/**
 * Pricing Library — sol cat (PSG category) → vendor packages browse.
 *
 * Sister view to Coverage > Module > Pricing (which compares 4 commodity
 * modules using the 23 curated benchmark vendors). This page covers the
 * full 414-vendor PSG catalogue at package level — every solution that
 * appears in the PSG IT Solutions directory.
 *
 * Filters: module, category, exclude-non-ERP. Each row shows lowest +
 * highest package price (SGD verbatim from GoBusiness export) and the
 * PSG support %. Click a row to expand into the full package table.
 *
 * Detail layer (Haiku-parsed tier breakdowns) is shown for vendors that
 * have been through the PDF parser pipeline — ~15 so far, will grow as
 * Phase 1-4 ingest expands.
 */
export function PricingLibraryPage() {
  const [payload, setPayload] = useState<PricingPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useSearchParams();

  const moduleFilter = search.get("mod") || "";
  const categoryFilter = search.get("cat") || "";
  const includeExcluded = search.get("inc") === "1";
  const query = search.get("q") || "";
  const expanded = search.get("ex") || "";

  // Local search-input state so typing stays responsive even when the
  // filter chain (fuzzyFilter across 430+ vendors) is slow. The committed
  // `query` state above is debounced — only fires the filter after the
  // user stops typing for 250ms. Initial value mirrors the URL param so
  // direct deep-link share-links still work.
  const [searchInput, setSearchInput] = useState<string>(query);
  // Keep input in sync if URL changes externally (e.g. nav back/forward).
  useEffect(() => { setSearchInput(query); }, [query]);
  useEffect(() => {
    if (searchInput === query) return;
    const t = setTimeout(() => {
      // Build a fresh params snapshot inside the timeout so we don't
      // race against other filter changes (mod/cat/inc) that already
      // moved through `update`/`updateMany`.
      const next = new URLSearchParams(search);
      if (searchInput) next.set("q", searchInput);
      else next.delete("q");
      setSearch(next, { replace: true });
    }, 250);
    return () => clearTimeout(t);
    // search & setSearch are intentionally omitted — we only want this
    // to fire on input changes, not on every URL state shift.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [searchInput]);
  // Compare view is gated on having a module OR category filter — the
  // 414-row flat table is unusable without narrowing first.
  const compareMode = search.get("compare") === "1";
  const isFiltered = !!(moduleFilter || categoryFilter);

  useEffect(() => {
    loadPricingPayload().then(setPayload).catch(e => setError(String(e?.message || e)));
  }, []);

  const sortedModules = useMemo(() => {
    if (!payload) return [];
    return Object.entries(payload.by_module)
      .sort((a, b) => b[1].vendor_count - a[1].vendor_count)
      .map(([slug, info]) => ({ slug, ...info }));
  }, [payload]);

  const sortedCategories = useMemo(() => {
    if (!payload) return [];
    return Object.entries(payload.by_category)
      .filter(([_, info]) => includeExcluded || !info.excluded)
      .filter(([_, info]) => {
        if (!moduleFilter) return true;
        return info.modules.includes(moduleFilter);
      })
      .map(([name, info]) => ({ name, ...info }))
      .sort((a, b) => b.vendor_ids.length - a.vendor_ids.length);
  }, [payload, moduleFilter, includeExcluded]);

  const activeCategory = useMemo(() => {
    if (!payload || !categoryFilter) return null;
    return payload.by_category[categoryFilter] || null;
  }, [payload, categoryFilter]);

  const visibleVendors = useMemo<PricingVendor[]>(() => {
    if (!payload) return [];
    let list: PricingVendor[];
    if (activeCategory) {
      list = activeCategory.vendor_ids.map(id => payload.vendors[id]).filter(Boolean);
    } else if (moduleFilter) {
      const idx = payload.by_module[moduleFilter];
      list = idx ? idx.vendor_ids.map(id => payload.vendors[id]).filter(Boolean) : [];
    } else {
      list = Object.values(payload.vendors);
    }
    if (!includeExcluded) {
      list = list.filter(v => !v.excluded_from_erp);
    }
    return fuzzyFilter(list, query, ["vendor_name", "solution_name", "category"]);
  }, [payload, activeCategory, moduleFilter, includeExcluded, query]);

  function update(key: string, value: string | null) {
    updateMany({ [key]: value });
  }

  /** Single setSearch call across an arbitrary number of patches. Each
   *  individual `update` would otherwise read the same stale `search`
   *  state and overwrite each other when called consecutively in one
   *  handler — that was the bug that made the Module dropdown snap back
   *  to "All" after every selection. */
  function updateMany(patches: Record<string, string | null>) {
    const next = new URLSearchParams(search);
    for (const [key, value] of Object.entries(patches)) {
      if (value == null || value === "") {
        next.delete(key);
      } else {
        next.set(key, value);
      }
    }
    setSearch(next, { replace: false });
  }

  if (error) {
    return (
      <section className="pricing-lib-page">
        <h1>Pricing Library</h1>
        <p>Failed to load pricing payload: {error}</p>
      </section>
    );
  }

  if (!payload) {
    return (
      <section className="pricing-lib-page">
        <h1>Pricing Library</h1>
        <p className="muted">Loading PSG vendor pricing…</p>
      </section>
    );
  }

  return (
    <section className="pricing-lib-page">
      <header className="pricing-lib-header">
        <h1>Pricing Library</h1>
        <p className="muted">
          Verbatim package pricing from the GoBusiness PSG IT Solutions
          directory ({payload._meta.summary_count} vendors).
          Detail breakdown available for {payload._meta.detailed_count} vendors
          so far (more added as PSG submission PDFs are parsed).
          Generated {new Date(payload._meta.generated_at).toLocaleDateString()}.
        </p>
      </header>

      {/* Sub-tab switcher: 'catalog' (existing PSG browse) vs 'missing'
       *  (new — vendors with feature evidence but no pricing entry).
       *  URL param 'tab' so deep-links survive nav. */}
      <div className="pricing-lib-subtabs">
        <button
          type="button"
          className={`pricing-lib-subtab${(search.get("tab") || "catalog") === "catalog" ? " active" : ""}`}
          onClick={() => updateMany({ tab: null })}
        >
          PSG Catalogue
        </button>
        <button
          type="button"
          className={`pricing-lib-subtab${search.get("tab") === "missing" ? " active" : ""}`}
          onClick={() => updateMany({ tab: "missing" })}
        >
          Missing Pricing
        </button>
      </div>

      {search.get("tab") === "missing" ? <MissingPricingPanel /> : (<>

      <TabHelp hint="Filter by module, category, or vendor. Click a vendor row to expand the per-package breakdown (year-1 SGD, software, professional services, training).">
        SG-list pricing catalogue for SME ERP buyers. Read this view to compare
        what each PSG-listed vendor charges, what's bundled, and which modules
        they cover. The price source-of-truth is the GoBusiness PDF; web pages
        only fill in feature lists.
      </TabHelp>

      <div className="pricing-lib-filters">
        <label>
          <span>Module:</span>
          <select value={moduleFilter} onChange={e => updateMany({ mod: e.target.value, cat: "" })}>
            <option value="">All modules</option>
            {sortedModules.map(m => (
              <option key={m.slug} value={m.slug}>
                {moduleLabel(m.slug)} ({m.vendor_count})
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>Sol cat / category:</span>
          <select value={categoryFilter} onChange={e => update("cat", e.target.value)}>
            <option value="">All categories</option>
            {sortedCategories.map(c => (
              <option key={c.name} value={c.name}>
                {c.name} ({c.vendor_ids.length})
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>Search:</span>
          <input
            type="search"
            value={searchInput}
            placeholder="vendor or solution name…"
            onChange={e => setSearchInput(e.target.value)}
          />
        </label>
        <label className="pricing-lib-inline-check">
          <input
            type="checkbox"
            checked={includeExcluded}
            onChange={e => update("inc", e.target.checked ? "1" : null)}
          />
          <span>Include non-ERP categories</span>
        </label>
      </div>

      <div className="pricing-lib-summary">
        <span>
          Showing <strong>{visibleVendors.length}</strong> vendor
          {visibleVendors.length === 1 ? "" : "s"}
          {moduleFilter && <> in <strong>{moduleLabel(moduleFilter)}</strong></>}
          {categoryFilter && <> · <strong>{categoryFilter}</strong></>}
          .
        </span>
        {isFiltered && (
          <div className="pricing-lib-mode">
            <button type="button"
              className={`pricing-lib-mode-btn${compareMode ? "" : " active"}`}
              onClick={() => update("compare", null)}>
              Vendor list
            </button>
            <button type="button"
              className={`pricing-lib-mode-btn${compareMode ? " active" : ""}`}
              onClick={() => update("compare", "1")}>
              Compare packages
            </button>
          </div>
        )}
      </div>

      {compareMode && isFiltered ? (
        <CrossVendorPackageTable vendors={visibleVendors} />
      ) : (
        <VendorListTable
          vendors={visibleVendors}
          expanded={expanded}
          onToggle={(id, on) => update("ex", on ? id : "")}
        />
      )}

      </>)}
    </section>
  );
}

interface RowProps {
  v: PricingVendor;
  isExpanded: boolean;
  onToggle: () => void;
  lo: number | null;
  hi: number | null;
}

function Row({ v, isExpanded, onToggle, lo, hi }: RowProps) {
  const hasDetail = !!v.detail;
  const isBenchmark = !!v.benchmark_id;
  return (
    <>
      <tr className={`pricing-lib-row${isBenchmark ? " benchmark" : ""}${v.excluded_from_erp ? " excluded" : ""}`}>
        <td>
          <strong>{v.vendor_name || "—"}</strong>
          <br />
          <span className="solution-name">{v.solution_name || "—"}</span>
          {isBenchmark && <span className="badge benchmark-badge">Benchmark ERP</span>}
          {v.excluded_from_erp && <span className="badge excluded-badge">Non-ERP</span>}
        </td>
        <td>
          {v.category || "—"}
          {v.modules.length > 0 && (
            <div className="module-chips">
              {v.modules.map(m => <span key={m} className="chip">{moduleLabel(m)}</span>)}
            </div>
          )}
        </td>
        <td className="num">{v.packages.length}</td>
        <td className="num">{lo != null ? formatSgd(lo) : "—"}</td>
        <td className="num">{hi != null ? formatSgd(hi) : "—"}</td>
        <td className="num">{v.psg_support_pct_raw || "—"}</td>
        <td>
          <button type="button" className="link-btn" onClick={onToggle}>
            {isExpanded ? "Hide" : hasDetail ? "Show + breakdown" : "Show packages"}
          </button>
          {v.psg_url && (
            <> · <a href={v.psg_url} target="_blank" rel="noopener noreferrer">PSG listing ↗</a></>
          )}
          {v.vendor_url && (
            <> · <a href={v.vendor_url} target="_blank" rel="noopener noreferrer">Vendor site ↗</a></>
          )}
        </td>
      </tr>
      {isExpanded && (
        <tr className="pricing-lib-detail-row">
          <td colSpan={7}>
            <VendorDetailExpansion v={v} />
          </td>
        </tr>
      )}
    </>
  );
}

function VendorDetailExpansion({ v }: { v: PricingVendor }) {
  return (
    <div className="pricing-lib-detail">
      {v.description && (
        <p className="vendor-desc">{v.description}</p>
      )}
      {v.packages.length > 0 && (
        <>
          <h4>Packages (verbatim from PSG listing)</h4>
          <table className="pkg-table">
            <thead>
              <tr>
                <th>Package</th>
                <th>Total cost</th>
                <th>Qualifying cost</th>
                <th>Net cost after PSG</th>
              </tr>
            </thead>
            <tbody>
              {v.packages.map((p, i) => <PackageRow key={i} p={p} />)}
            </tbody>
          </table>
          {v.payment_mode && (
            <p className="muted">Payment mode: <strong>{v.payment_mode}</strong></p>
          )}
        </>
      )}
      {v.detail && v.detail.plans.length > 0 && (
        <>
          <h4>Tier × feature comparison (Haiku-parsed)</h4>
          <p className="muted">
            Source: {v.detail.fetched_from || "vendor source"} ·
            Extracted: {v.detail.extracted_at ? new Date(v.detail.extracted_at).toLocaleDateString() : "—"} ·
            Model: {v.detail.model}
          </p>
          <FeaturePlanMatrix plans={v.detail.plans} />
        </>
      )}
      {!v.detail && v.packages.length === 0 && (
        <p className="muted">
          No package pricing or detail breakdown available for this vendor yet.
          {v.benchmark_id && " Benchmark ERPs without a PSG listing may require a vendor-site enrichment pass."}
        </p>
      )}
    </div>
  );
}

function PackageRow({ p }: { p: PricingPackage }) {
  return (
    <tr>
      <td><strong>{p.name}</strong></td>
      <td className="num">{p.total_cost_raw || "—"}</td>
      <td className="num">{p.qualifying_cost_raw || "—"}</td>
      <td className="num">{p.net_cost_raw || "—"}</td>
    </tr>
  );
}

function formatSgd(n: number): string {
  return `S$${n.toLocaleString("en-SG", { maximumFractionDigits: 0 })}`;
}

interface VendorListTableProps {
  vendors: PricingVendor[];
  expanded: string;
  onToggle: (id: string, on: boolean) => void;
}

/** Sortable per-vendor table. One row per vendor, expand for package +
 *  feature-matrix detail. Null values sort as "lowest" (nulls last in
 *  asc, nulls first in desc) so unpriced vendors don't crowd the top. */
function VendorListTable({ vendors, expanded, onToggle }: VendorListTableProps) {
  const rows = useMemo(() => vendors.map(aggregateVendor), [vendors]);
  const cmpNum = (a: number | null, b: number | null) => {
    if (a == null && b == null) return 0;
    if (a == null) return 1;   // nulls last (asc)
    if (b == null) return -1;
    return a - b;
  };
  const comparators = useMemo(() => ({
    vendor: (a: VendorRowAggregate, b: VendorRowAggregate) =>
      (a.v.vendor_name || "").localeCompare(b.v.vendor_name || "")
      || (a.v.solution_name || "").localeCompare(b.v.solution_name || ""),
    category: (a: VendorRowAggregate, b: VendorRowAggregate) =>
      (a.v.category || "").localeCompare(b.v.category || ""),
    packages: (a: VendorRowAggregate, b: VendorRowAggregate) =>
      a.packageCount - b.packageCount,
    lowest: (a: VendorRowAggregate, b: VendorRowAggregate) => cmpNum(a.lowest, b.lowest),
    highest: (a: VendorRowAggregate, b: VendorRowAggregate) => cmpNum(a.highest, b.highest),
  }), []);
  const { sorted, sortBy, sortDir, setSort } = useTableSort<
    VendorRowAggregate, "vendor" | "category" | "packages" | "lowest" | "highest"
  >(rows, { defaultKey: "vendor", defaultDir: "asc", comparators });

  return (
    <table className="pricing-lib-table">
      <thead>
        <tr>
          <th><SortHeader label="Vendor / Solution" colKey="vendor"
            sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Category" colKey="category"
            sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Packages" colKey="packages" numeric
            sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Lowest total" colKey="lowest" numeric
            sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Highest total" colKey="highest" numeric
            sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th>PSG support</th>
          <th>Detail</th>
        </tr>
      </thead>
      <tbody>
        {sorted.map(r => (
          <Row
            key={r.id}
            v={r.v}
            isExpanded={expanded === r.id}
            onToggle={() => onToggle(r.id, expanded !== r.id)}
            lo={r.lowest}
            hi={r.highest}
          />
        ))}
        {sorted.length === 0 && (
          <tr><td colSpan={7} className="muted">No vendors match the current filters.</td></tr>
        )}
      </tbody>
    </table>
  );
}

function CrossVendorPackageTable({ vendors }: { vendors: PricingVendor[] }) {
  const rows = useMemo(() => flattenForComparison(vendors), [vendors]);
  const cmpNum = (a: number | null, b: number | null) => {
    if (a == null && b == null) return 0;
    if (a == null) return 1;
    if (b == null) return -1;
    return a - b;
  };
  const comparators = useMemo(() => ({
    vendor: (a: PackageComparisonRow, b: PackageComparisonRow) =>
      a.vendor_name.localeCompare(b.vendor_name)
      || a.solution_name.localeCompare(b.solution_name),
    category: (a: PackageComparisonRow, b: PackageComparisonRow) =>
      a.category.localeCompare(b.category),
    package_name: (a: PackageComparisonRow, b: PackageComparisonRow) =>
      a.package_name.localeCompare(b.package_name),
    tier_rank: (a: PackageComparisonRow, b: PackageComparisonRow) =>
      a.tier_rank - b.tier_rank,
    total: (a: PackageComparisonRow, b: PackageComparisonRow) => cmpNum(a.total, b.total),
    qualifying: (a: PackageComparisonRow, b: PackageComparisonRow) => cmpNum(a.qualifying, b.qualifying),
    net: (a: PackageComparisonRow, b: PackageComparisonRow) => cmpNum(a.net, b.net),
  }), []);
  const { sorted, sortBy, sortDir, setSort } = useTableSort<
    PackageComparisonRow,
    "vendor" | "category" | "package_name" | "tier_rank" | "total" | "qualifying" | "net"
  >(rows, { defaultKey: "total", defaultDir: "asc", comparators });

  if (rows.length === 0) {
    return <p className="muted">No package pricing in the filtered set.</p>;
  }

  return (
    <div className="pricing-lib-compare-wrap">
      <p className="muted small">
        {rows.length} package{rows.length === 1 ? "" : "s"} across {vendors.length} vendor
        {vendors.length === 1 ? "" : "s"} · sorted by total cost (asc by default; click any
        header to re-sort).
      </p>
      <table className="pricing-lib-table pricing-lib-compare-table">
        <thead>
          <tr>
            <th><SortHeader label="Vendor / Solution" colKey="vendor"
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Category" colKey="category"
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Package" colKey="package_name"
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Tier" colKey="tier_rank" numeric
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Total" colKey="total" numeric
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Qualifying" colKey="qualifying" numeric
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th><SortHeader label="Net after PSG" colKey="net" numeric
              sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
            <th>Support</th>
          </tr>
        </thead>
        <tbody>
          {sorted.map(r => (
            <tr key={r.rowId}>
              <td>
                <strong>{r.vendor_name}</strong>
                <br />
                <span className="solution-name">{r.solution_name}</span>
              </td>
              <td>{r.category}</td>
              <td>{r.package_name}</td>
              <td className="num">{r.tier_rank > 0 ? tierBadge(r.tier_rank) : <span className="muted">—</span>}</td>
              <td className="num">{r.total != null ? formatSgd(r.total) : <span className="muted">—</span>}</td>
              <td className="num">{r.qualifying != null ? formatSgd(r.qualifying) : <span className="muted">—</span>}</td>
              <td className="num">{r.net != null ? formatSgd(r.net) : <span className="muted">—</span>}</td>
              <td className="muted small">{r.support_pct}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

