import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type PerModuleView,
  type ReEvalFlag,
} from "../../lib/stakeholdersData";
import { readSession, writeSession } from "../../lib/urlState";
import { TabHelp } from "../TabHelp";
import "./ModuleDeepDiveAccordion.css";

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

export function ModuleDeepDiveAccordion({ modules }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  // sessionStorage-backed; default = all collapsed on first visit.
  const [collapsed, setCollapsed] = useState<Record<string, boolean>>(() => {
    const stored = readSession<Record<string, boolean> | null>("dash.deepdive.collapsed", null);
    if (stored) return stored;
    const init: Record<string, boolean> = {};
    for (const m of modules) init[m.slug] = true;
    return init;
  });
  useEffect(() => {
    writeSession("dash.deepdive.collapsed", collapsed);
  }, [collapsed]);

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  if (error) {
    return (
      <div className="dash-panel mdda-error">
        Failed to load stakeholders payload: {error}
      </div>
    );
  }
  if (!data) {
    return <div className="dash-panel mdda-loading">Loading deep-dive data…</div>;
  }

  const allCollapsed = modules.every(m => collapsed[m.slug]);
  const collapseAll = () => {
    const next: Record<string, boolean> = {};
    for (const m of modules) next[m.slug] = true;
    setCollapsed(next);
  };
  const expandAll = () => {
    const next: Record<string, boolean> = {};
    for (const m of modules) next[m.slug] = false;
    setCollapsed(next);
  };
  const toggle = (slug: string) =>
    setCollapsed(prev => ({ ...prev, [slug]: !prev[slug] }));

  return (
    <div className="dash-panel">
      <TabHelp hint="Each module shows the top sol cats × reference ERPs that produced its caps, plus warnings the audit flagged for re-review.">
        Build-chain narrative — where each module's caps came from. Click a
        module header to expand its top sol cats, top reference ERPs, and any
        re-evaluation flags raised by the audit pipeline.
      </TabHelp>
      <div className="dash-chip-bar">
        <span className="dash-chip">
          <strong>{modules.length}</strong> modules · build chain · re-evaluation flags
        </span>
        <button
          type="button"
          className="dash-toggle-all"
          onClick={allCollapsed ? expandAll : collapseAll}
          title={allCollapsed ? "Expand every module" : "Collapse every module"}
        >
          {allCollapsed ? "Expand all ▾" : "Collapse all ▸"}
        </button>
        <span className="dash-chip dash-chip-hint">
          PSG sol cats × reference ERPs that produced each module
        </span>
      </div>

      <ModuleNavChips
        modules={modules}
        anchorPrefix="mdda"
        onClickModule={slug => {
          // Auto-expand on jump.
          setCollapsed(prev => ({ ...prev, [slug]: false }));
        }}
      />

      {modules.map(m => {
        const pmv = data.per_module_views?.[m.slug];
        return (
          <article
            key={m.slug}
            id={`mdda-${m.slug}`}
            className={`mdda-card${collapsed[m.slug] ? " collapsed" : ""}`}
          >
            <div
              className="mdda-head"
              onClick={(e) => {
                if ((e.target as HTMLElement).closest("a")) return;
                toggle(m.slug);
              }}
            >
              <span className="mod-id">{m.module_id}</span>
              <Link to={`/canonical/${m.slug}`} className="mod-name">
                {m.module_name}
              </Link>
              {pmv && (
                <span className="mdda-mix">
                  {pmv.build_chain.total_caps} caps · {pmv.build_chain.top_solcats.length} sol cats · {pmv.build_chain.top_proxies.length} ref ERPs
                </span>
              )}
              <FlagsBadge flags={pmv?.reeval_flags || []} />
              <span className="mod-chev">▾</span>
            </div>
            {!collapsed[m.slug] && pmv && (
              <ModuleBody
                slug={m.slug}
                pmv={pmv}
                proxyIdToName={data.proxy_id_to_name || {}}
              />
            )}
            {!collapsed[m.slug] && !pmv && (
              <div className="mdda-empty">No deep-dive data for this module yet.</div>
            )}
          </article>
        );
      })}
    </div>
  );
}

function FlagsBadge({ flags }: { flags: ReEvalFlag[] }) {
  if (!flags || flags.length === 0) return null;
  const high = flags.filter(f => f.severity === "high").length;
  const med = flags.filter(f => f.severity === "med").length;
  const low = flags.filter(f => f.severity === "low" || f.severity === "info" || !f.severity).length;
  const total = high + med + low;
  if (total === 0) return null;
  let tone = "low";
  if (high > 0) tone = "high";
  else if (med > 0) tone = "med";
  return (
    <span
      className={`mdda-flags-badge mdda-flags-${tone}`}
      title={`${total} re-eval flag${total === 1 ? "" : "s"} — ${high} high · ${med} med · ${low} info`}
    >
      {total} flag{total === 1 ? "" : "s"}
    </span>
  );
}

function ModuleBody({
  slug,
  pmv,
  proxyIdToName,
}: {
  slug: string;
  pmv: PerModuleView;
  proxyIdToName: Record<string, string>;
}) {
  const flags = pmv.reeval_flags || pmv.tiers.required?.flags || [];
  const groupedFlags = useMemo(() => {
    const order: Array<"high" | "med" | "low" | "info"> = ["high", "med", "low", "info"];
    const buckets: Record<string, ReEvalFlag[]> = { high: [], med: [], low: [], info: [] };
    for (const f of flags) {
      const sev = (f.severity as keyof typeof buckets) || "info";
      (buckets[sev] || buckets.info).push(f);
    }
    return order
      .filter(k => buckets[k].length > 0)
      .map(k => ({ severity: k, items: buckets[k] }));
  }, [flags]);

  return (
    <div className="mdda-body">
      {/* ── Build chain ─────────────────────────────────────────────── */}
      <div className="mdda-section">
        <h4 className="mdda-h4">Build chain</h4>
        {pmv.build_chain.narrative && (
          <p className="mdda-narrative">{pmv.build_chain.narrative}</p>
        )}
        <div className="mdda-build-grid">
          <div>
            <div className="mdda-mini-h">PSG sol cats contributing</div>
            <div className="mdda-list">
              {pmv.build_chain.top_solcats.length === 0 && (
                <div className="mdda-list-empty">No PSG sol cats — proxy-grounded module.</div>
              )}
              {pmv.build_chain.top_solcats.slice(0, 8).map(sc => (
                <div key={sc.id} className="mdda-list-row">
                  <span className="mdda-list-name">
                    {sc.display_name}
                    {sc.vertical_saas && <span className="mdda-vsaas">vertical</span>}
                  </span>
                  <span className="mdda-list-num">{sc.cap_count} caps</span>
                </div>
              ))}
            </div>
          </div>
          <div>
            <div className="mdda-mini-h">Reference ERPs cited</div>
            <div className="mdda-list">
              {pmv.build_chain.top_proxies.length === 0 && (
                <div className="mdda-list-empty">No ref-ERP citations.</div>
              )}
              {pmv.build_chain.top_proxies.slice(0, 8).map(p => (
                <div key={p.id} className="mdda-list-row" title={p.id}>
                  <span className="mdda-list-name">{proxyIdToName[p.id] || p.id}</span>
                  <span className="mdda-list-num">{p.cap_count} caps</span>
                </div>
              ))}
            </div>
          </div>
        </div>
        <div className="mdda-step-actions">
          <Link to={`/canonical/${slug}`} className="mdda-step-link">
            Open {slug} canonical →
          </Link>
        </div>
      </div>

      {/* ── Re-evaluation flags ─────────────────────────────────────── */}
      {flags.length === 0 ? (
        <div className="mdda-section mdda-no-flags">
          <h4 className="mdda-h4">Re-evaluation flags</h4>
          <div className="mdda-empty-row">No re-eval flags for this module.</div>
        </div>
      ) : (
        <div className="mdda-section">
          <h4 className="mdda-h4">Re-evaluation flags · {flags.length}</h4>
          {groupedFlags.map(g => (
            <details
              key={g.severity}
              className={`mdda-flag-group mdda-flag-group-${g.severity}`}
              open={g.severity === "high" || g.severity === "med"}
            >
              <summary>
                <span className={`mdda-flag-sev mdda-flag-sev-${g.severity}`}>
                  {g.severity}
                </span>
                <span className="mdda-flag-count">{g.items.length}</span>
              </summary>
              <ul className="mdda-flag-list">
                {g.items.map((f, i) => (
                  <li key={i} className="mdda-flag-item">
                    <span className="mdda-flag-kind">{f.kind}</span>
                    <span className="mdda-flag-msg">{f.msg}</span>
                  </li>
                ))}
              </ul>
            </details>
          ))}
        </div>
      )}
    </div>
  );
}

// ──────────────────────────────────────────────────────────────────────
// Module nav chip strip — used here + by the Checklists panel sibling.
// Kept colocated to stay self-contained; if a third caller appears, lift
// to its own file under components/dash/.
// ──────────────────────────────────────────────────────────────────────

export function ModuleNavChips({
  modules,
  anchorPrefix,
  onClickModule,
}: {
  modules: ModuleEntry[];
  anchorPrefix: string;
  onClickModule?: (slug: string) => void;
}) {
  const handleClick = (slug: string) => {
    if (onClickModule) onClickModule(slug);
    // Defer scroll so any expand-on-click state has a chance to render.
    setTimeout(() => {
      const el = document.getElementById(`${anchorPrefix}-${slug}`);
      if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
    }, 0);
  };
  return (
    <div className="mdda-nav-chips">
      <span className="mdda-nav-label">Jump to</span>
      {modules.map(m => (
        <button
          key={m.slug}
          type="button"
          className="mdda-nav-chip"
          onClick={() => handleClick(m.slug)}
          title={m.module_name}
        >
          <span className="mdda-nav-chip-id">{m.module_id}</span>
          <span className="mdda-nav-chip-short">{m.short}</span>
        </button>
      ))}
    </div>
  );
}
