import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { api, type AuditRow } from "../lib/api";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import { listAuditCommits, getCommitImpactForModule } from "../lib/auditLog";
import { computeFieldDiff } from "../lib/auditDiff";
import { parseDeepLink } from "../lib/auditDeepLink";
import { tierLabel } from "../lib/tier";
import { useTableSort } from "../lib/useTableSort";
import { SortHeader } from "./SortHeader";
import "./ChangeLogTable.css";

export interface Props {
  module: string;
}

type State =
  | { status: "loading" }
  | { status: "loaded"; rows: AuditRow[] }
  | { status: "error"; message: string };

/** Run `fn` over `items` with at most `limit` parallel in-flight calls.
 *  Resolves to results in the same order as `items`. */
async function mapWithConcurrency<T, R>(
  items: T[],
  limit: number,
  fn: (item: T) => Promise<R>,
): Promise<R[]> {
  const results: R[] = new Array(items.length);
  let next = 0;
  const workers = Array.from({ length: Math.min(limit, items.length) }, async () => {
    while (true) {
      const i = next++;
      if (i >= items.length) return;
      results[i] = await fn(items[i]);
    }
  });
  await Promise.all(workers);
  return results;
}

function formatDate(iso: string): string {
  // Best-effort short rendering; full ISO stays in the title for power users.
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    return d.toISOString().replace("T", " ").slice(0, 16) + " UTC";
  } catch {
    return iso;
  }
}

function renderValue(v: unknown, field?: string): string {
  if (v === undefined || v === null || v === "") return "(none)";
  if (typeof v === "object") return JSON.stringify(v);
  // Tier values display as the canonical label (Mandatory / Preferred / Advanced).
  if (field === "sme_tier") return tierLabel(String(v));
  return String(v);
}

function FieldsCell({ row }: { row: AuditRow }) {
  const diff = computeFieldDiff(
    (row.prior_fields as Record<string, unknown> | null) ?? null,
    (row.fields as Record<string, unknown> | null) ?? null,
  );
  if (diff.length === 0) {
    return <span className="muted">—</span>;
  }
  return (
    <ul className="cl-diff-list">
      {diff.map(d => (
        <li key={d.field} className={`cl-diff-line cl-${d.kind}`}>
          <code className="cl-diff-field">{d.field}</code>
          {d.kind === "set_no_prior" ? (
            <>
              <span className="cl-diff-after">{renderValue(d.after, d.field)}</span>
              <span className="cl-diff-no-prior">prior not captured</span>
            </>
          ) : (
            <>
              <span className="cl-diff-before">{renderValue(d.before, d.field)}</span>
              <span className="cl-diff-arrow">→</span>
              <span className="cl-diff-after">{renderValue(d.after, d.field)}</span>
            </>
          )}
        </li>
      ))}
    </ul>
  );
}

export function ChangeLogTable({ module }: Props) {
  const [state, setState] = useState<State>({ status: "loading" });
  const { auth: ghAuth } = useAuth();

  useEffect(() => {
    let cancelled = false;
    setState({ status: "loading" });

    // v2: read filtered git commit history via the Commits API instead
    // of the (shorted-out) /api/audit endpoint. We surface only commits
    // whose message marks them as editor activity, filtered to the files
    // a module's edits would touch.
    if (GITHUB_NATIVE) {
      if (!ghAuth) {
        setState({ status: "loaded", rows: [] });
        return;
      }
      // No path filter — editor publishes touch many YAMLs (cap_overrides,
      // reorder_overrides, ai_features state, additions, cluster_assignments,
      // imda_ref_overrides). Filtering on a single path drops reorder + AI
      // Features publishes silently. The library's isEditorCommit message
      // filter (auditLog.ts) already narrows to editor activity.
      // Two-step:
      //   1) listAuditCommits — broad keyword/prefix filter on subject lines
      //      (cheap; one paged scan of main).
      //   2) getCommitImpactForModule — per-commit file-list fetch to confirm
      //      that the commit actually touched THIS module's checklist data,
      //      and to extract impacted cap IDs from patches. Drops false
      //      positives (e.g. viewer refactors mentioning "compliance" in the
      //      message but not editing checklist YAML/JSON).
      // Concurrency cap keeps GH API friendly while still parallelising.
      listAuditCommits(ghAuth, { limit: 100 })
        .then(async commits => {
          if (cancelled) return;
          const impacts = await mapWithConcurrency(commits, 5, async c => {
            try {
              return { c, impact: await getCommitImpactForModule(ghAuth, c.sha, module) };
            } catch {
              // Treat detail-fetch failure as "unknown impact, hide" — better
              // to under-show than to show false positives.
              return { c, impact: null };
            }
          });
          if (cancelled) return;
          const rows: AuditRow[] = [];
          for (const { c, impact } of impacts) {
            if (!impact || !impact.touchedAny) continue;
            const target = parseDeepLink(c.subject);
            // Prefer cap IDs extracted from the patch (precise). Fall back
            // to the subject deep-link if the patch parser found nothing
            // (e.g. compliance-only or AI-Features-only edits).
            const fromPatch = impact.capIds;
            const ids = fromPatch.length > 0
              ? fromPatch
              : (target?.kind === "cap" ? [target.capId] : []);
            const baseFields = {
              _commit: c.subject,
              ...(impact.touchedCompliance ? { _compliance: "changed" } : {}),
              ...(impact.touchedAiFeatures ? { _ai_features: "changed" } : {}),
            } as Record<string, unknown>;
            if (ids.length === 0) {
              // Commit touched in-scope files (e.g. compliance) but no cap-ID
              // surfaced. Keep one row so the change isn't lost.
              rows.push({
                id: 0,
                module,
                cap_id: impact.touchedCompliance
                  ? "(compliance baseline)"
                  : impact.touchedAiFeatures
                    ? "(AI features)"
                    : "(see commit)",
                op: c.subject.includes("publish") ? "publish" : "save",
                fields: baseFields,
                prior_fields: null,
                author: { email: c.author_email ?? "", name: c.author_login },
                created_at: c.authored_at,
                publish_commit_sha: c.sha,
              });
            } else {
              for (const capId of ids) {
                rows.push({
                  id: 0,
                  module,
                  cap_id: capId,
                  op: c.subject.includes("publish") ? "publish" : "save",
                  fields: baseFields,
                  prior_fields: null,
                  author: { email: c.author_email ?? "", name: c.author_login },
                  created_at: c.authored_at,
                  publish_commit_sha: c.sha,
                });
              }
            }
          }
          setState({ status: "loaded", rows });
        })
        .catch(e => {
          if (!cancelled) setState({ status: "error", message: String(e?.message || e) });
        });
      return () => { cancelled = true; };
    }

    api.audit({ module })
      .then(rows => {
        if (!cancelled) setState({ status: "loaded", rows });
      })
      .catch(e => {
        if (!cancelled) setState({ status: "error", message: String(e?.message || e) });
      });
    return () => { cancelled = true; };
  }, [module, ghAuth]);

  if (state.status === "loading") {
    return <div className="cl-table-msg muted">Loading change log…</div>;
  }
  if (state.status === "error") {
    return <div className="cl-table-msg error">Failed to load change log: {state.message}</div>;
  }
  if (state.rows.length === 0) {
    return <div className="cl-table-msg muted">No edits recorded for this module yet.</div>;
  }

  return (
    <ChangeLogTableBody
      rows={state.rows}
      repoOwner={ghAuth?.repoOwner}
      repoName={ghAuth?.repoName}
    />
  );
}

function ChangeLogTableBody({
  rows,
  repoOwner,
  repoName,
}: {
  rows: AuditRow[];
  repoOwner?: string;
  repoName?: string;
}) {
  const navigate = useNavigate();
  // Default: newest first (matches the order the audit API returns).
  const comparators = useMemo(() => ({
    created_at: (a: AuditRow, b: AuditRow) =>
      (a.created_at || "").localeCompare(b.created_at || ""),
    op: (a: AuditRow, b: AuditRow) => (a.op || "").localeCompare(b.op || ""),
    cap_id: (a: AuditRow, b: AuditRow) =>
      (a.cap_id || "").localeCompare(b.cap_id || ""),
    author: (a: AuditRow, b: AuditRow) =>
      (a.author.email || "").localeCompare(b.author.email || ""),
    publish_commit_sha: (a: AuditRow, b: AuditRow) =>
      (a.publish_commit_sha || "").localeCompare(b.publish_commit_sha || ""),
  }), []);
  const { sorted, sortBy, sortDir, setSort } = useTableSort<
    AuditRow,
    "created_at" | "op" | "cap_id" | "author" | "publish_commit_sha"
  >(rows, { defaultKey: "created_at", defaultDir: "desc", comparators });

  return (
    <table className="cl-table">
      <thead>
        <tr>
          <th><SortHeader label="When" colKey="created_at" sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Op" colKey="op" sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Cap" colKey="cap_id" sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th>Fields changed</th>
          <th><SortHeader label="Author" colKey="author" sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
          <th><SortHeader label="Commit" colKey="publish_commit_sha" sortBy={sortBy} sortDir={sortDir} onSort={setSort} /></th>
        </tr>
      </thead>
      <tbody>
        {sorted.map((row, idx) => {
          const hasCapTarget = row.cap_id && row.cap_id !== "(see commit)";
          const commitHref =
            row.publish_commit_sha && repoOwner && repoName
              ? `https://github.com/${repoOwner}/${repoName}/commit/${row.publish_commit_sha}`
              : null;
          return (
            <tr key={row.publish_commit_sha || `${row.id}-${idx}`}>
              <td className="cl-when" title={row.created_at}>{formatDate(row.created_at)}</td>
              <td className={`cl-op cl-op-${row.op}`}>{row.op}</td>
              <td className="cl-cap">
                {hasCapTarget ? (
                  <button
                    type="button"
                    className="cl-cap-link"
                    onClick={() =>
                      navigate(
                        `/canonical/${row.module}?cap=${encodeURIComponent(row.cap_id)}`,
                      )
                    }
                    title={`Open ${row.cap_id} in the module editor`}
                  >
                    <code>{row.cap_id}</code>
                  </button>
                ) : (
                  <code className="muted">{row.cap_id}</code>
                )}
              </td>
              <td className="cl-fields"><FieldsCell row={row} /></td>
              <td className="cl-author">{row.author.email}</td>
              <td className="cl-sha muted">
                {commitHref ? (
                  <a href={commitHref} target="_blank" rel="noopener noreferrer">
                    <code>{row.publish_commit_sha!.slice(0, 7)}</code>
                  </a>
                ) : row.publish_commit_sha ? (
                  <code>{row.publish_commit_sha.slice(0, 7)}</code>
                ) : (
                  <span className="muted">—</span>
                )}
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}
