import { useEffect, useState } from "react";
import { MODULES } from "../lib/modules";
import { TabHelp } from "../components/TabHelp";
import {
  loadDashboardSummary,
  type DashboardSummary,
} from "../lib/dashboardSummary";
import { useDrafts } from "../contexts/DraftsContext";
import { DashboardTile } from "../components/DashboardTile";
import "./HomePage.css";

function countDraftsByModule(draftsByCap: Map<string, { module: string }>): Map<string, number> {
  const counts = new Map<string, number>();
  draftsByCap.forEach(d => {
    counts.set(d.module, (counts.get(d.module) || 0) + 1);
  });
  return counts;
}

export function HomePage() {
  const [summary, setSummary] = useState<DashboardSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const { draftsByCap } = useDrafts();

  useEffect(() => {
    loadDashboardSummary()
      .then(setSummary)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  const draftCounts = countDraftsByModule(draftsByCap);
  const totalDrafts = Array.from(draftCounts.values()).reduce((a, b) => a + b, 0);

  if (error) {
    return (
      <section className="home-page error">
        <h1>Dashboard</h1>
        <p>Failed to load dashboard summary: {error}</p>
      </section>
    );
  }

  if (!summary) {
    return (
      <section className="home-page">
        <h1>Dashboard</h1>
        <p className="muted">Loading…</p>
      </section>
    );
  }

  // Aggregate top-line counts across modules.
  const totals = Object.values(summary.modules).reduce(
    (acc, m) => ({
      caps: acc.caps + m.total_caps,
      required: acc.required + m.required,
      preferred: acc.preferred + m.preferred,
      advanced: acc.advanced + m.advanced,
      optional: acc.optional + m.optional,
      sub_modules: acc.sub_modules + m.sub_modules,
    }),
    { caps: 0, required: 0, preferred: 0, advanced: 0, optional: 0, sub_modules: 0 },
  );

  return (
    <section className="home-page">
      <header className="home-header">
        <span className="home-eyebrow">PSG ERP Spec · Dashboard</span>
        <h1>10 ERP modules · {totals.caps} capabilities</h1>
        <p className="home-headline">
          Generated {new Date(summary.generated_at).toLocaleString()}. Click any
          module to open its checklist + editor.
        </p>
        <TabHelp hint="Each module card opens the canonical checklist for that module (caps grouped by family + sub-module, evidence + vendor coverage per cap). Use Coverage / Cap library / Pricing Library from the top nav for cross-module views.">
          Workspace home — the 10 ERP module surface. Read this view to see
          aggregate cap counts per module and to jump into per-module
          checklists. Cross-module analysis lives under the top nav.
        </TabHelp>
        <div className="home-howto">
          <div className="home-howto-title">How to verify a sol cat's coverage</div>
          <ol className="home-howto-steps">
            <li>
              <strong>Coverage → IMDA gap</strong> — pick a sol cat → see per-module
              cap coverage with Mandatory pass/fail and explicit gaps.
            </li>
            <li>
              <strong>Coverage → By-IMDA-Q reference</strong> — same sol cat → see
              every IMDA Q with the canonical caps it backs (or flagged as orphan / baseline).
            </li>
            <li>
              <strong>Click any cap name</strong> in those tables → jumps to that cap's
              row in the module's canonical view, where you can review or edit.
            </li>
            <li>
              <strong>Pending edits tab</strong> on each module page — review draft
              changes before publishing to the YAML overrides.
            </li>
          </ol>
        </div>
        <div className="home-totals">
          <Stat label="Mandatory" value={totals.required} />
          <Stat label="Preferred" value={totals.preferred} />
          <Stat label="Advanced" value={totals.advanced} />
          <Stat label="Optional" value={totals.optional} />
          <Stat label="Sub-modules" value={totals.sub_modules} />
          <Stat label="Drafts pending" value={totalDrafts} highlight={totalDrafts > 0} />
        </div>
      </header>

      <div className="home-grid">
        {MODULES.map(m => {
          const s = summary.modules[m.slug];
          if (!s) return null;
          return (
            <DashboardTile
              key={m.slug}
              slug={m.slug}
              summary={s}
              draftCount={draftCounts.get(m.slug) || 0}
            />
          );
        })}
      </div>
    </section>
  );
}

function Stat({ label, value, highlight }: { label: string; value: number; highlight?: boolean }) {
  return (
    <div className={`home-totals-stat${highlight ? " highlight" : ""}`}>
      <div className="home-totals-value">{value}</div>
      <div className="home-totals-label">{label}</div>
    </div>
  );
}
