import type { PricingVendor } from "./pricingData";

/**
 * Pure helpers for the Pricing Library's compare-mode table.
 *
 * Split out of PricingLibraryPage.tsx so the row aggregation + per-vendor
 * tier ranking logic is testable in isolation — the page-level components
 * stay thin and rendering-only.
 */

export interface VendorRowAggregate {
  v: PricingVendor;
  id: string;
  packageCount: number;
  lowest: number | null;
  highest: number | null;
}

export function aggregateVendor(v: PricingVendor): VendorRowAggregate {
  const id = v.psg_id || v.benchmark_id || `${v.vendor_name}-${v.solution_name}`;
  const totals = v.packages
    .map(p => p.total_cost_sgd)
    .filter((n): n is number => typeof n === "number");
  return {
    v, id,
    packageCount: v.packages.length,
    lowest: totals.length ? Math.min(...totals) : null,
    highest: totals.length ? Math.max(...totals) : null,
  };
}

export interface PackageComparisonRow {
  rowId: string;
  vendor_name: string;
  solution_name: string;
  category: string;
  package_name: string;
  /** Tier slot — 1=cheapest, 2=mid, ... within the vendor's own packages.
   *  0 when the package has no total_cost_sgd (can't be ranked). */
  tier_rank: number;
  total: number | null;
  qualifying: number | null;
  net: number | null;
  support_pct: string;
}

/** Flatten visibleVendors → one row per package, with each row carrying
 *  the vendor's tier rank for that package (1 = cheapest, 0 = unpriced).
 *  Unpriced packages stay in the output so the table is honest about
 *  what's missing pricing. */
export function flattenForComparison(vendors: PricingVendor[]): PackageComparisonRow[] {
  const out: PackageComparisonRow[] = [];
  for (const v of vendors) {
    const indexed = v.packages.map((p, i) => ({ p, i }));
    indexed.sort((a, b) => {
      const aa = a.p.total_cost_sgd;
      const bb = b.p.total_cost_sgd;
      if (aa == null && bb == null) return a.i - b.i;
      if (aa == null) return 1;
      if (bb == null) return -1;
      return aa - bb;
    });
    indexed.forEach((entry, rankIdx) => {
      const tier_rank = entry.p.total_cost_sgd == null ? 0 : rankIdx + 1;
      out.push({
        rowId: `${v.psg_id || v.benchmark_id || v.vendor_name || "?"}::${entry.i}`,
        vendor_name: v.vendor_name || "—",
        solution_name: v.solution_name || "—",
        category: v.category || "—",
        package_name: entry.p.name || "(unnamed)",
        tier_rank,
        total: entry.p.total_cost_sgd,
        qualifying: entry.p.qualifying_cost_sgd,
        net: entry.p.net_cost_sgd,
        support_pct: v.psg_support_pct_raw || "—",
      });
    });
  }
  return out;
}

/** S/M/L labels for the tier_rank column. Falls back to TN for 4+. */
export function tierBadge(rank: number): string {
  if (rank === 1) return "S";
  if (rank === 2) return "M";
  if (rank === 3) return "L";
  return `T${rank}`;
}
