import type { ReactNode } from "react";
import "./TabHelp.css";

export interface TabHelpProps {
  /**
   * Optional override for the leading bold prefix. Defaults to "What's this for?".
   * Pass a different value (e.g. "How to read this:") when the framing isn't a
   * pure "what is this view for" question.
   */
  prefix?: string;
  /** One-sentence answer to the prefix question. */
  children: ReactNode;
  /** Optional muted second line — e.g. concrete next-step guidance. */
  hint?: ReactNode;
}

/**
 * Standard "What's this for?" callout used at the top of every tab and
 * sub-tab in the SPA. Single source of styling so the help blurb stays
 * visually consistent across surfaces.
 *
 * Usage:
 *   <TabHelp>The full canonical checklist for this module…</TabHelp>
 *   <TabHelp hint="Click any cap to drill into provenance">
 *     Sol cat × module heatmap.
 *   </TabHelp>
 */
export function TabHelp({ prefix = "What's this for?", children, hint }: TabHelpProps) {
  return (
    <div className="tab-help" role="note">
      <div className="tab-help-body">
        <strong>{prefix}</strong> {children}
      </div>
      {hint && <div className="tab-help-hint">{hint}</div>}
    </div>
  );
}
