import { HashRouter, Route, Routes, useLocation, useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { api, type Me } from "./lib/api";
import { CanonicalPage } from "./pages/CanonicalPage";
import { StakeholdersPage } from "./pages/StakeholdersPage";
import { HomePage } from "./pages/HomePage";
import { DashboardPage } from "./pages/DashboardPage";
import { CapLibraryPage } from "./pages/CapLibraryPage";
import { PricingLibraryPage } from "./pages/PricingLibraryPage";
import { AdminUsersPage } from "./pages/AdminUsersPage";
import { AdminHealthPage } from "./pages/AdminHealthPage";
import { AuditLogPage } from "./pages/AuditLogPage";
import { SolutionPage } from "./pages/SolutionPage";
import { AiPage } from "./pages/AiPage";
import { WorkflowsPage } from "./pages/WorkflowsPage";
import { IntegrationPage } from "./pages/IntegrationPage";
import { DraftsProvider } from "./contexts/DraftsContext";
import { AuthProvider, GITHUB_NATIVE, useAuth } from "./contexts/AuthContext";
import { SignIn } from "./components/SignIn";
import { PublishButton } from "./components/PublishButton";
import { PreviewBanner } from "./components/PreviewBanner";
import { NavBar } from "./components/NavBar";

export function App() {
  return (
    <AuthProvider>
      <DraftsProvider>
        <HashRouter>
          <AuthGate>
            <PreviewBanner />
            <Shell />
            <PublishButton />
          </AuthGate>
        </HashRouter>
      </DraftsProvider>
    </AuthProvider>
  );
}

/**
 * v2-only gate: when the build is GITHUB_NATIVE, the SPA refuses to render
 * any content until the user has signed in with a valid token. The CF
 * Worker + GH Pages bridge deploys leave GITHUB_NATIVE undefined, so the
 * gate is a no-op there.
 */
function AuthGate({ children }: { children: React.ReactNode }) {
  const { user, loading } = useAuth();
  if (!GITHUB_NATIVE) return <>{children}</>;
  if (loading) return null;
  if (!user) return <SignIn />;
  return <>{children}</>;
}

function Shell() {
  return (
    <div className="app-shell-spa">
      <ShellHeader />
      <main>
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/dashboard" element={<DashboardPage />} />
          <Route path="/stakeholders" element={<StakeholdersPage />} />
          <Route path="/canonical/:module" element={<CanonicalPage />} />
          <Route path="/cap-library" element={<CapLibraryPage />} />
          <Route path="/pricing-library" element={<PricingLibraryPage />} />
          <Route path="/admin/users" element={<AdminUsersPage />} />
          <Route path="/admin/health" element={<AdminHealthPage />} />
          <Route path="/audit" element={<AuditLogPage />} />
          <Route path="/solution" element={<SolutionPage />} />
          <Route path="/ai" element={<AiPage />} />
          <Route path="/workflows" element={<WorkflowsPage />} />
          <Route path="/integration" element={<IntegrationPage />} />
        </Routes>
      </main>
    </div>
  );
}

// Active-item resolver for the NavBar. Pulls the current route + (when on
// a canonical page) the module slug so the right item is aria-current=page.
function useActiveNavItem():
  | "overview"
  | "coverage"
  | "methodology"
  | "cap-library"
  | "pricing-library"
  | "admin-users"
  | "admin-health"
  | string
  | undefined {
  const loc = useLocation();
  const params = useParams<{ module?: string }>();
  if (loc.pathname === "/") return "overview";
  // Routes kept as /dashboard + /stakeholders so old bookmarks still work;
  // labels in the nav read "Coverage" + "Methodology".
  if (loc.pathname.startsWith("/dashboard")) return "coverage";
  if (loc.pathname.startsWith("/stakeholders")) return "methodology";
  if (loc.pathname.startsWith("/cap-library")) return "cap-library";
  if (loc.pathname.startsWith("/pricing-library")) return "pricing-library";
  if (loc.pathname.startsWith("/admin/users")) return "admin-users";
  if (loc.pathname.startsWith("/admin/health")) return "admin-health";
  if (loc.pathname.startsWith("/solution")) return "solution";
  if (loc.pathname.startsWith("/ai")) return "ai";
  if (loc.pathname.startsWith("/workflows")) return "workflows";
  if (loc.pathname.startsWith("/integration")) return "integration";
  if (loc.pathname.startsWith("/canonical/") && params.module) return params.module;
  // Try parsing the slug straight from the path so the resolver works
  // outside a route component context (the nav itself isn't a route child).
  const m = loc.pathname.match(/^\/canonical\/([^/]+)/);
  if (m) return m[1];
  return undefined;
}

function ShellHeader() {
  const active = useActiveNavItem();
  const { user: ghUser, signOut, previewRole, setPreviewRole } = useAuth();
  const [me, setMe] = useState<Me | null>(null);
  // v1 path still hits /api/me. v2 has no Worker; the role comes from
  // AuthContext (which derives it from data/_state/users.json after token
  // validation).
  useEffect(() => {
    if (GITHUB_NATIVE) {
      setMe(null);
      return;
    }
    api.me().then(setMe).catch(() => {});
  }, []);
  // Effective role honours preview override.
  const actualRole = GITHUB_NATIVE
    ? (ghUser?.app_role as Me["role"] | undefined)
    : me?.role;
  const effectiveRole = (previewRole as Me["role"] | undefined) || actualRole;
  const userLabel = GITHUB_NATIVE
    ? (ghUser ? `@${ghUser.login}${ghUser.email ? ` · ${ghUser.email}` : ""}` : "")
    : (me?.email ?? "");
  const canPreview = actualRole === "editor" || actualRole === "admin";
  return (
    <>
      <NavBar
        active={active}
        role={effectiveRole}
        visibleModules={GITHUB_NATIVE ? ghUser?.visible_modules ?? null : null}
      />
      <div className="app-user-strip">
        {(GITHUB_NATIVE ? !!ghUser : !!me)
          ? <span className="app-user">{userLabel}</span>
          : <span className="muted">…</span>}
        {canPreview && (
          <button
            type="button"
            className="app-preview-toggle"
            onClick={() => setPreviewRole(previewRole ? null : "viewer")}
            title={previewRole
              ? "Exit preview — show your actual role's UI again"
              : "Preview the SPA as a viewer would see it (read-only). Doesn't change your actual permissions."}
          >
            {previewRole ? "Exit preview" : "Preview as viewer"}
          </button>
        )}
        {GITHUB_NATIVE && ghUser && (
          <button
            type="button"
            className="app-signout"
            onClick={signOut}
            title="Sign out (clears stored token)"
          >
            Sign out
          </button>
        )}
      </div>
    </>
  );
}

