/**
 * Pricing coverage data — vendors with feature evidence but no pricing
 * entries in data/vendor_pricing/manual_pricing_overrides.yaml.
 *
 * Source: output/pricing_coverage.json — built by
 * scripts/build_pricing_coverage_snapshot.py.
 *
 * Companion to lib/pricingData.ts (which carries package-level pricing
 * for the 414-vendor PSG catalogue). This file focuses on the GAP —
 * which curated vendors are missing manual pricing entry.
 */

const BASE_URL = (import.meta.env.BASE_URL || "/").replace(/\/+$/, "/");

export interface PricingPlan {
  vendor_id: string;
  plan_name?: string;
  currency?: string;
  monthly_cost?: number;
  annual_cost?: number;
  per_user_cost?: number;
  per_user_unit?: string;
  included_users?: number;
  one_time_setup?: number;
  quoted_at?: string;
  quote_source?: string;
  raw_quote_text?: string;
  notes?: string;
  edited_by?: string;
  edited_at?: string;
}

export interface PricingCoverageRow {
  vendor_id: string;
  name: string;
  type: string;
  tier: string;
  modules: string[];
  pricing_url: string | null;
  pricing_status: string;
  currency: string | null;
  psg_id: string | null;
  has_evidence: boolean;
  n_pricings: number;
  plans: PricingPlan[];
  is_missing: boolean;
  is_quote_only: boolean;
}

export interface PricingCoverageMeta {
  generated_by: string;
  schema_version: number;
  vendor_count: number;
  with_evidence: number;
  with_pricing: number;
  missing: number;
  quote_only: number;
}

export interface PricingCoveragePayload {
  _meta: PricingCoverageMeta;
  vendors: PricingCoverageRow[];
}

let cache: PricingCoveragePayload | null = null;
let inflight: Promise<PricingCoveragePayload> | null = null;

export async function loadPricingCoverage(): Promise<PricingCoveragePayload> {
  if (cache) return cache;
  if (inflight) return inflight;
  const url = `${BASE_URL}pricing_coverage.json`;
  inflight = fetch(url, { cache: "no-store" })
    .then(r => {
      if (!r.ok) throw new Error(`HTTP ${r.status} fetching ${url}`);
      return r.json() as Promise<PricingCoveragePayload>;
    })
    .then(d => { cache = d; inflight = null; return d; });
  return inflight;
}

export type PricingFilter = "missing" | "quote_only" | "covered" | "all";

export function filterPricingRows(
  rows: PricingCoverageRow[],
  filter: PricingFilter,
  query: string,
): PricingCoverageRow[] {
  let out = rows;
  if (filter === "missing") out = out.filter(r => r.is_missing);
  else if (filter === "quote_only") out = out.filter(r => r.is_quote_only && r.is_missing);
  else if (filter === "covered") out = out.filter(r => r.n_pricings > 0);
  // "all" — no filter
  const q = query.trim().toLowerCase();
  if (q) {
    out = out.filter(r =>
      r.vendor_id.toLowerCase().includes(q) ||
      r.name.toLowerCase().includes(q) ||
      r.tier.toLowerCase().includes(q) ||
      r.type.toLowerCase().includes(q) ||
      r.modules.some(m => m.toLowerCase().includes(q))
    );
  }
  return out;
}
