import { Fragment, useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  loadStakeholdersSummary,
  type CapEvidence,
  type StakeholdersSummary,
} from "../lib/stakeholdersData";
import { tierLabel, tierClass } from "../lib/tier";
import { fuzzyFilter } from "../lib/fuzzy";
import { TabHelp } from "../components/TabHelp";
import { useTableSort } from "../lib/useTableSort";
import { SortHeader } from "../components/SortHeader";
import { CapSolutionsCoverageTable } from "../components/CapSolutionsCoverageTable";
import "./CapLibraryPage.css";

type ViewMode = "library" | "solutions";

/**
 * Cap library — Phase 1.
 *
 * One sortable / filterable table of every capability across all 10 modules,
 * with side detail panel showing provenance (IMDA sol cats), reference ERP
 * citations, and sector relevance. Built on caps_index already emitted by
 * scripts/build_stakeholders_summary.py — no new pipeline needed.
 *
 * Phase 2 (later): multi-select caps + "Generate sol cat checklist scaffold"
 * button + per-cap source attribution editor.
 */

const ALL = "__all__";

type SourceKind = "psg" | "proxy" | "both" | "none";

function classifySource(c: CapEvidence): SourceKind {
  const psg = (c.imda_refs?.length || 0) > 0;
  const proxy = (c.cited_sources?.length || 0) > 0;
  if (psg && proxy) return "both";
  if (psg) return "psg";
  if (proxy) return "proxy";
  return "none";
}

const SOURCE_LABEL: Record<SourceKind, string> = {
  psg: "PSG-driven",
  proxy: "Proxy-only",
  both: "PSG + Proxy",
  none: "No source",
};

type SizeFilter = "all" | "sme" | "mid_enterprise" | "enterprise_only";

const SIZE_LABEL: Record<SizeFilter, string> = {
  all: "All sizes",
  sme: "SME-applicable",
  mid_enterprise: "Mid + Enterprise (not SME)",
  enterprise_only: "Enterprise only",
};

function matchesSize(c: CapEvidence, f: SizeFilter): boolean {
  if (f === "all") return true;
  const a = c.applicability || [];
  if (f === "sme") return a.includes("sme");
  if (f === "mid_enterprise") return !a.includes("sme") && a.includes("mid_market");
  if (f === "enterprise_only") return a.length === 1 && a[0] === "enterprise";
  return true;
}

export function CapLibraryPage() {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  // Two-stage search state so typing stays responsive on the ~300-cap
  // table. `searchInput` updates instantly (controls the input element);
  // `search` is the debounced filter trigger that runs the fuzzy match.
  // 200ms is short enough to feel immediate but long enough to skip
  // every-keystroke filter rebuilds.
  const [searchInput, setSearchInput] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  useEffect(() => {
    const t = setTimeout(() => setSearch(searchInput), 200);
    return () => clearTimeout(t);
  }, [searchInput]);
  const [moduleFilter, setModuleFilter] = useState<string>(ALL);
  const [tierFilter, setTierFilter] = useState<string>(ALL);
  const [sourceFilter, setSourceFilter] = useState<string>(ALL);
  const [sectorFilter, setSectorFilter] = useState<string>(ALL);
  const [sizeFilter, setSizeFilter] = useState<SizeFilter>("all");
  const [selectedId, setSelectedId] = useState<string | null>(null);
  // Sub-tab toggle: "library" (existing sortable table + side detail) vs
  // "solutions" (new per-cap vendor coverage view with last_updated). Both
  // share the filter state above — sub-tab just rebrands the rendering.
  const [viewMode, setViewMode] = useState<ViewMode>("library");

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  // Build the sector list from caps' sector_relevance (union of scope_sectors).
  const allSectors = useMemo(() => {
    if (!data) return [];
    const set = new Set<string>();
    for (const c of data.caps_index) {
      const sectors = c.sector_relevance?.scope_sectors || [];
      for (const s of sectors) set.add(s);
    }
    return Array.from(set).sort();
  }, [data]);

  const filtered = useMemo(() => {
    if (!data) return [];
    // Structured filters first — narrows the set before fuzzy ranking.
    const structured = data.caps_index.filter((c: CapEvidence) => {
      if (moduleFilter !== ALL && c.module !== moduleFilter) return false;
      if (tierFilter !== ALL && c.sme_tier !== tierFilter) return false;
      if (sourceFilter !== ALL && classifySource(c) !== sourceFilter) return false;
      if (!matchesSize(c, sizeFilter)) return false;
      if (sectorFilter !== ALL) {
        const rel = c.sector_relevance?.sectors?.[sectorFilter];
        if (!rel?.relevant) return false;
      }
      return true;
    });
    return fuzzyFilter(
      structured,
      search,
      ["id", "name", "module", "sub_module_name", "family", "question"],
    );
  }, [data, search, moduleFilter, tierFilter, sourceFilter, sectorFilter, sizeFilter]);

  const selectedCap = useMemo(
    () => data?.caps_index.find(c => c.id === selectedId) || null,
    [data, selectedId],
  );

  // Column-level sort on the filtered set. When search is non-empty the
  // fuzzy match order is preferred (relevance > alphabetical), so we let
  // useTableSort fall through to default (name asc).
  const TIER_ORDER: Record<string, number> = { required: 0, preferred: 1, advanced: 2, deleted: 3 };
  const capComparators = useMemo(() => ({
    name:   (a: CapEvidence, b: CapEvidence) => (a.name || "").localeCompare(b.name || ""),
    module: (a: CapEvidence, b: CapEvidence) =>
      moduleShort(a.module, data!).localeCompare(moduleShort(b.module, data!))
      || (a.sub_module_name || "").localeCompare(b.sub_module_name || ""),
    sme_tier: (a: CapEvidence, b: CapEvidence) =>
      (TIER_ORDER[a.sme_tier || ""] ?? 99) - (TIER_ORDER[b.sme_tier || ""] ?? 99),
    source: (a: CapEvidence, b: CapEvidence) =>
      classifySource(a).localeCompare(classifySource(b)),
    sectors: (a: CapEvidence, b: CapEvidence) => {
      const ra = Object.values(a.sector_relevance?.sectors || {}).filter(s => s?.relevant).length;
      const rb = Object.values(b.sector_relevance?.sectors || {}).filter(s => s?.relevant).length;
      return ra - rb;
    },
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }), [data]);
  const { sorted: sortedFiltered, sortBy: capSortBy, sortDir: capSortDir, setSort: setCapSort } =
    useTableSort<CapEvidence, "name" | "module" | "sme_tier" | "source" | "sectors">(filtered, {
      defaultKey: "name",
      defaultDir: "asc",
      comparators: capComparators,
    });

  if (error) {
    return (
      <section className="cl-page error">
        <h1>Cap Library</h1>
        <p>Failed to load: {error}</p>
      </section>
    );
  }

  if (!data) {
    return (
      <section className="cl-page">
        <h1>Cap Library</h1>
        <p className="muted">Loading…</p>
      </section>
    );
  }

  const counts = {
    total: data.caps_index.length,
    visible: filtered.length,
  };

  return (
    <section className="cl-page">
      <header className="cl-header">
        <h1>Cap Library</h1>
      </header>
      <TabHelp hint="Filter by module, tier, sector, or source. Library tab — click a row to open the side detail with IMDA refs, reference-ERP citations, and sector relevance. Solutions Coverage tab — per-cap vendor coverage groups + last-updated timestamp.">
        Every capability across all 10 ERP modules in one searchable table —
        the canonical universe of caps the pipeline produces, before any
        sub-module grouping or in_checklist filtering.
      </TabHelp>

      <div className="cl-subtabs" role="tablist">
        <button
          type="button"
          role="tab"
          aria-selected={viewMode === "library"}
          className={`cl-subtab${viewMode === "library" ? " cl-subtab-active" : ""}`}
          onClick={() => setViewMode("library")}
        >
          Cap Library
        </button>
        <button
          type="button"
          role="tab"
          aria-selected={viewMode === "solutions"}
          className={`cl-subtab${viewMode === "solutions" ? " cl-subtab-active" : ""}`}
          onClick={() => setViewMode("solutions")}
        >
          Solutions Coverage
        </button>
      </div>

      <div className="cl-filters">
        <input
          type="search"
          className="cl-search"
          placeholder={`Search ${counts.total} caps by name, id, or question text…`}
          value={searchInput}
          onChange={e => setSearchInput(e.target.value)}
        />

        <label className="cl-filter">
          <span>Module {moduleFilter !== ALL && <em className="cl-filter-active">· active</em>}</span>
          <select
            value={moduleFilter}
            onChange={e => {
              const next = e.target.value;
              setModuleFilter(next);
              // Visible diagnostic: helps confirm the state updated in production
              // bundles. Surface in console so users can paste back a screenshot.
              // eslint-disable-next-line no-console
              console.log("[CapLibrary] module dropdown → set", next);
            }}
          >
            <option value={ALL}>All ({data.caps_index.length})</option>
            {data.modules.map(m => {
              const count = data.caps_index.filter(c => c.module === m.slug).length;
              return (
                <option key={m.slug} value={m.slug}>
                  {m.short || m.name} ({count})
                </option>
              );
            })}
          </select>
        </label>

        <label className="cl-filter">
          <span>Tier</span>
          <select value={tierFilter} onChange={e => setTierFilter(e.target.value)}>
            <option value={ALL}>All</option>
            <option value="required">Mandatory</option>
            <option value="preferred">Preferred</option>
            <option value="advanced">Advanced</option>
          </select>
        </label>

        <label className="cl-filter">
          <span>Source</span>
          <select value={sourceFilter} onChange={e => setSourceFilter(e.target.value)}>
            <option value={ALL}>All</option>
            <option value="psg">PSG-driven</option>
            <option value="proxy">Proxy-only</option>
            <option value="both">PSG + Proxy</option>
            <option value="none">No source</option>
          </select>
        </label>

        <label className="cl-filter">
          <span>Sector</span>
          <select value={sectorFilter} onChange={e => setSectorFilter(e.target.value)}>
            <option value={ALL}>Any</option>
            {allSectors.map(s => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </label>

        <label className="cl-filter">
          <span>Size</span>
          <select
            value={sizeFilter}
            onChange={e => setSizeFilter(e.target.value as SizeFilter)}
            title="Firm size the cap applies to. SME-applicable is the PSG target."
          >
            {(Object.keys(SIZE_LABEL) as SizeFilter[]).map(k => (
              <option key={k} value={k}>{SIZE_LABEL[k]}</option>
            ))}
          </select>
        </label>

        <span className="cl-count">{counts.visible} of {counts.total}</span>
      </div>

      {viewMode === "solutions" ? (
        <CapSolutionsCoverageTable
          caps={sortedFiltered}
          summary={data}
        />
      ) : (
      <div className={`cl-body${selectedCap ? " cl-body-with-detail" : ""}`}>
        <div className="cl-table-wrap">
          <table className="cl-table">
            <thead>
              <tr>
                <th><SortHeader label="Cap" colKey="name" sortBy={capSortBy} sortDir={capSortDir} onSort={setCapSort} /></th>
                <th><SortHeader label="Module · Sub-module" colKey="module" sortBy={capSortBy} sortDir={capSortDir} onSort={setCapSort} /></th>
                <th><SortHeader label="Tier" colKey="sme_tier" sortBy={capSortBy} sortDir={capSortDir} onSort={setCapSort} /></th>
                <th><SortHeader label="Source" colKey="source" sortBy={capSortBy} sortDir={capSortDir} onSort={setCapSort} /></th>
                <th><SortHeader label="Sectors" colKey="sectors" sortBy={capSortBy} sortDir={capSortDir} onSort={setCapSort} /></th>
              </tr>
            </thead>
            <tbody>
              {sortedFiltered.length === 0 ? (
                <tr><td colSpan={5} className="cl-empty">No caps match the current filters.</td></tr>
              ) : sortedFiltered.map(c => {
                const src = classifySource(c);
                const sectors = c.sector_relevance?.sectors || {};
                const scope = c.sector_relevance?.scope_sectors || [];
                const relevantCount = Object.values(sectors).filter(s => s?.relevant).length;
                const isSelected = c.id === selectedId;
                return (
                  <tr
                    key={c.id}
                    className={isSelected ? "cl-row cl-row-selected" : "cl-row"}
                    onClick={() => setSelectedId(prev => prev === c.id ? null : c.id)}
                  >
                    <td className="cl-cap-cell">
                      <div className="cl-cap-name">{c.name}</div>
                      <code className="cl-cap-id">{c.id}</code>
                    </td>
                    <td className="cl-mod-cell">
                      <div className="cl-mod-name">{moduleShort(c.module, data)}</div>
                      <div className="cl-sm-name">{c.sub_module_name || "—"}</div>
                    </td>
                    <td className={`cl-tier-cell ${tierClass(c.sme_tier)} tier-text`}>
                      {tierLabel(c.sme_tier)}
                    </td>
                    <td className="cl-src-cell">
                      <span className={`cl-src-pill cl-src-${src}`}>{SOURCE_LABEL[src]}</span>
                      {src !== "none" && (
                        <div className="cl-src-counts">
                          {(c.imda_refs?.length || 0) > 0 && <span>{c.imda_refs.length} IMDA</span>}
                          {(c.cited_sources?.length || 0) > 0 && <span>{c.cited_sources.length} ERPs</span>}
                        </div>
                      )}
                    </td>
                    <td className="cl-sect-cell">
                      {scope.length === 0 ? <span className="muted small">—</span> : (
                        <span className="cl-sect-frac">{relevantCount}/{scope.length}</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {selectedCap && (
          <CapDetailPanel
            cap={selectedCap}
            data={data}
            onClose={() => setSelectedId(null)}
          />
        )}
      </div>
      )}
    </section>
  );
}

function moduleShort(slug: string, data: StakeholdersSummary): string {
  const m = data.modules.find(x => x.slug === slug);
  return m ? (m.short || m.name || slug) : slug;
}

function CapDetailPanel({
  cap,
  data,
  onClose,
}: {
  cap: CapEvidence;
  data: StakeholdersSummary;
  onClose: () => void;
}) {
  const sectors = cap.sector_relevance?.sectors || {};
  const scope = cap.sector_relevance?.scope_sectors || [];
  const relevantCount = Object.values(sectors).filter(s => s?.relevant).length;
  const src = classifySource(cap);

  return (
    <aside className="cl-detail">
      <header className="cl-detail-head">
        <div>
          <code className="cl-cap-id">{cap.id}</code>
          <h2>{cap.name}</h2>
          <div className="cl-detail-meta">
            {moduleShort(cap.module, data)}
            {cap.sub_module_name && <> · {cap.sub_module_name}</>}
            {" · "}
            <strong className={`${tierClass(cap.sme_tier)} tier-text`}>
              {tierLabel(cap.sme_tier)}
            </strong>
            <span className={`cl-src-pill cl-src-${src} cl-detail-src`}>
              {SOURCE_LABEL[src]}
            </span>
          </div>
        </div>
        <div className="cl-detail-actions">
          <Link to={`/canonical/${cap.module}`} className="cl-detail-link">
            Open in module →
          </Link>
          <button type="button" className="cl-detail-close" onClick={onClose} title="Close">
            ×
          </button>
        </div>
      </header>

      {cap.question && (
        <section className="cl-detail-section">
          <h3>Vendor question</h3>
          <p className="cl-question">{cap.question}</p>
        </section>
      )}

      <section className="cl-detail-section">
        <h3>IMDA provenance · {cap.imda_refs?.length || 0} ref{cap.imda_refs?.length === 1 ? "" : "s"}</h3>
        {(!cap.imda_refs || cap.imda_refs.length === 0) ? (
          <p className="muted small italic">No IMDA references — proxy-grounded only.</p>
        ) : (
          <ul className="cl-ref-list">
            {cap.imda_refs.map((r, i) => (
              <li key={i} className="cl-ref-item">
                <div className="cl-ref-q">{r.q_title}</div>
                <div className="cl-ref-sc">
                  {(r.sources || []).map(s => s.split("__").pop()).join(" · ")}
                </div>
              </li>
            ))}
          </ul>
        )}
      </section>

      <section className="cl-detail-section">
        <h3>Reference ERP citations · {cap.cited_sources?.length || 0}</h3>
        {(!cap.cited_sources || cap.cited_sources.length === 0) ? (
          <p className="muted small italic">No ref ERP citations recorded.</p>
        ) : (
          <div className="cl-vendor-chips">
            {cap.cited_sources.map(v => (
              <span key={v} className="cl-vendor-chip" title={v}>
                {data.proxy_id_to_name[v] || v}
              </span>
            ))}
          </div>
        )}
      </section>

      <section className="cl-detail-section">
        <h3>Size applicability</h3>
        {(!cap.applicability || cap.applicability.length === 0) ? (
          <p className="muted small italic">Not specified.</p>
        ) : (
          <div className="cl-size-chips">
            {(["sme", "mid_market", "enterprise"] as const).map(s => (
              <span
                key={s}
                className={`cl-size-chip${cap.applicability.includes(s) ? " on" : " off"}`}
                title={cap.applicability.includes(s) ? `Applies at ${s} size` : `Not applicable at ${s} size`}
              >
                {s === "mid_market" ? "Mid-market" : s.charAt(0).toUpperCase() + s.slice(1)}
              </span>
            ))}
          </div>
        )}
      </section>

      <section className="cl-detail-section">
        <h3>Sector relevance · {relevantCount}/{scope.length}</h3>
        {scope.length === 0 ? (
          <p className="muted small italic">No sector data.</p>
        ) : (
          <div className="cl-sect-heatmap">
            {scope.map(s => {
              const entry = sectors[s];
              const relevant = entry?.relevant === true;
              return (
                <Fragment key={s}>
                  <div
                    className={`cl-sect-cell${relevant ? " cl-sect-relevant" : ""}`}
                    title={entry?.reason || (relevant ? "Relevant" : "Not relevant")}
                  >
                    {s}
                  </div>
                </Fragment>
              );
            })}
          </div>
        )}
      </section>
    </aside>
  );
}
