import { useEffect, useMemo, useState } from "react";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import { listAuditCommits, type AuditCommit, type AuditFilters } from "../lib/auditLog";
import { useEffectiveRole } from "../lib/useEffectiveRole";
import { canEdit } from "../lib/role";
import { TabHelp } from "../components/TabHelp";
import { useTableSort } from "../lib/useTableSort";
import { SortHeader } from "../components/SortHeader";
import "./AuditLogPage.css";

/**
 * v2 audit log — filtered git commit history surfaced as a sortable table.
 * Reads commits via the GitHub Commits API (no Worker, no D1). Filter by
 * file path / author / date range; export to CSV via the browser if needed.
 *
 * Available only in v2 (GITHUB_NATIVE). v1 surfaces the CF Worker audit log
 * elsewhere. The Page returns a "not available in this deploy" notice when
 * VITE_GITHUB_NATIVE isn't set, so the route stays linkable but degrades
 * gracefully.
 */
export function AuditLogPage() {
  const { auth: ghAuth, user: ghUser } = useAuth();
  const role = useEffectiveRole();
  const editable = canEdit(role);
  const [rows, setRows] = useState<AuditCommit[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [filterPath, setFilterPath] = useState<string>("");
  const [filterAuthor, setFilterAuthor] = useState<string>("");
  const [filterSince, setFilterSince] = useState<string>("");
  const [limit, setLimit] = useState<number>(50);

  const presetPaths = useMemo(() => [
    { value: "", label: "(any file)" },
    { value: "data/manual_cap_overrides.yaml", label: "Cap overrides YAML" },
    { value: "data/manual_reorder_overrides.yaml", label: "Reorder overrides YAML" },
  ], []);

  const fetchRows = async () => {
    if (!GITHUB_NATIVE || !ghAuth) return;
    setLoading(true);
    setError(null);
    try {
      const filters: AuditFilters = { limit };
      if (filterPath) filters.path = filterPath;
      if (filterAuthor) filters.author = filterAuthor;
      if (filterSince) filters.since = filterSince;
      const data = await listAuditCommits(ghAuth, filters);
      setRows(data);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRows();
    // Intentionally only refreshes on mount + manual reload — fetching on
    // every filter keystroke would burn rate-limit budget for tiny changes.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Server returns rows sorted by authored_at desc. The hook respects that
  // as the default so first render is unchanged.
  const auditComparators = useMemo(() => ({
    authored_at: (a: AuditCommit, b: AuditCommit) =>
      (a.authored_at || "").localeCompare(b.authored_at || ""),
    author_login: (a: AuditCommit, b: AuditCommit) =>
      (a.author_login || "").localeCompare(b.author_login || ""),
    subject: (a: AuditCommit, b: AuditCommit) =>
      (a.subject || "").localeCompare(b.subject || ""),
    short_sha: (a: AuditCommit, b: AuditCommit) =>
      (a.short_sha || "").localeCompare(b.short_sha || ""),
  }), []);
  const { sorted: sortedRows, sortBy: auditSortBy, sortDir: auditSortDir, setSort: setAuditSort } =
    useTableSort<AuditCommit, "authored_at" | "author_login" | "subject" | "short_sha">(rows, {
      defaultKey: "authored_at",
      defaultDir: "desc",
      comparators: auditComparators,
    });

  if (!GITHUB_NATIVE) {
    return (
      <div className="audit-shell">
        <h1>Audit log</h1>
        <p className="muted">
          The audit log surface is only available in the v2 GitHub-native
          deploy. The current build uses a different audit backend.
        </p>
      </div>
    );
  }

  if (!ghAuth) {
    return (
      <div className="audit-shell">
        <h1>Audit log</h1>
        <p className="muted">Sign in to view editor history.</p>
      </div>
    );
  }

  if (!editable) {
    return (
      <div className="audit-shell">
        <h1>Audit log</h1>
        <p className="muted">
          The audit log is available to editors and admins only. As a viewer,
          you have read-only access to the checklist itself.
        </p>
      </div>
    );
  }

  return (
    <div className="audit-shell">
      <header className="audit-header">
        <h1>Audit log</h1>
        <p className="muted small">
          Every editor publish becomes a git commit on <code>main</code>. This
          page surfaces commits whose message marks them as editor activity
          (<code>data(editor)</code> / <code>data(overrides)</code> / <code>editor(draft)</code>).
          Filter by file or author, then click a row to open the commit on GitHub.
        </p>
      </header>
      <TabHelp hint="Filter the GitHub commit log to editor-flagged commits only. Click any row to open the commit diff on GitHub for full provenance.">
        Provenance trail for every checklist edit. Useful when investigating
        when a cap tier changed, who authored an override, or which session
        a vendor question was rewritten in.
      </TabHelp>

      <section className="audit-filters">
        <label>
          File
          <select value={filterPath} onChange={e => setFilterPath(e.target.value)}>
            {presetPaths.map(p => <option key={p.value} value={p.value}>{p.label}</option>)}
          </select>
        </label>
        <label>
          Author (GitHub username)
          <input
            type="text"
            value={filterAuthor}
            onChange={e => setFilterAuthor(e.target.value)}
            placeholder={ghUser?.login || "any"}
            spellCheck={false}
          />
        </label>
        <label>
          Since
          <input
            type="date"
            value={filterSince}
            onChange={e => setFilterSince(e.target.value ? `${e.target.value}T00:00:00Z` : "")}
          />
        </label>
        <label>
          Limit
          <select value={limit} onChange={e => setLimit(parseInt(e.target.value, 10))}>
            <option value={20}>20</option>
            <option value={50}>50</option>
            <option value={100}>100</option>
          </select>
        </label>
        <button className="audit-apply" onClick={fetchRows} disabled={loading}>
          {loading ? "Loading…" : "Apply"}
        </button>
      </section>

      {error && <div className="audit-error">Failed to load: {error}</div>}

      {rows.length === 0 && !loading ? (
        <p className="muted">No editor commits matched these filters.</p>
      ) : (
        <table className="audit-table">
          <thead>
            <tr>
              <th>
                <SortHeader label="When" colKey="authored_at"
                  sortBy={auditSortBy} sortDir={auditSortDir} onSort={setAuditSort} />
              </th>
              <th>
                <SortHeader label="Author" colKey="author_login"
                  sortBy={auditSortBy} sortDir={auditSortDir} onSort={setAuditSort} />
              </th>
              <th>
                <SortHeader label="Commit" colKey="short_sha"
                  sortBy={auditSortBy} sortDir={auditSortDir} onSort={setAuditSort} />
              </th>
              <th>
                <SortHeader label="Subject" colKey="subject"
                  sortBy={auditSortBy} sortDir={auditSortDir} onSort={setAuditSort} />
              </th>
            </tr>
          </thead>
          <tbody>
            {sortedRows.map(r => (
              <tr key={r.sha}>
                <td className="audit-when" title={r.authored_at}>
                  {r.authored_at ? new Date(r.authored_at).toLocaleString() : ""}
                </td>
                <td className="audit-author">@{r.author_login}</td>
                <td className="audit-sha">
                  <a href={r.url} target="_blank" rel="noopener noreferrer">
                    {r.short_sha} ↗
                  </a>
                </td>
                <td className="audit-subject">{r.subject}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
