import { useEffect, useMemo, useState } from "react";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type VendorPricingPayload,
  type VendorPricingModule,
  type VendorPricingTier,
  type VendorPricingRow,
  type VendorTier,
} from "../../lib/stakeholdersData";
import { TabHelp } from "../TabHelp";
import { PricingChart } from "./PricingChart";
import {
  usePricingProfile,
  rescale,
  applyComponents,
  formatPriceForDisplay,
  PERIOD_LABEL,
  COMPONENT_LABEL,
  type PricingProfile,
  type PricingPax,
  type PricingCurrency,
  type PricingPeriod,
  type PricingComponents,
} from "../../lib/pricingProfile";
import "./PricingCheckPanel.css";

/** Combined tier filter — adds "SME + Mid-market" alongside the 3 base tiers. */
type TierKey = VendorTier | "sme_mid";

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

// Map canonical module slug → vendor_pricing key
const MODULE_TO_PRICING_KEY: Record<string, string> = {
  financial_management: "financial",
  sales_and_crm: "sales_crm",
  human_resources_management: "hr",
  supply_chain_and_inventory: "supply_chain",
};

const MODULE_LABEL: Record<string, string> = {
  financial: "Financial",
  sales_crm: "Sales & CRM",
  hr: "HR",
  supply_chain: "Supply Chain",
};

const TIER_LABEL: Record<TierKey, string> = {
  sme: "SME",
  mid: "Mid-market",
  enterprise: "Enterprise",
  sme_mid: "SME + Mid-market",
};

const TYPE_LABEL: Record<string, string> = {
  erp_suite: "ERP suite",
  sg_local_psg: "SG-PSG",
  sg_local_non_psg: "SG-local",
  enterprise: "Enterprise",
};

const SOURCE_LABEL: Record<string, string> = {
  psg_package_bundled: "PSG bundle",
  website_granular: "Website (incl. PS+training)",
  website_software_only: "Website (software only)",
  no_pricing_data: "No data",
  no_data: "No data",
};

/**
 * Coverage > Module > Pricing check sub-tab.
 *
 * For the 4 commodity-suite modules (Financial / Sales-CRM / HR /
 * Supply Chain), shows how PSG-listed + reference ERP vendors price
 * the Mandatory cap list. Helps the grants team validate the M tier
 * against commercial reality.
 *
 * Data source: summary.vendor_pricing (built by
 * scripts/build_vendor_pricing_summary.py).
 */
export function PricingCheckPanel({ modules }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [moduleSlug, setModuleSlug] = useState<string>(modules[0]?.slug || "");
  const [tier, setTier] = useState<TierKey>("sme_mid");
  const [profile, updateProfile] = usePricingProfile();

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  const pricing: VendorPricingPayload | null = data?.vendor_pricing || null;
  const pricingKey = MODULE_TO_PRICING_KEY[moduleSlug];
  const moduleData: VendorPricingModule | null = pricing && pricingKey
    ? pricing.modules[pricingKey] || null
    : null;

  // Only show modules that have pricing data
  const supportedModules = useMemo(() => {
    if (!pricing) return [] as ModuleEntry[];
    return modules.filter(m => MODULE_TO_PRICING_KEY[m.slug] && pricing.modules[MODULE_TO_PRICING_KEY[m.slug]]);
  }, [pricing, modules]);

  if (error) return <div className="dash-panel pcp-error">Failed to load: {error}</div>;
  if (!data) return <div className="dash-panel pcp-loading">Loading…</div>;
  if (!pricing) {
    return (
      <div className="dash-panel">
        <TabHelp>
          Vendor-pricing data hasn't been generated yet. Run{" "}
          <code>python3 scripts/build_vendor_pricing_summary.py</code> on the
          backend, then re-build the SPA.
        </TabHelp>
      </div>
    );
  }

  return (
    <div className="dash-panel pcp-panel">
      <TabHelp hint="Year-1 SGD = software×12 + PS one-time + training one-time. PSG-bundled vendors use their bundled total (already includes all 3). Vendors with quote-on-request show 'No data' but stay in the table.">
        Validate our Mandatory tier against commercial reality. For each
        of the 4 commodity-suite modules, see how reference ERP suites and
        PSG-listed SG vendors price the Mandatory cap list — base plan
        coverage, add-ons, and bundled Year-1 SGD totals. Use this to
        defend the grant amount or rebalance M / P / A.
      </TabHelp>

      <div className="pcp-controls">
        <div className="pcp-control">
          <label>Module</label>
          <div className="pcp-pills">
            {supportedModules.map(m => (
              <button
                key={m.slug}
                type="button"
                className={`pcp-pill${m.slug === moduleSlug ? " active" : ""}`}
                onClick={() => setModuleSlug(m.slug)}
              >
                {m.module_name}
              </button>
            ))}
          </div>
        </div>
        <div className="pcp-control">
          <label>Vendor tier</label>
          <div className="pcp-pills">
            {(["sme_mid", "sme", "mid", "enterprise"] as TierKey[]).map(t => (
              <button
                key={t}
                type="button"
                className={`pcp-pill${t === tier ? " active" : ""}`}
                onClick={() => setTier(t)}
                title={
                  t === "sme_mid"
                    ? "SME-positioned + mid-market-positioned vendors combined"
                    : `${TIER_LABEL[t]}-positioned vendors`
                }
              >
                {TIER_LABEL[t]}
              </button>
            ))}
          </div>
        </div>
        <div className="pcp-meta">
          {pricing._meta.vendor_count_with_pricing} of{" "}
          {pricing._meta.vendor_count_total} catalogued vendors have pricing data ·
          backend baseline: fx USD→SGD = {pricing._meta.fx_assumption_usd_to_sgd} ·{" "}
          {pricing._meta.user_baseline} pax · SGD/month. Profile controls (below
          chart) rescale prices for display only.
        </div>
      </div>

      {moduleData ? (
        <ModuleSection
          moduleData={moduleData}
          tierKey={tier}
          moduleSlug={moduleSlug}
          profile={profile}
          updateProfile={updateProfile}
        />
      ) : (
        <p className="muted">No pricing data for this module.</p>
      )}
    </div>
  );
}

function ProfileControls({
  profile,
  update,
}: {
  profile: PricingProfile;
  update: (patch: Partial<PricingProfile>) => void;
}) {
  const paxOptions: PricingPax[] = [1, 5, 10, 25, 50];
  const periodOptions: PricingPeriod[] = ["monthly", "annual", "3yr_tco"];
  const componentOptions: PricingComponents[] = ["sw_only", "sw_ps", "sw_ps_tr"];
  const currencyOptions: PricingCurrency[] = ["SGD", "USD"];
  return (
    <div className="pcp-control pcp-profile-controls">
      <div className="pcp-profile-group">
        <label>Pax</label>
        <div className="pcp-pills pcp-pills-compact">
          {paxOptions.map(p => (
            <button
              key={p}
              type="button"
              className={`pcp-pill${p === profile.pax ? " active" : ""}`}
              onClick={() => update({ pax: p })}
            >
              {p}
            </button>
          ))}
        </div>
      </div>
      <div className="pcp-profile-group">
        <label>Period</label>
        <div className="pcp-pills pcp-pills-compact">
          {periodOptions.map(p => (
            <button
              key={p}
              type="button"
              className={`pcp-pill${p === profile.period ? " active" : ""}`}
              onClick={() => update({ period: p })}
            >
              {PERIOD_LABEL[p]}
            </button>
          ))}
        </div>
      </div>
      <div className="pcp-profile-group">
        <label>Components</label>
        <div className="pcp-pills pcp-pills-compact">
          {componentOptions.map(c => (
            <button
              key={c}
              type="button"
              className={`pcp-pill${c === profile.components ? " active" : ""}`}
              onClick={() => update({ components: c })}
              title={COMPONENT_LABEL[c]}
            >
              {c === "sw_only" ? "SW" : c === "sw_ps" ? "+ PS" : "+ PS + Tr"}
            </button>
          ))}
        </div>
      </div>
      <div className="pcp-profile-group">
        <label>Currency</label>
        <div className="pcp-pills pcp-pills-compact">
          {currencyOptions.map(c => (
            <button
              key={c}
              type="button"
              className={`pcp-pill${c === profile.currency ? " active" : ""}`}
              onClick={() => update({ currency: c })}
            >
              {c}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

function ModuleSection({
  moduleData,
  tierKey,
  moduleSlug,
  profile,
  updateProfile,
}: {
  moduleData: VendorPricingModule;
  tierKey: TierKey;
  moduleSlug: string;
  profile: PricingProfile;
  updateProfile: (patch: Partial<PricingProfile>) => void;
}) {
  const moduleLabel = MODULE_LABEL[moduleSlug] || moduleSlug;

  // Resolve which tier(s) the active filter covers
  const tierKeys: VendorTier[] =
    tierKey === "sme_mid" ? ["sme", "mid"] : [tierKey];
  const vendorsForTier: VendorPricingRow[] = tierKeys.flatMap(t =>
    moduleData.by_tier[t]?.vendors || [],
  );
  const totalCount = tierKeys.reduce(
    (n, t) => n + (moduleData.by_tier[t]?.vendor_count_total || 0), 0);
  const withPricingCount = tierKeys.reduce(
    (n, t) => n + (moduleData.by_tier[t]?.vendor_count_with_pricing || 0), 0);

  const tierData: VendorPricingTier = {
    vendor_count_total: totalCount,
    vendor_count_with_pricing: withPricingCount,
    vendors: vendorsForTier,
    avg_base_price_sgd_month: null,
    min_base_price_sgd_month: null,
    max_base_price_sgd_month: null,
  };

  if (vendorsForTier.length === 0) {
    return (
      <p className="pcp-empty">
        No {TIER_LABEL[tierKey]} vendors catalogued for {moduleLabel}.
      </p>
    );
  }

  // Headline numbers (across the resolved tier set) — applied through the
  // active profile so headline matches what the table + chart show.
  const withPricing = vendorsForTier.filter(v => v.year1_total_sgd != null);
  const rescaledTotals = withPricing.map(v => {
    const componentTotal = applyComponents(v.year1_breakdown, v.year1_total_sgd, profile.components);
    const baselineSgdMonth = componentTotal != null ? componentTotal / 12 : null;
    return rescale(baselineSgdMonth, v.base_price_label, profile);
  }).map(r => r.value).filter((n): n is number => typeof n === "number");

  const avgTotal = rescaledTotals.length > 0
    ? rescaledTotals.reduce((s, v) => s + v, 0) / rescaledTotals.length
    : null;
  const avgCoverage = withPricing.length > 0
    ? withPricing.reduce((sum, v) => sum + v.mandatory_pct, 0) / withPricing.length
    : null;
  const periodLabel =
    profile.period === "monthly" ? "monthly avg"
    : profile.period === "3yr_tco" ? "3-yr TCO avg"
    : "Year-1 avg";

  return (
    <>
      <div className="pcp-headline">
        <div className="pcp-stat">
          <div className="pcp-stat-num">{moduleData.mandatory_total}</div>
          <div className="pcp-stat-lbl">Mandatory caps</div>
        </div>
        <div className="pcp-stat">
          <div className="pcp-stat-num">
            {tierData.vendor_count_with_pricing}/{tierData.vendor_count_total}
          </div>
          <div className="pcp-stat-lbl">{TIER_LABEL[tierKey]} vendors with data</div>
        </div>
        <div className="pcp-stat">
          <div className="pcp-stat-num">
            {avgTotal != null ? formatPriceForDisplay(avgTotal, profile) : "—"}
          </div>
          <div className="pcp-stat-lbl">{periodLabel} ({profile.pax} pax)</div>
        </div>
        <div className="pcp-stat">
          <div className="pcp-stat-num">
            {avgCoverage != null ? `${Math.round(avgCoverage)}%` : "—"}
          </div>
          <div className="pcp-stat-lbl">avg Mandatory coverage in base</div>
        </div>
      </div>

      <PricingChart vendors={tierData.vendors} profile={profile} />

      <ProfileControls profile={profile} update={updateProfile} />

      <h4 className="pcp-h4">Vendor pricing detail</h4>
      <table className="pcp-vendor-table">
        <thead>
          <tr>
            <th>Vendor</th>
            <th>Type</th>
            <th>Base plan</th>
            <th>Year-1 SGD</th>
            <th>Net after PSG</th>
            <th>M coverage</th>
            <th>Add-ons</th>
            <th>Source</th>
          </tr>
        </thead>
        <tbody>
          {tierData.vendors.map(v => (
            <VendorRow key={v.id} vendor={v} profile={profile} />
          ))}
        </tbody>
      </table>

      {/* Per-cap × per-vendor matrix MOVED to Dashboard Perspective C
          (Coverage matrix) — see CoverageMatrixPanel. This panel now
          focuses on the pricing-side story only: chart + profile + per-
          vendor pricing detail. */}
    </>
  );
}

// Per-cap × per-vendor matrix code (CapVendorMatrix + MatrixTierFilterBar +
// VendorFilterBar + cellGlyph + cellLabel + shortenVendor helpers) was
// moved to Dashboard Perspective C → CoverageMatrixPanel.

function VendorRow({ vendor, profile }: { vendor: VendorPricingRow; profile: PricingProfile }) {
  const breakdown = vendor.year1_breakdown;
  const isBundled = breakdown?.bundled;

  // Apply components filter first, then rescale the resulting total.
  const componentTotal = applyComponents(breakdown, vendor.year1_total_sgd, profile.components);
  const baselineSgdMonth = componentTotal != null ? componentTotal / 12 : null;
  const rescaled = rescale(baselineSgdMonth, vendor.base_price_label, profile);
  const yearTotalCell = rescaled.value != null
    ? formatPriceForDisplay(rescaled.value, profile)
    : (vendor.pricing_status === "quote_on_request" ? "Quote-on-request" : "—");

  // Net-after-PSG also gets the period+currency treatment (per-pax doesn't apply).
  const netRescaled = isBundled && breakdown?.net_cost_after_psg_sgd != null
    ? rescale(breakdown.net_cost_after_psg_sgd / 12, null, profile)
    : null;
  const netCell = netRescaled?.value != null
    ? formatPriceForDisplay(netRescaled.value, profile)
    : "—";

  const coverageCell = vendor.no_pricing_data
    ? "—"
    : `${vendor.mandatory_pct}% (${vendor.mandatory_covered_in_base}/${vendor.mandatory_total})`;

  // Source + freshness: backend stamps `year1_source` (psg_package_bundled /
  // website_granular / website_software_only / no_pricing_data). When
  // available, also surface the extracted_at timestamp.
  const sourceLabel = SOURCE_LABEL[vendor.year1_source] || vendor.year1_source;
  const extractedAt = vendor.extracted_at;
  const sourceUrl = vendor.source_url;

  return (
    <tr className={vendor.no_pricing_data ? "pcp-row-no-data" : ""}>
      <td>
        <strong>{vendor.name}</strong>
        <div className={`pcp-tier-badge pcp-tier-${vendor.tier}`}>
          {TIER_LABEL[vendor.tier]}
        </div>
      </td>
      <td>
        <span className="pcp-type-badge">{TYPE_LABEL[vendor.vendor_type] || vendor.vendor_type}</span>
      </td>
      <td>
        {vendor.base_plan_name ? (
          <>
            <div className="pcp-plan-name">{vendor.base_plan_name}</div>
            {vendor.base_price_label && (
              <div className="pcp-uom" title={`Quoted unit (verbatim from source): ${vendor.base_price_label}`}>
                {vendor.base_price_label}
              </div>
            )}
          </>
        ) : (
          <span className="muted">—</span>
        )}
      </td>
      <td className="num">
        <strong title={vendor.base_price_label ? `Quoted as: ${vendor.base_price_label}` : undefined}>{yearTotalCell}</strong>
        {rescaled.scaled && (
          <div className="muted small pcp-rescale-note" title={rescaled.label}>↺ {rescaled.label}</div>
        )}
        {breakdown && !isBundled && (breakdown.software_year_sgd || breakdown.ps_one_time_sgd || breakdown.training_one_time_sgd) && (
          <div className="muted small pcp-breakdown">
            sw {formatComponent(breakdown.software_year_sgd, profile)}
            {" · "}
            ps {formatComponent(breakdown.ps_one_time_sgd, profile)}
            {" · "}
            tr {formatComponent(breakdown.training_one_time_sgd, profile)}
          </div>
        )}
        {isBundled && breakdown?.psg_package_name && (
          <div className="muted small pcp-pkg">
            pkg: {breakdown.psg_package_name}
            {breakdown.psg_period === "year_1" && <span className="pcp-period-chip"> year-1</span>}
            {breakdown.psg_period === "one_time" && <span className="pcp-period-chip"> one-time</span>}
          </div>
        )}
      </td>
      <td className="num">{netCell}</td>
      <td className="num">
        {!vendor.no_pricing_data && (
          <div className={`pcp-coverage-pill ${coverageBand(vendor.mandatory_pct)}`}>
            {coverageCell}
          </div>
        )}
      </td>
      <td className="num">
        {vendor.add_on_caps.length > 0 ? vendor.add_on_caps.length : <span className="muted">—</span>}
      </td>
      <td>
        <span className={`pcp-source pcp-source-${vendor.year1_source}`}>
          {sourceLabel}
        </span>
        {extractedAt && (
          <div className="muted xs" title={extractedAt}>
            {new Date(extractedAt).toLocaleDateString("en-SG")}
          </div>
        )}
        {sourceUrl && (
          <a href={sourceUrl} target="_blank" rel="noopener noreferrer" className="pcp-source-link" title={sourceUrl}>
            ↗
          </a>
        )}
      </td>
    </tr>
  );
}

/** Apply currency + period to a single component value (Year-1 SGD).
 *  Used for the sw/ps/tr breakdown cells inside the Year-1 column. */
function formatComponent(value: number | null | undefined, profile: PricingProfile): string {
  if (value == null) return "—";
  const monthsByPeriod = { monthly: 1 / 12, annual: 1, "3yr_tco": 3 };
  let v = value * monthsByPeriod[profile.period];
  if (profile.currency === "USD") v = v / 1.35;
  return formatPriceForDisplay(v, profile);
}

function coverageBand(pct: number): string {
  if (pct >= 80) return "ok";
  if (pct >= 50) return "partial";
  if (pct === 0) return "muted";
  return "fail";
}
