import {
  DndContext,
  PointerSensor,
  KeyboardSensor,
  closestCenter,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import {
  SortableContext,
  arrayMove,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { useMemo } from "react";
import type { Capability } from "../types/canonical";
import { useModuleState } from "../contexts/ModuleStateContext";
import { CapRow } from "./CapRow";
import { ReorderStatus } from "./ReorderStatus";
import "./Type2Umbrella.css";

interface Props {
  moduleId: string;
  moduleSlug: string;
  umbrellaKey: string;          // e.g. "required:all", "preferred:procurement"
  seq: string;
  title: string;
  /** Umbrella-level IMDA-format question that introduces the cap list.
   *  Renders below the title in italic. e.g. "Does your finance module
   *  provide the following functions?" Matches the Type 2 spec in
   *  docs/imda_checklist_formats.md. Optional — when missing, the
   *  umbrella renders without an introductory line (back-compat). */
  umbrellaQuestion?: string;
  tierLabel: string;
  tierClass: "mandatory" | "preferred" | "advanced";
  caps: Capability[];
  multiSelect: boolean;
  signedInEmail?: string;
  /** Mandatory-tier umbrella clusters for this module (multi-core only).
   *  Threaded to each CapRow so the inline CapEditor can surface a
   *  picker for Mandatory caps. */
  requiredClusters?: Array<{ id: string; name: string }>;
  /** This umbrella's own cluster id — when set, every cap rendered in
   *  this umbrella ships with `currentClusterId` = this. _other / tail
   *  caps get `_other` so the picker prefill matches step19's view. */
  currentClusterId?: string;
}

/**
 * Apply user-driven cap order from the cloud's `cap_order` map. Order maps to
 * a position within this umbrella; caps not yet in the map (new caps after a
 * pipeline change) fall to the tail in canonical order.
 */
function applyOrder(caps: Capability[], orderedIds: string[] | undefined): Capability[] {
  if (!orderedIds || orderedIds.length === 0) return caps;
  const byId = new Map(caps.map(c => [c.id, c]));
  const seen = new Set<string>();
  const out: Capability[] = [];
  for (const id of orderedIds) {
    const cap = byId.get(id);
    if (cap) { out.push(cap); seen.add(id); }
  }
  for (const c of caps) if (!seen.has(c.id)) out.push(c);
  return out;
}

export function Type2Umbrella({
  moduleId, moduleSlug, umbrellaKey, seq, title, umbrellaQuestion, tierLabel, tierClass,
  caps, multiSelect, signedInEmail, requiredClusters, currentClusterId,
}: Props) {
  const { capOrder, userCapOrder, publishedCapOrder, setCapOrderForUmbrella } = useModuleState();
  const orderedCaps = useMemo(
    () => applyOrder(caps, capOrder[umbrellaKey]),
    [caps, capOrder, umbrellaKey],
  );
  // "Reorder pending" if the user has a draft for this umbrella that
  // hasn't been published yet. (Empty list = explicit user choice to
  // clear; still counts as pending.)
  const reorderPending = userCapOrder[umbrellaKey] !== undefined;
  // Per-cap published-index map for the "(was #N)" chip — only meaningful
  // when there's a reorder pending AND we have published order to diff against.
  const publishedIndexByCapId = useMemo(() => {
    const m = new Map<string, number>();
    const pub = publishedCapOrder[umbrellaKey];
    if (Array.isArray(pub)) {
      pub.forEach((id, idx) => m.set(id, idx + 1));
    }
    return m;
  }, [publishedCapOrder, umbrellaKey]);

  const sensors = useSensors(
    useSensor(PointerSensor, {
      // Require pointer to move 6px before drag fires — prevents accidental
      // drags when the user just wants to click ✎ or check a box.
      activationConstraint: { distance: 6 },
    }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  if (orderedCaps.length === 0) return null;

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    const ids = orderedCaps.map(c => c.id);
    const oldIndex = ids.indexOf(String(active.id));
    const newIndex = ids.indexOf(String(over.id));
    if (oldIndex === -1 || newIndex === -1) return;
    const next = arrayMove(ids, oldIndex, newIndex);
    setCapOrderForUmbrella(umbrellaKey, next);
  };

  return (
    <div className={`t2-umbrella t2-${tierClass}${reorderPending ? " t2-umbrella-reorder-pending" : ""}`} data-umbrella-key={umbrellaKey}>
      <div className="t2-row-head">
        <span className="t2-row-id">{moduleId}.{seq}</span>
        <span className="t2-row-title">{title}</span>
        <span className={`t2-row-tier tier-${tierClass === "mandatory" ? "mandatory" : tierClass}`}>{tierLabel}</span>
        <ReorderStatus umbrellaKey={umbrellaKey} />
        {reorderPending && (
          <span
            className="t2-reorder-pending-pill"
            title="You've reordered this umbrella but haven't published yet. Hit Publish in the bottom-right to commit. Caps with a 'was #N' chip show their previous position."
          >
            ↕ Reorder pending
          </span>
        )}
      </div>
      {umbrellaQuestion && (
        <p className="t2-umbrella-question">{umbrellaQuestion}</p>
      )}
      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleDragEnd}
      >
        <SortableContext
          items={orderedCaps.map(c => c.id)}
          strategy={verticalListSortingStrategy}
        >
          <ol className="t2-bullet-list">
            {orderedCaps.map((c, i) => {
              const pubIdx = publishedIndexByCapId.get(c.id);
              return (
                <CapRow
                  key={c.id}
                  cap={c}
                  index={i + 1}
                  // Only surface the "was #N" hint when there IS a pending
                  // reorder AND the cap actually moved relative to published.
                  // Caps that stayed put, or new caps that have no published
                  // baseline, get no chip — keeps the signal noise-free.
                  publishedIndex={reorderPending && pubIdx !== undefined && pubIdx !== i + 1 ? pubIdx : undefined}
                  multiSelect={multiSelect}
                  module={moduleSlug}
                  signedInEmail={signedInEmail}
                  requiredClusters={requiredClusters}
                  currentClusterId={currentClusterId}
                />
              );
            })}
          </ol>
        </SortableContext>
      </DndContext>
    </div>
  );
}
