import { useEffect, useState } from "react";
import { api, type Me } from "./api";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import type { EditorRole } from "./role";

/**
 * One source of truth for "what should the SPA render right now?" — across
 * both v1 (CF Worker /api/me) and v2 (AuthContext + users.json).
 *
 * Priority:
 *   1. AuthContext.previewRole — when editor/admin has clicked
 *      "Preview as viewer". Lets them see the read-only UI without
 *      signing out. Does NOT affect actual API permissions — server-side
 *      auth uses the real token regardless.
 *   2. v2: app_role straight off useAuth().user
 *   3. v1: api.me() result (lazy first-load).
 *
 * Returns the role string ("admin" / "editor" / "viewer") or undefined
 * while loading. Use with canEdit() / canPublish() / isAdmin() from
 * ./role.ts for the actual permission checks.
 */
export function useEffectiveRole(): EditorRole {
  const { user: ghUser, previewRole } = useAuth();
  const [me, setMe] = useState<Me | null>(null);

  useEffect(() => {
    if (GITHUB_NATIVE) return;
    let cancelled = false;
    api.me().then(m => { if (!cancelled) setMe(m); }).catch(() => {});
    return () => { cancelled = true; };
  }, []);

  // Preview override wins when set (UI-only — server doesn't see it).
  if (previewRole) return previewRole as EditorRole;

  if (GITHUB_NATIVE) {
    return ghUser?.app_role as EditorRole;
  }
  return (me?.role as EditorRole) ?? undefined;
}

/** True iff the user's actual role differs from the role they're previewing
 *  as — surface this in a banner so they remember the override is active. */
export function useIsInPreview(): boolean {
  const { user: ghUser, previewRole } = useAuth();
  if (!previewRole) return false;
  const actual = GITHUB_NATIVE ? ghUser?.app_role : undefined;
  return !!actual && actual !== previewRole;
}
