import { useState } from "react";
import type { Capability, SmeTier } from "../types/canonical";
import type { DraftFields } from "../lib/api";
import { useDrafts } from "../contexts/DraftsContext";
import { useAuth } from "../contexts/AuthContext";
import { clearAddition } from "../lib/additions";
import "./CapEditor.css";

/** A cap is "user-added" when its ID was minted by AddRequirementModal —
 *  format `<prefix>.user_<slug>_<rand4>`. Pipeline-derived caps never
 *  contain the literal `user_` segment, so this single check is enough. */
function isUserAddedCap(capId: string): boolean {
  return /\.user_/.test(capId);
}

const TIERS: SmeTier[] = ["required", "preferred", "advanced", "deleted"];

interface Props {
  module: string;
  cap: Capability;
  /** Mandatory-tier umbrella clusters for this module (from canonical's
   *  `preferred_clusters.required.clusters`). Empty/null when the module
   *  is single-core. When present (mfg / asset / sc / hr today) and the
   *  cap's tier is `required`, the editor surfaces an umbrella picker
   *  prefilled with `currentClusterId`. */
  requiredClusters?: Array<{ id: string; name: string }>;
  /** Current cluster id the cap belongs to (resolved by the parent from
   *  buildClusters). Falsy means the cap is in the synthetic `_other`
   *  tail. The picker is gated on tier still being `required` at save
   *  time — switching to Preferred/Advanced clears any pending pick. */
  currentClusterId?: string;
  onClose: () => void;
}

/**
 * Inline editor for a single cap. Pre-fills from the active draft (cloud
 * cache) if any, else from canonical. Save flushes to the Worker via the
 * DraftsContext optimistic-update path; Discard deletes the cloud row.
 */
export function CapEditor({
  module, cap, requiredClusters, currentClusterId, onClose,
}: Props) {
  const { getDraftFields, saveDraft, clearDraft } = useDrafts();
  const { user, auth } = useAuth();
  const draft = getDraftFields(module, cap.id);
  const userAdded = isUserAddedCap(cap.id);

  // Initial form state — draft fields > canonical baseline.
  const [name, setName] = useState<string>(
    draft?.name !== undefined ? draft.name : cap.name || "",
  );
  const [description, setDescription] = useState<string>(
    draft?.description !== undefined ? draft.description : (cap.description || ""),
  );
  const [smeTier, setSmeTier] = useState<SmeTier>(
    (draft?.sme_tier !== undefined ? draft.sme_tier : (cap.sme_tier || "preferred")) as SmeTier,
  );
  const [inChecklist, setInChecklist] = useState<boolean>(
    draft?.in_checklist !== undefined ? draft.in_checklist : (cap.in_checklist !== false),
  );
  const vq = cap.vendor_questions || {};
  const [questionTerse, setQuestionTerse] = useState<string>(
    draft?.vendor_question_terse !== undefined ? draft.vendor_question_terse : (vq.question_terse || ""),
  );
  const [question, setQuestion] = useState<string>(
    draft?.vendor_question !== undefined ? draft.vendor_question : (vq.question || ""),
  );
  const [questionT2, setQuestionT2] = useState<string>(
    draft?.vendor_question_t2 !== undefined ? draft.vendor_question_t2 : (vq.question_t2 || ""),
  );
  const [note, setNote] = useState<string>(draft?.note || "");
  // Umbrella picker — only meaningful for Mandatory tier on multi-core
  // modules. Prefilled in priority: pending draft override > cap's
  // current cluster (resolved by the parent from buildClusters).
  const [clusterId, setClusterId] = useState<string>(
    draft?.cluster_id !== undefined ? draft.cluster_id : (currentClusterId || ""),
  );

  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Same gate as AddRequirementModal — Preferred/Advanced are single-
  // cluster everywhere, so hiding the picker matches step19's scope.
  const hasMultiCoreClusters = (requiredClusters?.length || 0) > 0;
  const showClusterPicker = smeTier === "required" && hasMultiCoreClusters;

  const buildEdit = (): DraftFields => {
    const out: DraftFields = {};
    if (name !== (cap.name || "")) out.name = name;
    if (description !== (cap.description || "")) out.description = description;
    if (smeTier !== cap.sme_tier) out.sme_tier = smeTier;
    const baseInChecklist = cap.in_checklist !== false;
    if (inChecklist !== baseInChecklist) out.in_checklist = inChecklist;
    if (questionTerse !== (vq.question_terse || "")) out.vendor_question_terse = questionTerse;
    if (question !== (vq.question || "")) out.vendor_question = question;
    if (questionT2 !== (vq.question_t2 || "")) out.vendor_question_t2 = questionT2;
    if (note.trim().length > 0) out.note = note.trim();
    // Umbrella override — only ships when the picker is visible AND
    // changed from the cap's current cluster. Empty pick (""=Other tail)
    // serialises as `_other` so step19 explicitly moves the cap into the
    // synthetic tail rather than leaving the override ambiguous.
    if (showClusterPicker) {
      const baseCluster = currentClusterId || "";
      if (clusterId !== baseCluster) {
        out.cluster_id = clusterId || "_other";
      }
    }
    return out;
  };

  const handleSave = async () => {
    setError(null);
    const edit = buildEdit();
    if (Object.keys(edit).length === 0) {
      onClose();
      return;
    }
    setSaving(true);
    try {
      // Auto-demote: required + in_checklist:false is nonsensical → flip tier.
      if (edit.in_checklist === false && smeTier === "required") {
        edit.sme_tier = "preferred";
      }
      await saveDraft(module, cap.id, edit);
      onClose();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setSaving(false);
    }
  };

  const handleDiscard = async () => {
    setError(null);
    setSaving(true);
    try {
      await clearDraft(module, cap.id);
      onClose();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setSaving(false);
    }
  };

  /** Delete a user-added cap entirely. Writes a tombstone YAML to the
   *  user's draft branch — on publish, step18 ignores tombstoned
   *  additions and the cap never lands in canonical. The pipeline can
   *  also delete it from any prior publish via the same mechanism. */
  const handleDeleteUserAdded = async () => {
    if (!auth || !user) {
      setError("Sign in to discard a user-added requirement.");
      return;
    }
    if (!confirm(`Delete this user-added requirement?\n\n${cap.name}\n\nA tombstone will be written to your draft branch; the cap is removed on next publish.`)) {
      return;
    }
    setError(null);
    setSaving(true);
    try {
      // Clear any in-flight D1 draft for this cap first so the publish
      // flow doesn't carry stale edits forward into the tombstoned addition.
      try { await clearDraft(module, cap.id); } catch { /* no draft is fine */ }
      await clearAddition(auth, user.login, module, cap.id);
      onClose();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="cap-editor-spa">
      <label>
        <span className="cap-editor-label">Name</span>
        <input
          type="text"
          value={name}
          onChange={e => setName(e.target.value)}
          disabled={saving}
        />
      </label>

      <label>
        <span className="cap-editor-label">Description</span>
        <textarea
          rows={2}
          value={description}
          onChange={e => setDescription(e.target.value)}
          disabled={saving}
        />
      </label>

      <label>
        <span className="cap-editor-label">SME tier</span>
        <select
          value={smeTier}
          onChange={e => setSmeTier(e.target.value as SmeTier)}
          disabled={saving}
        >
          {TIERS.map(t => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>
      </label>

      <label className="cap-editor-checkbox-row">
        <input
          type="checkbox"
          checked={inChecklist}
          onChange={e => setInChecklist(e.target.checked)}
          disabled={saving}
        />
        <span>
          <b>Include in checklist</b> — uncheck to flag as Optional / Add-on
        </span>
      </label>

      {showClusterPicker && (
        <label>
          <span className="cap-editor-label">Umbrella (multi-core split)</span>
          <select
            value={clusterId}
            onChange={e => setClusterId(e.target.value)}
            disabled={saving}
          >
            <option value="">— Other (synthetic tail) —</option>
            {(requiredClusters || []).map(c => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>
          <div className="cap-editor-hint">
            Move this cap into a different Mandatory umbrella. Override is
            published to <code>data/manual_cluster_assignments.yaml</code> and
            consumed by step19 at canonicalise.
          </div>
        </label>
      )}
      {smeTier !== "required" && hasMultiCoreClusters && (
        <div className="cap-editor-info">
          ℹ Umbrella picker only appears on Mandatory tier — Preferred and Advanced are single-cluster on this module.
        </div>
      )}

      <label>
        <span className="cap-editor-label">Type 2 bullet (umbrella summary)</span>
        <textarea
          rows={2}
          value={questionT2}
          onChange={e => setQuestionT2(e.target.value)}
          disabled={saving}
          placeholder="8–15 word verb-led summary, e.g. 'Post journal entries to a multi-currency chart of accounts'"
        />
      </label>

      <label>
        <span className="cap-editor-label">Type 1.1 question (terse)</span>
        <textarea
          rows={2}
          value={questionTerse}
          onChange={e => setQuestionTerse(e.target.value)}
          disabled={saving}
          placeholder="(blank = falls back to verbose Type 1)"
        />
      </label>

      <label>
        <span className="cap-editor-label">Type 1 question (verbose)</span>
        <textarea
          rows={3}
          value={question}
          onChange={e => setQuestion(e.target.value)}
          disabled={saving}
        />
      </label>

      <label>
        <span className="cap-editor-label">Note (override rationale, captured in YAML)</span>
        <textarea
          rows={2}
          value={note}
          onChange={e => setNote(e.target.value)}
          disabled={saving}
          placeholder="e.g. 'Demoted to Preferred — many SMEs handle expenses outside ERP'"
        />
      </label>

      {error && <div className="cap-editor-error">Save failed: {error}</div>}

      <div className="cap-editor-actions">
        <button
          className="cap-editor-save"
          onClick={handleSave}
          disabled={saving}
        >
          {saving ? "Saving…" : "Save & close"}
        </button>
        <button
          className="cap-editor-cancel"
          onClick={onClose}
          disabled={saving}
        >
          Close
        </button>
        {draft && (
          <button
            className="cap-editor-discard"
            onClick={handleDiscard}
            disabled={saving}
          >
            Discard draft
          </button>
        )}
        {userAdded && (
          <button
            type="button"
            className="cap-editor-delete-user-added"
            onClick={handleDeleteUserAdded}
            disabled={saving}
            title="Delete this user-added requirement (writes a tombstone, removed on next publish)"
          >
            Delete user-added cap
          </button>
        )}
      </div>
      {userAdded && (
        <div className="cap-editor-hint" style={{ marginTop: 6 }}>
          ℹ This cap was added via the requirements modal — it can be deleted
          entirely. Pipeline-derived caps can only be flagged Deleted via the
          tier dropdown.
        </div>
      )}
    </div>
  );
}
