import { useMemo } from "react";
import type { PricingDetailPlan } from "../lib/pricingData";
import { buildFeatureMatrix, type CellKind } from "../lib/featureMatrix";
import "./FeaturePlanMatrix.css";

interface Props {
  plans: PricingDetailPlan[];
}

/**
 * Per-vendor feature × plan matrix. Replaces the legacy "stacked vertical
 * plan list" inside VendorDetailExpansion with a side-by-side comparison.
 *
 * Renders nothing when the vendor has no parsed plans (caller should hide
 * the section entirely in that case).
 */
export function FeaturePlanMatrix({ plans }: Props) {
  const matrix = useMemo(() => buildFeatureMatrix(plans), [plans]);

  if (matrix.plans.length === 0 || matrix.rows.length === 0) {
    return (
      <p className="muted small fpm-empty">
        No structured feature breakdown available for this vendor yet.
      </p>
    );
  }

  return (
    <div className="fpm-wrap">
      <table className="fpm-table">
        <thead>
          <tr>
            <th className="fpm-feature-h">Feature</th>
            {matrix.plans.map(p => (
              <th key={p.id} className="fpm-plan-h">
                <div className="fpm-plan-name">{p.name}</div>
                <div className="fpm-plan-price">{p.priceDisplay}</div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {matrix.rows.map((row, idx) => (
            <tr key={idx} className={row.universal ? "fpm-row-universal" : ""}>
              <td className="fpm-feature">{row.feature}</td>
              {row.cells.map((c, j) => (
                <td key={j} className={`fpm-cell fpm-cell-${c}`} title={cellTitle(c)}>
                  <span className="fpm-cell-mark">{cellGlyph(c)}</span>
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
      <p className="muted small fpm-legend">
        ✓ included · <span className="fpm-addon-glyph">+</span> add-on / paid extra · — not in this plan
      </p>
    </div>
  );
}

function cellGlyph(c: CellKind): string {
  switch (c) {
    case "included": return "✓";
    case "add_on":   return "+";
    case "absent":   return "—";
  }
}

function cellTitle(c: CellKind): string {
  switch (c) {
    case "included": return "Included in this plan";
    case "add_on":   return "Available as a paid add-on";
    case "absent":   return "Not in this plan";
  }
}
