import type { Capability, SectorRelevance } from "../types/canonical";

export const GENERIC = "__generic__" as const;
export type SectorFilter = string | typeof GENERIC | null;

// Mirrors legacy `_isGeneric()` from scripts/templates/canonical/_controls.js.
// `generic` is L1-scoped (locked 2026-04-26): it means "relevant across all
// sectors this MODULE applies to", not "relevant across all 16 PSG sectors".
// The defensive `sectors == {}` fallback handles caps where step 7b hasn't
// produced data yet — we'd rather show them than silently hide.
function isGeneric(sr: SectorRelevance | undefined): boolean {
  if (!sr) return false;
  if (sr.generic === true) return true;
  const sectors = sr.sectors || {};
  if (Object.keys(sectors).length === 0) {
    const verts = (sr as { applicable_verticals?: unknown[] }).applicable_verticals;
    if (!Array.isArray(verts) || verts.length === 0) return true;
  }
  return false;
}

export function capMatchesSector(c: Capability, sector: SectorFilter | undefined): boolean {
  if (sector == null) return true;
  const sr = c.sector_relevance;
  if (sector === GENERIC) return isGeneric(sr);
  if (!sr) return false;
  if (isGeneric(sr)) return true; // generic caps appear in every sector view
  const slot = sr.sectors?.[sector];
  return slot?.relevant === true;
}

export function filterCapsBySector(
  caps: Capability[],
  sector: SectorFilter | undefined,
): Capability[] {
  if (sector == null) return caps;
  return caps.filter(c => capMatchesSector(c, sector));
}
