import { useEffect, useMemo, useState } from "react";
import {
  loadMultiCorePayload,
  type MultiCorePayload,
  type SolutionClassification,
  type CoreDef,
  moduleVerdictBadge,
  solutionVerdictBadge,
} from "../../lib/multiCoreData";
import { TabHelp } from "../TabHelp";
import "./MultiCoreCheckPanel.css";

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

const MULTI_CORE_MODULES = new Set([
  "manufacturing_management",
  "asset_management",
  "supply_chain_and_inventory",
  "human_resources_management",
]);

/**
 * Multi-core validation matrix.
 *
 * Three layers stacked per module:
 *  1. Headline: module verdict (Split validated / Theoretical only /
 *     Boundary mismatch / Data thin) with counts.
 *  2. Solution matrix: rows = PSG solutions, cols = cores. Cells show
 *     coverage (full / partial / none). Per-row badge for verdict.
 *  3. Known-ERP overlay: how reference ERPs (SAP B1, Sage 300, Globe3,
 *     NetSuite, Odoo, etc.) package each core — separate / bundled /
 *     partial / absent.
 *  4. Core-split revisions (when verdict = boundary_mismatch): Haiku-
 *     proposed alternative groupings with backing evidence. Read-only
 *     for review — operator applies to config/preferred_clusters.yaml
 *     manually after deciding.
 */
export function MultiCoreCheckPanel({ modules }: Props) {
  const [payload, setPayload] = useState<MultiCorePayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedModule, setSelectedModule] = useState<string | null>(null);

  useEffect(() => {
    loadMultiCorePayload().then(setPayload).catch(e => setError(String(e?.message || e)));
  }, []);

  const inScopeModules = useMemo(() => {
    return modules.filter(m => MULTI_CORE_MODULES.has(m.slug));
  }, [modules]);

  // Default selection: first module that has classification data.
  useEffect(() => {
    if (!payload || selectedModule) return;
    const first = inScopeModules.find(m => payload.classification[m.slug]);
    if (first) setSelectedModule(first.slug);
  }, [payload, selectedModule, inScopeModules]);

  if (error) return <p>Failed to load multi-core data: {error}</p>;
  if (!payload) return <p className="muted">Loading multi-core validation data…</p>;

  if (inScopeModules.length === 0) {
    return (
      <div className="multi-core-panel">
        <p className="muted">
          No multi-core modules in the current view. The 4 multi-core modules
          (Manufacturing / Asset / Supply Chain / HR) are defined in
          <code>config/preferred_clusters.yaml</code>.
        </p>
      </div>
    );
  }

  return (
    <div className="multi-core-panel">
      <TabHelp hint="Each PSG-listed vendor is classified against each core of multi-core modules (Mfg / Asset / SC / HR). Reference ERPs (SAP B1, Sage 300, etc.) show how the major suites bundle the same functionality, so we can validate whether the multi-core split matches commercial reality.">
        Multi-core validation — does the locked Required-cap split for
        Mfg / Asset / SC / HR match what vendors actually package today?
      </TabHelp>
      <header className="mc-header">
        <h3>Multi-core validation</h3>
        <p className="muted">
          Does the locked Required-cap multi-core split for Mfg / Asset / SC / HR
          match commercial reality? Each PSG solution is classified against each
          core; reference ERPs (SAP B1, Sage 300, etc.) show how the major suites
          package the same functionality.
        </p>
        <nav className="mc-module-tabs">
          {inScopeModules.map(m => {
            const cls = payload.classification[m.slug];
            const total = cls ? Object.keys(cls.classifications || {}).length : 0;
            const isActive = selectedModule === m.slug;
            return (
              <button
                key={m.slug}
                type="button"
                className={`mc-module-tab${isActive ? " active" : ""}`}
                onClick={() => setSelectedModule(m.slug)}
              >
                {m.short} <span className="mc-tab-count">({total})</span>
              </button>
            );
          })}
        </nav>
      </header>

      {selectedModule && (
        <ModuleSection
          moduleSlug={selectedModule}
          moduleName={inScopeModules.find(m => m.slug === selectedModule)?.module_name || selectedModule}
          payload={payload}
        />
      )}
    </div>
  );
}

interface SectionProps {
  moduleSlug: string;
  moduleName: string;
  payload: MultiCorePayload;
}

function ModuleSection({ moduleSlug, moduleName, payload }: SectionProps) {
  const cls = payload.classification[moduleSlug];
  const erp = payload.erp_overlay[moduleSlug];
  const prop = payload.proposals[moduleSlug];
  const [expandedId, setExpandedId] = useState<string | null>(null);

  if (!cls) {
    return (
      <p className="muted">
        No classification data yet for <strong>{moduleName}</strong>. Run{" "}
        <code>python3 scripts/classify_psg_solutions_per_core.py --module {moduleSlug}</code>{" "}
        to generate.
      </p>
    );
  }

  const verdict = prop?.verdict;
  const verdictBadge = verdict ? moduleVerdictBadge(verdict) : null;
  const cores = cls.cores;
  const classifications = Object.entries(cls.classifications || {});
  const totalCount = classifications.length;

  const counts = classifications.reduce((acc, [_, c]) => {
    const v = c.verdict || "unclassified";
    acc[v] = (acc[v] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return (
    <section className="mc-section">
      <div className="mc-headline">
        <h4>{moduleName}</h4>
        {verdictBadge && (
          <span className={`mc-verdict-badge tone-${verdictBadge.tone}`}>
            {verdictBadge.label}
          </span>
        )}
        <div className="mc-counts">
          <CountChip label="Single core" count={counts["single_core_full"] || 0} tone="good" />
          <CountChip label="Full suite" count={counts["multi_core_full"] || 0} tone="neutral" />
          <CountChip label="Partial" count={counts["partial_only"] || 0} tone="warn" />
          <CountChip label="Out of scope" count={counts["unclassified"] || 0} tone="muted" />
          <span className="mc-total">of {totalCount}</span>
        </div>
      </div>

      {cls.rationale && (
        <div className="mc-rationale">
          <h5 className="mc-rationale-title">Why this split?</h5>
          {cls.rationale.split(/\n\s*\n/).map((para, i) => (
            <p key={i}>{para.replace(/\n/g, " ")}</p>
          ))}
          <p className="mc-rationale-foot">
            Source: <code>config/preferred_clusters.yaml</code> · {cores.length}-core split for Mandatory tier.
            Validation matrix below tests this split against {classifications.length} PSG-approved
            solutions.
          </p>
        </div>
      )}

      <div className="mc-legend">
        <span className="mc-legend-title">Cell legend:</span>
        <span><span className="mc-cell-icon" style={{ color: "#16a34a" }}>✓</span> all Mandatory caps in this core covered</span>
        <span><span className="mc-cell-icon" style={{ color: "#ca8a04" }}>~</span> some caps covered (partial)</span>
        <span><span className="mc-cell-icon" style={{ color: "#cbd5e1" }}>—</span> none covered (out of scope)</span>
        <span className="mc-legend-hint">Click any solution row to expand into per-cap heatmap.</span>
      </div>

      <table className="mc-matrix">
        <thead>
          <tr>
            <th>Solution</th>
            {cores.map(c => (
              <th key={c.id}>
                <div className="mc-core-name">{c.name}</div>
                <div className="mc-core-meta">{c.cap_count} caps</div>
              </th>
            ))}
            <th>Verdict</th>
          </tr>
        </thead>
        <tbody>
          {sortClassifications(classifications).map(([psg_id, c]) => (
            <SolutionRow
              key={psg_id}
              psgId={psg_id}
              c={c}
              cores={cores}
              expanded={expandedId === psg_id}
              onToggle={() => setExpandedId(prev => prev === psg_id ? null : psg_id)}
            />
          ))}
          {classifications.length === 0 && (
            <tr><td colSpan={cores.length + 2} className="muted">No classifications yet.</td></tr>
          )}
        </tbody>
        {erp && Object.keys(erp.erps || {}).length > 0 && (
          <tbody className="mc-erp-rows">
            <tr className="mc-section-divider">
              <td colSpan={cores.length + 2}>
                Known reference ERPs · how they package these cores (web-search benchmark)
              </td>
            </tr>
            {Object.entries(erp.erps).map(([erpId, data]) => (
              <ErpRow key={erpId} erpId={erpId} data={data} cores={cores} />
            ))}
          </tbody>
        )}
      </table>

      {prop?.proposed_revisions && prop.proposed_revisions.length > 0 && (
        <div className="mc-proposals">
          <h5>Proposed core-split revisions ({prop.proposed_revisions.length})</h5>
          <p className="muted">
            Generated when the current split's <em>partial_only</em> ratio
            exceeds 40%. Read-only — apply to <code>config/preferred_clusters.yaml</code>
            manually after review.
          </p>
          {prop.proposed_revisions.map((rev, i) => (
            <div key={i} className="mc-proposal">
              <h6>Option {i + 1}</h6>
              <p>{rev.rationale}</p>
              <div className="mc-proposal-cores">
                {rev.cores.map(core => (
                  <div key={core.id} className="mc-proposal-core">
                    <strong>{core.name}</strong>
                    <span className="muted"> ({core.id})</span>
                    <ul>
                      {core.caps.map(cap => <li key={cap}>{cap}</li>)}
                    </ul>
                  </div>
                ))}
              </div>
              {rev.backing_evidence.length > 0 && (
                <details className="mc-evidence">
                  <summary>Backing evidence ({rev.backing_evidence.length})</summary>
                  <ul>
                    {rev.backing_evidence.map((e, j) => (
                      <li key={j}>
                        <code>{e.psg_id}</code>: {e.reason}
                      </li>
                    ))}
                  </ul>
                </details>
              )}
            </div>
          ))}
        </div>
      )}
    </section>
  );
}

interface SolutionRowProps {
  psgId: string;
  c: SolutionClassification;
  cores: CoreDef[];
  expanded: boolean;
  onToggle: () => void;
}

function SolutionRow({ psgId, c, cores, expanded, onToggle }: SolutionRowProps) {
  const verdictBadge = solutionVerdictBadge(c.verdict);
  return (
    <>
      <tr
        className={`mc-row mc-verdict-${c.verdict} mc-row-clickable${expanded ? " mc-row-expanded" : ""}`}
        onClick={onToggle}
        title="Click to expand into per-cap heatmap"
      >
        <td>
          <code>{psgId}</code>
          <div><strong>{c.vendor_name}</strong></div>
          <div className="muted">{c.solution_name}</div>
        </td>
        {cores.map(core => {
          const cell = c.by_core?.[core.id];
          const v = cell?.verdict || "none";
          const totalCaps = core.cap_count || (core.caps?.length ?? 0);
          const coveredN = cell?.covered_caps?.length ?? 0;
          return (
            <td key={core.id} className={`mc-cell mc-${v}`}>
              <span className="mc-cell-icon">
                {v === "full" ? "✓" : v === "partial" ? "~" : "—"}
              </span>
              {totalCaps > 0 && v !== "none" && (
                <div className="mc-cell-frac">{coveredN}/{totalCaps}</div>
              )}
            </td>
          );
        })}
        <td>
          <span className={`mc-verdict-badge tone-${verdictBadge.tone}`}>
            {verdictBadge.label}
          </span>
        </td>
      </tr>
      {expanded && (
        <tr className="mc-row-drill">
          <td colSpan={cores.length + 2}>
            <CapHeatmap c={c} cores={cores} />
          </td>
        </tr>
      )}
    </>
  );
}

/** Per-cap heatmap inside an expanded SolutionRow. Each core's caps are
 *  listed individually with covered / partial / not-covered status. */
function CapHeatmap({ c, cores }: { c: SolutionClassification; cores: CoreDef[] }) {
  return (
    <div className="mc-drill">
      <div className="mc-drill-summary muted">
        Per-cap verdict (Mandatory caps in this module's locked split).
        Hover any cell for Haiku's reasoning.
      </div>
      <div className="mc-drill-cores">
        {cores.map(core => {
          const cell = c.by_core?.[core.id];
          const coveredSet = new Set(cell?.covered_caps || []);
          const partialSet = new Set(cell?.partial_caps || []);
          const allCaps = core.caps || [];
          if (allCaps.length === 0) {
            return (
              <div key={core.id} className="mc-drill-core">
                <h6>{core.name}</h6>
                <div className="muted small">
                  Cap list not exposed yet (regenerate classifier output).
                </div>
              </div>
            );
          }
          return (
            <div key={core.id} className="mc-drill-core">
              <h6>{core.name} <span className="muted small">({allCaps.length} caps)</span></h6>
              <ul className="mc-cap-list">
                {allCaps.map(capId => {
                  const status = coveredSet.has(capId) ? "full"
                    : partialSet.has(capId) ? "partial" : "none";
                  return (
                    <li key={capId} className={`mc-cap-pill mc-cap-${status}`}>
                      <span className="mc-cell-icon">
                        {status === "full" ? "✓" : status === "partial" ? "~" : "—"}
                      </span>
                      <code>{capId}</code>
                    </li>
                  );
                })}
              </ul>
              {cell?.reason && (
                <div className="mc-drill-reason muted small">
                  <strong>Haiku rationale:</strong> {cell.reason}
                </div>
              )}
            </div>
          );
        })}
      </div>
      {c.summary_reason && (
        <div className="mc-drill-summary-reason small">
          <strong>Overall:</strong> {c.summary_reason}
        </div>
      )}
    </div>
  );
}

/** Reference-ERP row — same column structure as solution rows so the
 *  user can compare directly. Cell shows the packaging model (separate
 *  module, bundled, partial, absent) instead of a coverage tick. */
function ErpRow({ erpId, data, cores }: { erpId: string; data: { name: string; tier: string; packaging_per_core?: Record<string, { model?: string; sku_name?: string; pricing_unit?: string; notes?: string }> }; cores: CoreDef[] }) {
  return (
    <tr className="mc-erp-row">
      <td>
        <code>{erpId}</code>
        <div><strong>{data.name}</strong></div>
        <div className="muted">{data.tier}</div>
      </td>
      {cores.map(core => {
        const cell = data.packaging_per_core?.[core.id];
        const model = cell?.model || "unknown";
        return (
          <td key={core.id} className={`mc-erp-cell mc-${model}`}>
            <span className={`mc-packaging-cell mc-${model}`}>{model}</span>
            {cell?.sku_name && <div className="mc-sku">{cell.sku_name}</div>}
            {cell?.notes && (
              <div className="mc-notes muted" title={cell.notes}>
                {cell.notes.length > 70 ? cell.notes.slice(0, 70) + "…" : cell.notes}
              </div>
            )}
          </td>
        );
      })}
      <td>
        <span className="mc-verdict-badge tone-neutral">Reference</span>
      </td>
    </tr>
  );
}

function CountChip({ label, count, tone }: { label: string; count: number; tone: string }) {
  return (
    <span className={`mc-count-chip tone-${tone}`}>
      <strong>{count}</strong> {label}
    </span>
  );
}

function sortClassifications<T extends [string, SolutionClassification]>(rows: T[]): T[] {
  const order: Record<string, number> = {
    single_core_full: 0,
    multi_core_full: 1,
    partial_only: 2,
    unclassified: 3,
  };
  return [...rows].sort((a, b) => {
    const oa = order[a[1].verdict] ?? 9;
    const ob = order[b[1].verdict] ?? 9;
    if (oa !== ob) return oa - ob;
    return a[0].localeCompare(b[0]);
  });
}
