import { useState } from "react";
import { Link } from "react-router-dom";
import { MODULES } from "../lib/modules";
import type { UserRole } from "../lib/api";
import "./NavBar.css";

/**
 * Active selector — controls which item is aria-current="page" + visually
 * highlighted. Pass:
 *   "overview"     for the Home tile dashboard
 *   "coverage"     for the Coverage page (was Dashboard)
 *   "methodology"  for the Methodology page (was Stakeholders)
 *   "cap-library"  for the Cap library
 *   "admin-users"  for the Admin · Users page
 *   "admin-health" for the Admin · Health dashboard
 *   "<module-slug>" for any per-module canonical page
 */
type ActiveItem =
  | "overview"
  | "coverage"
  | "methodology"
  | "cap-library"
  | "pricing-library"
  | "admin-users"
  | "admin-health"
  | string;

export interface Props {
  active?: ActiveItem;
  /**
   * Current user's role. When `admin`, the "Admin" nav link is rendered.
   * Worker still gates /api/users; the link is just a UX shortcut so non-admins
   * don't see a dead end.
   */
  role?: UserRole;
  /**
   * v2-only: list of module slugs this user can see. null/undefined =
   * all modules (default). Empty array = no modules. Drives the Modules
   * lane filter when data/_state/users.json scopes the user.
   */
  visibleModules?: string[] | null;
}

// Legacy HTML surfaces — kept reachable via the BUILD tools dropdown until
// they're either ported into the SPA or retired. Each link leaves the SPA.
const BUILD_TOOLS_LINKS: Array<{ label: string; href: string }> = [
  { label: "Use cases (legacy)",   href: "/use_cases.html" },
  { label: "Gap analysis (legacy)", href: "/gap_analysis.html" },
  { label: "Pipeline (legacy)",    href: "/pipeline.html" },
  { label: "Integrations (legacy)", href: "/integrations.html" },
];

function navLinkProps(active: boolean) {
  return {
    className: `topbar-link${active ? " active" : ""}`,
    ...(active ? { "aria-current": "page" as const } : {}),
  };
}

export function NavBar({ active, role, visibleModules }: Props) {
  const [buildOpen, setBuildOpen] = useState(false);
  const isAdmin = role === "admin";
  const isEditorOrAbove = role === "editor" || role === "admin";
  // When visibleModules is null/undefined, show everything (default).
  // When it's an array, filter MODULES to that allow-list.
  const visibleModuleEntries = visibleModules == null
    ? MODULES
    : MODULES.filter(m => visibleModules.includes(m.slug));

  return (
    <nav className="topbar" aria-label="Main navigation">
      {/* Lane 1 — Functions */}
      <div className="topbar-lane topbar-lane-functions">
        <span className="topbar-brand">ERP Mapper</span>

        <Link to="/" {...navLinkProps(active === "overview")}>
          Overview
        </Link>
        <Link to="/dashboard" {...navLinkProps(active === "coverage")}>
          Coverage
        </Link>
        <Link to="/stakeholders" {...navLinkProps(active === "methodology")}>
          Methodology
        </Link>
        {isEditorOrAbove && (
          <Link to="/cap-library" {...navLinkProps(active === "cap-library")}>
            Cap library
          </Link>
        )}
        <Link to="/pricing-library" {...navLinkProps(active === "pricing-library")}>
          Pricing Library
        </Link>
        {isAdmin && (
          <Link to="/admin/health" {...navLinkProps(active === "admin-health")}>
            Health
          </Link>
        )}

        <div className="topbar-spacer" />

        {isAdmin && (
          <div className="topbar-dropdown-wrap">
            <button
              type="button"
              className="topbar-link topbar-dropdown-trigger"
              aria-expanded={buildOpen}
              aria-haspopup="menu"
              onClick={() => setBuildOpen(v => !v)}
              onBlur={() => setTimeout(() => setBuildOpen(false), 120)}
            >
              BUILD tools ▾
            </button>
          {buildOpen && (
            <div className="topbar-dropdown-menu" role="menu">
              {BUILD_TOOLS_LINKS.map(l => (
                <a
                  key={l.href}
                  href={l.href}
                  role="menuitem"
                  className="topbar-dropdown-item"
                >
                  {l.label}
                </a>
              ))}
            </div>
          )}
          </div>
        )}
      </div>

      {/* Lane 2 — Checklist sections (export order: solution → modules →
          cross-module). Smaller font + flex-wrap so we don't horizontally
          scroll when all 14 pills are visible. */}
      <div className="topbar-lane topbar-lane-modules topbar-lane-checklist">
        <span className="topbar-lane-label">Checklist</span>

        <Link to="/solution" {...navLinkProps(active === "solution")} title="Solution-level: compliance baseline + (future) integration capabilities">
          Solution
        </Link>

        {visibleModuleEntries.map(m => (
          <Link
            key={m.slug}
            to={`/canonical/${m.slug}`}
            {...navLinkProps(active === m.slug)}
            title={m.full}
          >
            {m.short}
          </Link>
        ))}
        {visibleModules != null && visibleModuleEntries.length === 0 && (
          <span className="muted small">No modules assigned to you yet.</span>
        )}

        <span className="topbar-lane-sep">·</span>

        <Link to="/ai" {...navLinkProps(active === "ai")} title="AI Features — cross-module">
          AI
        </Link>
        <Link to="/workflows" {...navLinkProps(active === "workflows")} title="End-to-end workflows (O2C, P2P, L2C, H2R, R2R…) across modules">
          Workflows
        </Link>
        <Link to="/integration" {...navLinkProps(active === "integration")} title="Cross-module integration capabilities (master data ownership, sync, reference integrity)">
          Integration
        </Link>
      </div>
    </nav>
  );
}
