/**
 * URL search-param state helpers — replace useState for state that should
 * survive browser back/forward + reload + share-link. Built on react-router
 * v6's useSearchParams; works under HashRouter.
 *
 * Use for: top-level navigation (perspective tab, sub-tab, picked sol cat).
 * Don't use for: ephemeral UI state that doesn't deserve a history entry
 * (e.g. accordion expand state — sessionStorage handles that better).
 */

import { useCallback } from "react";
import { useSearchParams } from "react-router-dom";

/**
 * Returns [value, setValue] for a single URL search param. The setter merges
 * with the existing param set so other params survive. Push-mode by default
 * so each change creates a back-button entry.
 *
 * Pass `defaultValue` to coalesce missing/empty params. Pass `replace: true`
 * to update the URL without adding a history entry — useful for filter/sort
 * state that the user toggles often.
 */
export function useUrlParam<T extends string>(
  key: string,
  defaultValue: T,
  options: { replace?: boolean } = {},
): [T, (next: T) => void] {
  const [params, setParams] = useSearchParams();
  const raw = params.get(key);
  const value = (raw == null || raw === "" ? defaultValue : raw) as T;
  const setValue = useCallback(
    (next: T) => {
      const merged = new URLSearchParams(params);
      if (next === defaultValue || next === "") {
        merged.delete(key);
      } else {
        merged.set(key, next);
      }
      setParams(merged, { replace: !!options.replace });
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [params, key, defaultValue, options.replace],
  );
  return [value, setValue];
}

/**
 * Reads + writes a JSON-serialisable value from sessionStorage. Returns
 * [value, setValue]. Lazy initialises from storage; persists on every set.
 *
 * Used for accordion expand state, scroll position — survives in-page nav
 * but flushes when the browser tab closes (clean slate per session, no
 * cross-tab pollution).
 */
export function readSession<T>(key: string, fallback: T): T {
  if (typeof sessionStorage === "undefined") return fallback;
  try {
    const raw = sessionStorage.getItem(key);
    if (raw == null) return fallback;
    return JSON.parse(raw) as T;
  } catch {
    return fallback;
  }
}

export function writeSession<T>(key: string, value: T): void {
  if (typeof sessionStorage === "undefined") return;
  try {
    sessionStorage.setItem(key, JSON.stringify(value));
  } catch {
    // Quota exceeded or storage disabled — silent fail, state simply
    // won't persist across reloads.
  }
}
