import { useId } from "react";
import type { AiFeatureExample, AiFeaturesResponse } from "../lib/aiFeatures";
import "./AiFeaturesUmbrella.css";

export interface Props {
  umbrellaQuestion: string;
  examples: AiFeatureExample[];
  response: AiFeaturesResponse;
  onChange: (next: AiFeaturesResponse) => void;
}

export function AiFeaturesUmbrella({ umbrellaQuestion, examples, response, onChange }: Props) {
  const checked = new Set(response.checkedTitles);
  const othersId = useId();
  return (
    <div className="ai-features">
      <p className="ai-features-question">{umbrellaQuestion}</p>
      {examples.length > 0 && (
        <ol className="ai-features-list">
          {examples.map(ex => {
            const isChecked = checked.has(ex.title);
            return (
              <li key={ex.title} className="ai-features-item">
                <label className="ai-features-label">
                  <input
                    type="checkbox"
                    checked={isChecked}
                    onChange={() => {
                      const nextSet = new Set(checked);
                      if (isChecked) nextSet.delete(ex.title);
                      else nextSet.add(ex.title);
                      onChange({
                        checkedTitles: Array.from(nextSet),
                        othersText: response.othersText,
                      });
                    }}
                  />
                  <span className="ai-features-title">{ex.title}</span>
                </label>
                <p className="ai-features-desc">{ex.description}</p>
              </li>
            );
          })}
        </ol>
      )}
      <div className="ai-features-others">
        <label htmlFor={othersId} className="ai-features-others-label">Others — please define</label>
        <textarea
          id={othersId}
          rows={3}
          value={response.othersText}
          onChange={e => onChange({
            checkedTitles: response.checkedTitles,
            othersText: e.target.value,
          })}
          placeholder="Describe any additional AI capabilities your solution provides…"
        />
      </div>
    </div>
  );
}
