import type { SortDir } from "../lib/useTableSort";
import "./SortHeader.css";

interface Props<K extends string> {
  label: string;
  colKey: K;
  sortBy: K;
  sortDir: SortDir;
  onSort: (k: K) => void;
  /** Optional — align chevron right (for numeric columns). */
  numeric?: boolean;
  /** Optional — disable click (for derived/computed columns). */
  disabled?: boolean;
}

/**
 * Single sortable column header. Renders the label + a chevron that
 * reflects (sortBy, sortDir). Click cycles asc → desc → default (handled
 * by useTableSort).
 *
 * All tables get the same UX:
 *   ↑  active asc
 *   ↓  active desc
 *   ⇅  inactive (clickable to activate)
 */
export function SortHeader<K extends string>({
  label, colKey, sortBy, sortDir, onSort, numeric, disabled,
}: Props<K>) {
  const isActive = sortBy === colKey;
  const arrow = !isActive ? "⇅" : sortDir === "asc" ? "↑" : "↓";
  const className = [
    "sort-h",
    isActive ? "sort-h-active" : "sort-h-inactive",
    numeric ? "sort-h-numeric" : "",
    disabled ? "sort-h-disabled" : "",
  ].filter(Boolean).join(" ");
  if (disabled) {
    return <span className={className}>{label}</span>;
  }
  return (
    <button
      type="button"
      className={className}
      onClick={() => onSort(colKey)}
      aria-sort={isActive ? (sortDir === "asc" ? "ascending" : "descending") : "none"}
      title={isActive ? `Sorted ${sortDir} — click to cycle` : `Sort by ${label}`}
    >
      <span className="sort-h-label">{label}</span>
      <span className="sort-h-arrow">{arrow}</span>
    </button>
  );
}
