import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import {
  checkRepoAccess,
  getAuthenticatedUser,
  GitHubApiError,
  listPendingInvitations,
  type GitHubAuth,
  type RepoInvitation,
} from "../lib/githubClient";
import {
  clearUsersTableCache,
  loadUsersTable,
  resolveUserProfile,
  type AppRole,
} from "../lib/usersTable";

/**
 * v2 auth context — abstracts over PAT vs OAuth token sources.
 *
 * Today (PAT): user pastes a fine-grained PAT, we validate via GET /user
 * + check repo permissions, store the token in sessionStorage (or
 * localStorage if "remember me"), and re-validate on every page load.
 *
 * Tomorrow (OAuth): same shape, just a different `signIn()` implementation
 * that runs the OAuth dance via a proxy. Everything downstream of
 * `signIn(token)` is identical.
 *
 * Permissions model:
 *   - push access to the target repo → role "editor"
 *   - pull-only access                → role "viewer"
 *   - 401 / no access                  → unauthenticated (show SignIn)
 */

/** Role inferred from GitHub repo permissions only — coarse outer gate.
 *  See `AppRole` (admin/editor/viewer) for the in-app role from users.json. */
export type AuthRole = "editor" | "viewer";

export interface SignedInUser {
  login: string;
  name: string | null;
  email: string | null;
  avatar_url: string;
  /** Outer gate: derived from GitHub repo `permissions.push`. */
  role: AuthRole;
  /** Inner gate: from data/_state/users.json. Decides UI visibility +
   *  publish rights within the SPA. `viewer` when not listed. */
  app_role: AppRole;
  /** Module slugs this user can see — null = all modules. */
  visible_modules: string[] | null;
  /** True when the user is explicitly listed in users.json (not just the
   *  default fallback). UI surfaces this so admins know who has bespoke
   *  access vs. who got the default. */
  is_known_user: boolean;
}

interface AuthContextValue {
  /** null when not signed in. */
  user: SignedInUser | null;
  /** null when not signed in. Same token used by githubClient calls. */
  auth: GitHubAuth | null;
  /** First load: true until the cached token has been re-validated. */
  loading: boolean;
  /** Last sign-in error message — surfaced by the SignIn UI. */
  error: string | null;
  /** When the last sign-in error was a 404 on the repo (most common
   *  failure), this carries the precise diagnostic: which case we're in
   *  + a clickable action (e.g. "Accept invite ↗"). Null otherwise. */
  errorDiagnostic: SignInDiagnostic | null;
  /** Validate + persist a new token. Returns the resolved user on success;
   *  throws on validation failure (UI shows error inline). */
  signIn: (token: string, remember: boolean) => Promise<SignedInUser>;
  signOut: () => void;
  /** Optional client-side role override — editors/admins can toggle this to
   *  preview what a viewer (or editor) sees without signing out. Does NOT
   *  affect actual permissions — the SPA still trusts user.app_role for
   *  any real authorisation; this only narrows the UI render. */
  previewRole: AppRole | null;
  setPreviewRole: (role: AppRole | null) => void;
}

const AuthContext = createContext<AuthContextValue | null>(null);

const STORAGE_KEY = "erp-mapper:v2:auth-token";

interface StoredToken {
  token: string;
  kind: "pat" | "oauth";
  /** sessionStorage vs localStorage source — informational, for the SignOut
   *  flow to clear the right slot. */
  persistent: boolean;
}

function readStoredToken(): StoredToken | null {
  for (const persistent of [true, false]) {
    const store = persistent ? localStorage : sessionStorage;
    const raw = store.getItem(STORAGE_KEY);
    if (!raw) continue;
    try {
      const parsed = JSON.parse(raw) as { token?: string; kind?: string };
      if (parsed.token) {
        return {
          token: parsed.token,
          kind: parsed.kind === "oauth" ? "oauth" : "pat",
          persistent,
        };
      }
    } catch {
      // Corrupt entry — clear it.
      store.removeItem(STORAGE_KEY);
    }
  }
  return null;
}

function writeStoredToken(token: string, kind: "pat" | "oauth", remember: boolean) {
  clearStoredToken();
  const store = remember ? localStorage : sessionStorage;
  store.setItem(STORAGE_KEY, JSON.stringify({ token, kind }));
}

function clearStoredToken() {
  localStorage.removeItem(STORAGE_KEY);
  sessionStorage.removeItem(STORAGE_KEY);
}

function repoConfig(): { owner: string; name: string } {
  // Fallbacks match the canonical repo for the workspace. Override via env
  // when building for a different fork / private mirror.
  const owner = import.meta.env.VITE_GITHUB_REPO_OWNER || "jersgcodes";
  const name = import.meta.env.VITE_GITHUB_REPO_NAME || "erp-mapper";
  return { owner, name };
}

/** Error type carrying a contextual "action" the user can click —
 *  e.g. "Accept invite" → opens the GitHub invitation page in a new tab.
 *  The SignIn UI renders the action as a button when present. */
export class SignInDiagnostic extends Error {
  readonly kind: "no_invite" | "pending_invite" | "no_collab" | "pat_repo_scope"
                | "sso_required" | "auth_failed" | "rate_limited" | "owner_404" | "unknown";
  readonly action?: { label: string; url: string };
  constructor(
    message: string,
    kind: SignInDiagnostic["kind"],
    action?: { label: string; url: string },
  ) {
    super(message);
    this.name = "SignInDiagnostic";
    this.kind = kind;
    this.action = action;
  }
}

/** Translate a raw GitHub 404 on the repo into a precise diagnostic.
 *  Calls `/user/repository_invitations` to detect pending invites + uses
 *  the authenticated user's login vs. repo owner to pick the right copy. */
async function diagnose404(
  auth: GitHubAuth,
  userLogin: string,
): Promise<SignInDiagnostic> {
  const repoFullName = `${auth.repoOwner}/${auth.repoName}`;
  const isOwner = userLogin.toLowerCase() === auth.repoOwner.toLowerCase();

  // First: check pending invites — most actionable case.
  if (!isOwner) {
    const invites = await listPendingInvitations(auth);
    const match = invites.find(
      (i: RepoInvitation) => i.repository.full_name.toLowerCase() === repoFullName.toLowerCase(),
    );
    if (match) {
      return new SignInDiagnostic(
        `@${userLogin} has a pending collaborator invite to ${repoFullName} that hasn't been accepted yet. Open the invite below to accept it, then retry sign-in.`,
        "pending_invite",
        { label: "Accept invite ↗", url: match.html_url || `https://github.com/${repoFullName}/invitations` },
      );
    }
  }

  // Owner-side: token can't even see their own repo — scope or App-install issue.
  if (isOwner) {
    return new SignInDiagnostic(
      `Token validates as @${userLogin} but ${repoFullName} returned 404. The token's scope is too narrow (PAT) or the OAuth App isn't installed on this repo. Try a fresh PAT with full repo scope.`,
      "owner_404",
    );
  }

  // Different user, no invite found — they're just not a collaborator.
  if (auth.kind === "pat") {
    return new SignInDiagnostic(
      `Your PAT works for @${userLogin} but doesn't include ${repoFullName} in its repository list. Either you're not a collaborator on this private repo, or the PAT's repo selection needs to be widened. Ask the repo owner to invite you, or edit the PAT to include this repo.`,
      "pat_repo_scope",
      { label: "Manage PATs ↗", url: "https://github.com/settings/personal-access-tokens" },
    );
  }
  // OAuth path
  return new SignInDiagnostic(
    `@${userLogin} isn't a collaborator on ${repoFullName} yet. Ask the repo owner to invite you, then accept the invite from your email or GitHub notifications before retrying sign-in.`,
    "no_collab",
    { label: "Ask owner via GitHub ↗", url: `https://github.com/${auth.repoOwner}` },
  );
}

async function validateToken(token: string, kind: "pat" | "oauth"): Promise<SignedInUser> {
  const { owner, name } = repoConfig();
  const auth: GitHubAuth = { token, kind, repoOwner: owner, repoName: name };
  const user = await getAuthenticatedUser(auth);
  let access: { permissions: { admin: boolean; push: boolean; pull: boolean }; private: boolean };
  try {
    access = await checkRepoAccess(auth);
  } catch (e) {
    // Convert raw 404 into a precise SignInDiagnostic so the UI can render
    // an actionable next step (accept-invite button etc).
    if (e instanceof GitHubApiError && e.isNotFound) {
      throw await diagnose404(auth, user.login);
    }
    throw e;
  }
  const role: AuthRole = access.permissions.push ? "editor" : "viewer";
  // Resolve role + visible_modules. Priority:
  //   1. users.json explicit entry (overrides + visible_modules scoping)
  //   2. GitHub repo permissions auto-map (admin/write/read → admin/editor/viewer)
  //   3. Default viewer as last resort.
  // The users.json file is OPTIONAL — colleagues added as GH collaborators
  // get a role automatically without anyone touching the file.
  let app_role: AppRole = "viewer";
  let visible_modules: string[] | null = null;
  let is_known_user = false;
  try {
    const table = await loadUsersTable(auth);
    const profile = resolveUserProfile(table, user.login, access.permissions);
    app_role = profile.role;
    visible_modules = profile.visible_modules;
    is_known_user = profile.is_known;
  } catch (e) {
    console.warn("[auth] users table load failed; falling back to GH permissions:", e);
    // Even without users.json, derive a role from GH permissions directly.
    if (access.permissions.admin) app_role = "admin";
    else if (access.permissions.push) app_role = "editor";
    else if (access.permissions.pull) app_role = "viewer";
  }
  // If GitHub says you don't have push access, you can't be editor/admin
  // in the SPA regardless of users.json. Clamp app_role down.
  if (role === "viewer" && app_role !== "viewer") {
    app_role = "viewer";
  }
  return {
    login: user.login,
    name: user.name,
    email: user.email,
    avatar_url: user.avatar_url,
    role,
    app_role,
    visible_modules,
    is_known_user,
  };
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<SignedInUser | null>(null);
  const [auth, setAuth] = useState<GitHubAuth | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [errorDiagnostic, setErrorDiagnostic] = useState<SignInDiagnostic | null>(null);
  const [previewRole, setPreviewRole] = useState<AppRole | null>(null);

  // On mount: try to revive a cached session.
  useEffect(() => {
    let cancelled = false;
    const stored = readStoredToken();
    if (!stored) {
      setLoading(false);
      return;
    }
    (async () => {
      try {
        const u = await validateToken(stored.token, stored.kind);
        if (cancelled) return;
        const { owner, name } = repoConfig();
        setAuth({ token: stored.token, kind: stored.kind, repoOwner: owner, repoName: name });
        setUser(u);
      } catch (e: unknown) {
        if (cancelled) return;
        // Cached token failed validation — discard it + force re-sign-in.
        clearStoredToken();
        if (e instanceof SignInDiagnostic) {
          setError(e.message);
          setErrorDiagnostic(e);
        } else {
          const msg = e instanceof GitHubApiError
            ? `Stored token rejected: ${e.githubMessage || e.message}`
            : (e instanceof Error ? e.message : String(e));
          setError(msg);
          setErrorDiagnostic(null);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  const signIn = useCallback(async (token: string, remember: boolean): Promise<SignedInUser> => {
    setError(null);
    setErrorDiagnostic(null);
    const trimmed = token.trim();
    if (!trimmed) {
      const err = "Token cannot be empty.";
      setError(err);
      throw new Error(err);
    }
    // Sniff token shape — informational only; we don't reject on shape.
    const kind: "pat" | "oauth" = trimmed.startsWith("github_pat_") || trimmed.startsWith("ghp_")
      ? "pat"
      : "oauth";
    try {
      const u = await validateToken(trimmed, kind);
      const { owner, name } = repoConfig();
      writeStoredToken(trimmed, kind, remember);
      setAuth({ token: trimmed, kind, repoOwner: owner, repoName: name });
      setUser(u);
      return u;
    } catch (e: unknown) {
      // SignInDiagnostic carries precise + actionable copy from validateToken's
      // 404 detection. Surface it as-is so the SignIn UI can render the action button.
      if (e instanceof SignInDiagnostic) {
        setError(e.message);
        setErrorDiagnostic(e);
        throw e;
      }
      let msg: string;
      if (e instanceof GitHubApiError) {
        if (e.isAuthError) {
          msg = "Token rejected by GitHub. Check the token value and that it hasn't expired.";
        } else if (e.isRateLimit) {
          msg = "GitHub rate-limited this token. Try again in a few minutes.";
        } else if (e.status === 403 && /saml/i.test(e.message + " " + e.githubMessage)) {
          msg = `Your organisation requires SAML SSO authorisation for this token. Visit github.com/settings/tokens and click "Configure SSO" next to this token.`;
        } else {
          msg = e.githubMessage || e.message;
        }
      } else {
        msg = e instanceof Error ? e.message : String(e);
      }
      setError(msg);
      setErrorDiagnostic(null);
      throw new Error(msg);
    }
  }, []);

  const signOut = useCallback(() => {
    clearStoredToken();
    clearUsersTableCache();
    setUser(null);
    setAuth(null);
    setError(null);
    setErrorDiagnostic(null);
    setPreviewRole(null);
  }, []);

  const value = useMemo<AuthContextValue>(() => ({
    user, auth, loading, error, errorDiagnostic, signIn, signOut,
    previewRole, setPreviewRole,
  }), [user, auth, loading, error, errorDiagnostic, signIn, signOut, previewRole]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

/** Safe stub returned when useAuth() is called outside <AuthProvider>.
 *  Lets v1 paths (CF Worker, GH Pages bridge) + unit tests run without
 *  wrapping every render in AuthProvider. v2 code paths gate on the user
 *  being non-null before doing any auth-required work, so a stub here
 *  results in those paths early-returning rather than crashing. */
const AUTH_STUB: AuthContextValue = {
  user: null,
  auth: null,
  loading: false,
  error: null,
  errorDiagnostic: null,
  signIn: () => Promise.reject(new Error("AuthProvider not mounted")),
  signOut: () => {},
  previewRole: null,
  setPreviewRole: () => {},
};

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  return ctx ?? AUTH_STUB;
}

/** Convenience flag — true when the build is running the v2 GitHub-native
 *  path (env VITE_GITHUB_NATIVE=true). Used by routing + canonical loader. */
export const GITHUB_NATIVE = import.meta.env.VITE_GITHUB_NATIVE === "true";
