import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type SolCatFulfilmentRow,
  type CapEvidence,
  type SolcatExpectedBeyondEntry,
} from "../../lib/stakeholdersData";
import { useUrlParam } from "../../lib/urlState";
import { fuzzyFilter } from "../../lib/fuzzy";
import { TabHelp } from "../TabHelp";
import "./SolCatDetailPanel.css";

type TierFilter = "mandatory" | "mandatory_preferred" | "all";

/** §1 — caps where this sol cat's IMDA Qs already contribute to a
 *  module-checklist cap (via caps_index.imda_refs.sources). These are
 *  evidence we've already produced for this sol cat. */
interface ContributedCap {
  cap_id: string;
  name: string;
  module: string;
  sub_module_name?: string | null;
  sme_tier?: string;
  applicability: string[];
  backing_q_titles: string[];
}

/** §2 — caps the LLM target says THIS sol cat should provide that aren't
 *  in §1 (trace). Sorted by confidence + sme-applicability, so actionable
 *  adds float to the top while enterprise-only caps stay visible for
 *  completeness. */
interface GapToAddCap {
  cap_id: string;
  name: string;
  module: string;
  sub_module_name?: string | null;
  sme_tier?: string;
  applicability: string[];
  confidence: "high" | "medium" | "low";
  reason: string;
}

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

/**
 * Three sections per sol cat:
 *
 *   contributed     — §1. Caps where the sol cat's IMDA Qs already back a
 *                     canonical cap (via caps_index.imda_refs). The work
 *                     we've already done that contributes to this sol cat.
 *
 *   gapsToAdd       — §2. LLM-expanded canonical_expected ∖ contributed.
 *                     Caps the LLM thinks an industry-real product in this
 *                     sol cat should provide but we haven't traced yet.
 *                     The "valuable to add to sol cat" emphasis.
 *                     SME or mid-applicable shown as actionable; enterprise-
 *                     only shown for completeness.
 *
 *   beyondCanonical — §3. LLM-suggested capabilities that don't map to any
 *                     of our 304 canonical caps — drives future cap-library
 *                     expansion. Light start: just a list with reasons.
 *
 * Source data:
 *   §1 ← caps_index (existing)
 *   §2 ← solcat_expected_caps[scId].canonical_expected (LLM expansion)
 *   §3 ← solcat_expected_caps[scId].beyond_canonical (LLM expansion)
 */
interface SolCatBuckets {
  contributed: ContributedCap[];
  gapsToAdd: GapToAddCap[];
  beyondCanonical: SolcatExpectedBeyondEntry[];
  hasLlmTarget: boolean;
}

export function SolCatDetailPanel({ modules }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  // URL-backed picker so a chosen sol cat survives reload + back/forward
  // and the link is shareable.
  const [scId, setScId] = useUrlParam<string>("sc", "");
  const [filter, setFilter] = useState<string>("");
  const [tierFilter, setTierFilter] = useUrlParam<TierFilter>("scd_tier", "mandatory_preferred");

  useEffect(() => {
    loadStakeholdersSummary()
      .then(d => {
        setData(d);
        // Auto-pick the first sol cat alphabetically so the page isn't empty.
        if (!scId && d.sol_cats?.length) {
          const first = d.sol_cats
            .slice()
            .sort((a, b) => a.display_name.localeCompare(b.display_name))[0];
          if (first) setScId(first.id);
        }
      })
      .catch(e => setError(String(e?.message || e)));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const solCatList = useMemo(() => {
    if (!data) return [];
    const ranked = (data.sol_cats || []).slice();
    ranked.sort((a, b) => a.display_name.localeCompare(b.display_name));
    return ranked;
  }, [data]);

  const filteredList = useMemo(() => {
    return fuzzyFilter(solCatList, filter, ["display_name", "vertical", "id"]);
  }, [filter, solCatList]);

  const sc = solCatList.find(s => s.id === scId);
  const fulfilmentRow: SolCatFulfilmentRow | undefined = data
    ? (data.solcat_fulfilment || []).find(f => f.id === scId)
    : undefined;

  const buckets = useMemo<SolCatBuckets>(() => {
    if (!sc || !data) {
      return { contributed: [], gapsToAdd: [], beyondCanonical: [], hasLlmTarget: false };
    }
    return buildBuckets(data, scId, tierFilter);
  }, [sc, scId, data, tierFilter]);

  if (error) {
    return (
      <div className="dash-panel scd-error">
        Failed to load stakeholders payload: {error}
      </div>
    );
  }
  if (!data) {
    return <div className="dash-panel scd-loading">Loading sol-cat data…</div>;
  }

  return (
    <div className="dash-panel scd-panel">
      <TabHelp hint="§1 = caps_index.imda_refs.sources contains this sol cat. §2 = LLM-expanded canonical_expected ∖ §1. §3 = LLM beyond_canonical. Source: data/_derived/solcat_expected_caps.yaml. Tier filter applies to §1 + §2.">
        Sol-cat-first view: <strong>§1</strong> what module-checklist work
        already contributes to this sol cat (the trace), <strong>§2</strong>{" "}
        gaps to add — caps an industry-real product in this category should
        provide that the trace doesn't yet back, <strong>§3</strong>{" "}
        capabilities beyond our 304 canonical caps that this sol cat would
        normally include (drives cap-library expansion).
      </TabHelp>
      <div className="dash-chip-bar">
        <span className="dash-chip">
          <strong>{solCatList.length}</strong> sol cats analysed (excludes 18 non-ERP)
        </span>
        <span className="dash-chip dash-chip-hint">
          Tier filter applies to all three buckets
        </span>
        <div className="scd-tier-pills" role="tablist" aria-label="Tier filter">
          <button
            type="button"
            className={`scd-tier-pill${tierFilter === "mandatory" ? " active" : ""}`}
            onClick={() => setTierFilter("mandatory")}
            aria-pressed={tierFilter === "mandatory"}
          >
            Mandatory only
          </button>
          <button
            type="button"
            className={`scd-tier-pill${tierFilter === "mandatory_preferred" ? " active" : ""}`}
            onClick={() => setTierFilter("mandatory_preferred")}
            aria-pressed={tierFilter === "mandatory_preferred"}
          >
            Mandatory + Preferred
          </button>
          <button
            type="button"
            className={`scd-tier-pill${tierFilter === "all" ? " active" : ""}`}
            onClick={() => setTierFilter("all")}
            aria-pressed={tierFilter === "all"}
          >
            All tiers
          </button>
        </div>
      </div>

      <div className="scd-layout">
        <aside className="scd-picker">
          <input
            type="search"
            className="scd-search"
            placeholder="Search sol cat or vertical…"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
          <div className="scd-list">
            {filteredList.length === 0 && (
              <div className="scd-empty">No sol cats match.</div>
            )}
            {filteredList.map(s => (
              <button
                key={s.id}
                type="button"
                className={`scd-list-row${s.id === scId ? " active" : ""}`}
                onClick={() => setScId(s.id)}
                title={s.id}
              >
                <span className="scd-list-name">
                  {s.display_name}
                  {s.vertical_saas && <span className="scd-vsaas">vertical</span>}
                </span>
                <span className="scd-list-vert">{s.vertical}</span>
              </button>
            ))}
          </div>
        </aside>

        <section className="scd-detail">
          {!sc ? (
            <div className="scd-empty">Pick a sol cat to see its coverage.</div>
          ) : (
            <DetailView
              sc={sc}
              fulfilmentRow={fulfilmentRow}
              buckets={buckets}
              capsIndex={data.caps_index || []}
              tierFilter={tierFilter}
              modules={modules}
            />
          )}
        </section>
      </div>
    </div>
  );
}

function DetailView({
  sc,
  fulfilmentRow,
  buckets,
  capsIndex,
  tierFilter,
  modules,
}: {
  sc: NonNullable<StakeholdersSummary["sol_cats"]>[number];
  fulfilmentRow?: SolCatFulfilmentRow;
  buckets: SolCatBuckets;
  capsIndex: CapEvidence[];
  tierFilter: TierFilter;
  modules: ModuleEntry[];
}) {
  // Headline: how much of the LLM target are we already covering via trace?
  const targetTotal = buckets.contributed.length + buckets.gapsToAdd.length;
  const targetPct = targetTotal > 0
    ? Math.round((buckets.contributed.length / targetTotal) * 100)
    : null;
  // Among gaps, how many are "actionable" at SME/mid (vs enterprise-only)?
  const actionableGaps = buckets.gapsToAdd.filter(c => sizeApplicable(c.applicability)).length;

  // IMDA Q × caps map for the picked sol cat — kept as the granular
  // appendix to the three-bucket view.
  const qToCaps = new Map<string, CapEvidence[]>();
  for (const cap of capsIndex) {
    for (const ref of cap.imda_refs || []) {
      if (!(ref.sources || []).includes(sc.id)) continue;
      const arr = qToCaps.get(ref.q_title) || [];
      arr.push(cap);
      qToCaps.set(ref.q_title, arr);
    }
  }
  const qEntries = Array.from(qToCaps.entries()).sort((a, b) => a[0].localeCompare(b[0]));
  const moduleNameLookup = new Map(modules.map(m => [m.slug, m.module_name]));

  return (
    <>
      <header className="scd-head">
        <div className="scd-head-top">
          <h3 className="scd-h3">{sc.display_name}</h3>
          {sc.vertical_saas && (
            <span className="scd-vsaas-pill" title={`Vertical SaaS — ${sc.vertical_saas_industry}`}>
              vertical mini-ERP
            </span>
          )}
        </div>
        <div className="scd-head-meta">
          <span><strong>{sc.vertical}</strong></span>
          <span>·</span>
          <span>{sc.imda_req_count} IMDA reqs</span>
          <span>·</span>
          <span title="Caps where this sol cat's IMDA Qs already contribute to a module-checklist cap (the trace).">
            {buckets.contributed.length} contributed
          </span>
          {buckets.hasLlmTarget && (
            <>
              <span>·</span>
              <span title="Of the LLM-expanded target list for this sol cat, how much is already covered by the trace.">
                {buckets.contributed.length}/{targetTotal} of target ({targetPct ?? "—"}%)
              </span>
              {buckets.gapsToAdd.length > 0 && (
                <>
                  <span>·</span>
                  <span className="scd-meta-warn" title="LLM-target caps not yet backed by this sol cat's IMDA Qs.">
                    {buckets.gapsToAdd.length} gap{buckets.gapsToAdd.length === 1 ? "" : "s"} to add
                    {actionableGaps !== buckets.gapsToAdd.length && ` (${actionableGaps} SME-actionable)`}
                  </span>
                </>
              )}
              {buckets.beyondCanonical.length > 0 && (
                <>
                  <span>·</span>
                  <span className="scd-meta-info" title="Capabilities the LLM thinks this sol cat should have that aren't in our 304 canonical caps — drives cap library expansion.">
                    {buckets.beyondCanonical.length} beyond-canonical
                  </span>
                </>
              )}
            </>
          )}
        </div>
        {fulfilmentRow && (
          <div className="scd-fulfilment-strip">
            <FulfilmentStat
              label="Direct trace"
              pct={fulfilmentRow.fulfilment_pct}
              tone="direct"
              title={`${fulfilmentRow.fulfilled_caps}/${fulfilmentRow.expected_caps} caps directly traced from PSG questions`}
            />
            <FulfilmentStat
              label="Realistic (Haiku)"
              pct={fulfilmentRow.realistic_pct ?? null}
              tone="realistic"
              title="Haiku-judged: would a typical sol cat in this category cover these caps?"
            />
            {fulfilmentRow.delta != null && (
              <FulfilmentDelta delta={fulfilmentRow.delta} pattern={fulfilmentRow.pattern} />
            )}
          </div>
        )}
      </header>

      <div className="scd-buckets">
        <ContributedSection
          caps={buckets.contributed}
          moduleNameLookup={moduleNameLookup}
          tierFilter={tierFilter}
          hasLlmTarget={buckets.hasLlmTarget}
          targetTotal={targetTotal}
        />
        <GapsToAddSection
          caps={buckets.gapsToAdd}
          moduleNameLookup={moduleNameLookup}
          tierFilter={tierFilter}
          hasLlmTarget={buckets.hasLlmTarget}
        />
        <BeyondCanonicalSection
          entries={buckets.beyondCanonical}
          hasLlmTarget={buckets.hasLlmTarget}
        />
      </div>

      <section className="scd-q-section">
        <h4 className="scd-q-h4">
          IMDA Q × cap backings{" "}
          <span className="scd-q-sub">
            ({qEntries.length} Q{qEntries.length === 1 ? "" : "s"} from {sc.display_name})
          </span>
        </h4>
        <p className="scd-q-blurb">
          For each PSG question on this sol cat, the caps it backs in our
          checklist. A single Q can back multiple caps when the question's
          req text spans them (e.g. 3-in-1 accounting Q backing GL + AR +
          AP + Cash + Tax).
        </p>
        {qEntries.length === 0 ? (
          <div className="scd-q-empty">
            No IMDA Q backings yet — this sol cat is mapped via sub-module
            scope only (no direct cap traces).
          </div>
        ) : (
          <div className="scd-q-list">
            {qEntries.map(([qTitle, caps]) => (
              <div key={qTitle} className="scd-q-row">
                <div className="scd-q-title">
                  {qTitle}{" "}
                  <span className="scd-q-count">
                    {caps.length} cap{caps.length === 1 ? "" : "s"}
                  </span>
                </div>
                <ul className="scd-q-caps">
                  {caps.map(c => (
                    <li key={c.id}>
                      <span className="scd-q-cap-name">{c.name}</span>
                      <code className="scd-q-cap-id">{c.id}</code>
                      <span className="scd-q-cap-mod">{c.module}</span>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        )}
      </section>
    </>
  );
}

// ──────────────────────────────────────────────────────────────────────
// Bucket sections — In-scope / Candidates / Trace-only
// ──────────────────────────────────────────────────────────────────────

interface CapRowLike {
  cap_id: string;
  name: string;
  module: string;
  sub_module_name?: string | null;
  sme_tier?: string;
}

function groupByModule<T extends CapRowLike>(
  caps: T[],
  moduleNameLookup: Map<string, string>,
): Array<{ module: string; module_name: string; caps: T[] }> {
  const map = new Map<string, { module: string; module_name: string; caps: T[] }>();
  for (const c of caps) {
    const g = map.get(c.module) || {
      module: c.module,
      module_name: moduleNameLookup.get(c.module) || c.module,
      caps: [] as T[],
    };
    g.caps.push(c);
    map.set(c.module, g);
  }
  return Array.from(map.values()).sort((a, b) => a.module.localeCompare(b.module));
}

/**
 * §1 Contributed — caps where this sol cat's IMDA Qs already back a
 * canonical cap (via caps_index.imda_refs.sources). The "what work
 * we've already done that contributes to this sol cat".
 *
 * Shows ALL applicability sizes (sme/mid/enterprise) — caps the trace
 * already produces are kept regardless of size. Mid-only and enterprise-
 * only caps get inline badges so reviewers see the size dimension at
 * a glance.
 */
function ContributedSection({
  caps,
  moduleNameLookup,
  tierFilter,
  hasLlmTarget,
  targetTotal,
}: {
  caps: ContributedCap[];
  moduleNameLookup: Map<string, string>;
  tierFilter: TierFilter;
  hasLlmTarget: boolean;
  targetTotal: number;
}) {
  const grouped = groupByModule(caps, moduleNameLookup);
  const subtitle = hasLlmTarget && targetTotal > 0
    ? `Caps where this sol cat's IMDA Qs already back a module-checklist cap. Covers ${caps.length} of ${targetTotal} target caps (${Math.round(100 * caps.length / targetTotal)}%, ${tierLabel(tierFilter)}).`
    : `Caps where this sol cat's IMDA Qs already back a module-checklist cap (${tierLabel(tierFilter)}).`;

  return (
    <section className="scd-bucket scd-bucket-inscope">
      <header className="scd-bucket-head">
        <span className="scd-bucket-icon">📋</span>
        <h4 className="scd-bucket-title">§1 What this sol cat contributes</h4>
        <span className="scd-bucket-count">{caps.length}</span>
        <span className="scd-bucket-sub">{subtitle}</span>
      </header>
      {caps.length === 0 ? (
        <p className="scd-bucket-empty">
          No IMDA Qs from this sol cat back any canonical cap at this tier.
          See §2 for caps the LLM thinks this sol cat should add.
        </p>
      ) : (
        <div className="scd-bucket-modules">
          {grouped.map(g => (
            <div key={g.module} className="scd-bucket-mod">
              <div className="scd-bucket-mod-name">
                <Link to={`/canonical/${g.module}`}>{g.module_name}</Link>
                <span className="scd-bucket-mod-count">{g.caps.length}</span>
              </div>
              <ul className="scd-bucket-caps">
                {g.caps.map(c => (
                  <li key={c.cap_id} className="scd-cap-verified">
                    <span className="scd-cap-mark" aria-label="Contributed">✓</span>
                    <Link
                      to={`/canonical/${c.module}?cap=${encodeURIComponent(c.cap_id)}`}
                      className="scd-bucket-cap-name"
                    >
                      {c.name}
                    </Link>
                    <span className={`scd-bucket-tier scd-bucket-tier-${c.sme_tier || "preferred"}`}>
                      {tierShort(c.sme_tier)}
                    </span>
                    {c.sub_module_name && (
                      <span className="scd-bucket-sm">{c.sub_module_name}</span>
                    )}
                    <SizeBadge applicability={c.applicability} />
                    <span
                      className="scd-bucket-via"
                      title={c.backing_q_titles.join("\n")}
                    >
                      via {c.backing_q_titles.length} Q{c.backing_q_titles.length === 1 ? "" : "s"}
                    </span>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      )}
    </section>
  );
}

/**
 * §2 Gaps to add — LLM-target caps not yet contributed.
 *
 * Two strata:
 *   actionable adds  — caps applicable to SME or mid-market (the PSG target)
 *   for completeness — enterprise-only caps. Shown so the reader sees the
 *                      complete picture of what an ideal product would have,
 *                      but flagged as not actionable for sol-cat-scope edits.
 *
 * Sorted within each stratum by confidence desc → tier → name.
 */
function GapsToAddSection({
  caps,
  moduleNameLookup,
  tierFilter,
  hasLlmTarget,
}: {
  caps: GapToAddCap[];
  moduleNameLookup: Map<string, string>;
  tierFilter: TierFilter;
  hasLlmTarget: boolean;
}) {
  const actionable = caps.filter(c => sizeApplicable(c.applicability));
  const completeness = caps.filter(c => !sizeApplicable(c.applicability));

  if (!hasLlmTarget) {
    return (
      <section className="scd-bucket scd-bucket-candidates">
        <header className="scd-bucket-head">
          <span className="scd-bucket-icon">＋</span>
          <h4 className="scd-bucket-title">§2 Gaps to add</h4>
          <span className="scd-bucket-count">—</span>
          <span className="scd-bucket-sub">
            LLM target hasn't been generated for this sol cat. Run{" "}
            <code>python3 scripts/expand_solcat_expected_caps.py</code> to enable.
          </span>
        </header>
      </section>
    );
  }

  return (
    <section className="scd-bucket scd-bucket-candidates">
      <header className="scd-bucket-head">
        <span className="scd-bucket-icon">＋</span>
        <h4 className="scd-bucket-title">§2 Gaps to add</h4>
        <span className="scd-bucket-count">{caps.length}</span>
        <span className="scd-bucket-sub">
          LLM-expanded target caps NOT yet contributed by this sol cat ({tierLabel(tierFilter)}).
          {actionable.length > 0 && completeness.length > 0 && (
            <> Two strata: <strong>SME-actionable</strong> ({actionable.length}, sme or mid-applicable — adds to consider) and <strong>enterprise-only</strong> ({completeness.length}, shown for completeness).</>
          )}
          {actionable.length > 0 && completeness.length === 0 && (
            <> All {actionable.length} caps are SME-actionable.</>
          )}
        </span>
      </header>
      {caps.length === 0 ? (
        <p className="scd-bucket-empty">
          No gaps at this tier — everything the LLM target predicts is already
          contributed via §1, or filtered out by tier.
        </p>
      ) : (
        <>
          {actionable.length > 0 && (
            <GapsToAddStratum
              title={`SME-actionable adds (sme or mid-applicable)`}
              caps={actionable}
              moduleNameLookup={moduleNameLookup}
              tone="primary"
            />
          )}
          {completeness.length > 0 && (
            <GapsToAddStratum
              title={`Enterprise-only (for completeness, not actionable for SME-targeted sol cat)`}
              caps={completeness}
              moduleNameLookup={moduleNameLookup}
              tone="secondary"
            />
          )}
        </>
      )}
    </section>
  );
}

function GapsToAddStratum({
  title,
  caps,
  moduleNameLookup,
  tone,
}: {
  title: string;
  caps: GapToAddCap[];
  moduleNameLookup: Map<string, string>;
  tone: "primary" | "secondary";
}) {
  const grouped = groupByModule(caps, moduleNameLookup);
  return (
    <div className={`scd-stratum scd-stratum-${tone}`}>
      <div className="scd-stratum-head">
        <span className="scd-stratum-title">{title}</span>
        <span className="scd-stratum-count">{caps.length}</span>
      </div>
      <div className="scd-bucket-modules">
        {grouped.map(g => (
          <div key={g.module} className="scd-bucket-mod">
            <div className="scd-bucket-mod-name">
              <Link to={`/canonical/${g.module}`}>{g.module_name}</Link>
              <span className="scd-bucket-mod-count">{g.caps.length}</span>
            </div>
            <ul className="scd-bucket-caps">
              {g.caps.map(c => (
                <li key={c.cap_id}>
                  <span
                    className={`scd-confidence scd-confidence-${c.confidence}`}
                    title={`LLM confidence: ${c.confidence}`}
                  >
                    {c.confidence === "high" ? "●" : c.confidence === "medium" ? "◐" : "○"}
                  </span>
                  <Link
                    to={`/canonical/${c.module}?cap=${encodeURIComponent(c.cap_id)}`}
                    className="scd-bucket-cap-name"
                  >
                    {c.name}
                  </Link>
                  <span className={`scd-bucket-tier scd-bucket-tier-${c.sme_tier || "preferred"}`}>
                    {tierShort(c.sme_tier)}
                  </span>
                  {c.sub_module_name && (
                    <span className="scd-bucket-sm">{c.sub_module_name}</span>
                  )}
                  <SizeBadge applicability={c.applicability} />
                  <span
                    className="scd-gap-reason"
                    title={c.reason}
                  >
                    why: {c.reason.length > 80 ? c.reason.slice(0, 80) + "…" : c.reason}
                  </span>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </div>
  );
}

/**
 * §3 Beyond canonical — LLM-suggested capabilities not in our 304 cap
 * library. Drives future cap-library expansion. Light start: just a list
 * with descriptions + reasons. No drill-down, no integration with caps.
 */
function BeyondCanonicalSection({
  entries,
  hasLlmTarget,
}: {
  entries: SolcatExpectedBeyondEntry[];
  hasLlmTarget: boolean;
}) {
  if (!hasLlmTarget) {
    return null;
  }
  return (
    <section className="scd-bucket scd-bucket-trace">
      <header className="scd-bucket-head">
        <span className="scd-bucket-icon">⊕</span>
        <h4 className="scd-bucket-title">§3 Beyond our canonical</h4>
        <span className="scd-bucket-count">{entries.length}</span>
        <span className="scd-bucket-sub">
          Capabilities the LLM thinks this sol cat would normally include
          but aren't in our 304 canonical caps. Future cap-library expansion
          candidates — review periodically and promote to canonical when a
          pattern emerges across sol cats.
        </span>
      </header>
      {entries.length === 0 ? (
        <p className="scd-bucket-empty">
          No beyond-canonical suggestions for this sol cat — the canonical
          list covers everything the LLM thinks is needed.
        </p>
      ) : (
        <ul className="scd-beyond-list">
          {entries.map((e, i) => (
            <li key={i} className="scd-beyond-item">
              <div className="scd-beyond-name">{e.name}</div>
              <div className="scd-beyond-desc">{e.description}</div>
              {e.reason && (
                <div className="scd-beyond-reason muted small">{e.reason}</div>
              )}
            </li>
          ))}
        </ul>
      )}
    </section>
  );
}

/**
 * Inline applicability badge — shown next to caps where applicability is
 * NOT [sme, mid_market, enterprise] (i.e., something is missing). Tells
 * reviewers at a glance which caps aren't SME-targeted.
 */
function SizeBadge({ applicability }: { applicability: string[] }) {
  if (applicability.length === 0) return null;
  const set = new Set(applicability);
  // The most common case — full coverage — gets no badge (signal-to-noise).
  if (set.has("sme") && set.has("mid_market") && set.has("enterprise")) return null;
  if (!set.has("sme") && set.has("mid_market") && set.has("enterprise")) {
    return (
      <span className="scd-size-badge scd-size-mid" title="Mid-market + enterprise (not SME-applicable)">
        mid+ent
      </span>
    );
  }
  if (set.has("enterprise") && set.size === 1) {
    return (
      <span className="scd-size-badge scd-size-ent" title="Enterprise-only — not actionable for SME-targeted sol cats">
        ent only
      </span>
    );
  }
  if (set.has("mid_market") && set.size === 1) {
    return (
      <span className="scd-size-badge scd-size-mid" title="Mid-market only">
        mid only
      </span>
    );
  }
  // Other patterns — show raw
  return (
    <span className="scd-size-badge scd-size-other" title={`Applicability: ${applicability.join(", ")}`}>
      {applicability.join("+")}
    </span>
  );
}


function tierShort(t?: string): string {
  if (t === "required") return "M";
  if (t === "preferred") return "P";
  if (t === "advanced") return "A";
  return "—";
}

function tierLabel(f: TierFilter): string {
  if (f === "mandatory") return "Mandatory only";
  if (f === "mandatory_preferred") return "Mandatory + Preferred";
  return "All tiers";
}

function FulfilmentStat({
  label, pct, tone, title,
}: { label: string; pct: number | null | undefined; tone: string; title?: string }) {
  if (pct == null) {
    return (
      <div className={`scd-fstat scd-fstat-${tone} scd-fstat-pending`} title={title}>
        <div className="scd-fstat-num">—</div>
        <div className="scd-fstat-lbl">{label}</div>
      </div>
    );
  }
  let band = "fail";
  if (pct >= 70) band = "pass";
  else if (pct >= 40) band = "partial";
  return (
    <div className={`scd-fstat scd-fstat-${tone} scd-fstat-band-${band}`} title={title}>
      <div className="scd-fstat-num">{pct}%</div>
      <div className="scd-fstat-lbl">{label}</div>
    </div>
  );
}

function FulfilmentDelta({
  delta, pattern,
}: { delta: number; pattern?: string }) {
  const sign = delta > 0 ? "+" : "";
  const tone =
    pattern === "cross_tag_suspect" ? "warn" :
    pattern === "over_mapped" ? "bad" :
    pattern === "healthy" ? "ok" : "neutral";
  return (
    <div
      className={`scd-fdelta scd-fdelta-${tone}`}
      title={pattern ? `Pattern: ${pattern}` : "Realistic minus direct"}
    >
      <div className="scd-fdelta-num">Δ {sign}{delta}</div>
      <div className="scd-fdelta-lbl">{pattern || "delta"}</div>
    </div>
  );
}


// ──────────────────────────────────────────────────────────────────────
// Bucket builder
// ──────────────────────────────────────────────────────────────────────

const TIER_RANK: Record<string, number> = { required: 0, preferred: 1, advanced: 2 };

function tierPasses(t: string | undefined, filter: TierFilter): boolean {
  if (filter === "all") return true;
  if (!t) return false;
  if (filter === "mandatory") return t === "required";
  if (filter === "mandatory_preferred") return t === "required" || t === "preferred";
  return false;
}

/**
 * Size filter: exclude enterprise-only caps. A cap shows up if its
 * applicability includes "sme" OR "mid_market". Enterprise-only caps
 * (apps == ['enterprise']) are dropped — sol cats target SME/mid-market
 * buyers, not enterprise.
 */
function sizeApplicable(applicability: string[] | undefined): boolean {
  if (!applicability || applicability.length === 0) return true;  // unknown → keep
  return applicability.includes("sme") || applicability.includes("mid_market");
}

const CONFIDENCE_RANK: Record<string, number> = { high: 0, medium: 1, low: 2 };

/**
 * Build the three buckets for the picked sol cat — sol-cat-first frame:
 *
 *   contributed     ← caps_index[*] where imda_refs.sources contains scId.
 *                     The work this sol cat's IMDA Qs already contribute
 *                     to module checklists. Tier-filtered, all sizes shown.
 *
 *   gapsToAdd       ← solcat_expected_caps[scId].canonical_expected ∖
 *                     contributed. Caps the LLM thinks an industry-real
 *                     product in this category should provide but no IMDA
 *                     Q from this sol cat backs yet. Sorted: confidence
 *                     desc, then SME-applicable first, then tier+name.
 *
 *   beyondCanonical ← solcat_expected_caps[scId].beyond_canonical. LLM-
 *                     suggested capabilities NOT in our 304 canonical caps.
 *                     Drives future cap-library expansion.
 *
 * Tier filter applies to §1 + §2 (LLM target uses canonical's sme_tier).
 * Size filter is informational (badge), NOT used to drop rows — the user
 * wants enterprise caps visible "for completeness" even though they
 * aren't actionable adds for SME-targeted sol cats.
 */
function buildBuckets(
  data: StakeholdersSummary,
  scId: string,
  tierFilter: TierFilter,
): SolCatBuckets {
  const capsIndex = data.caps_index || [];
  const expansion = data.solcat_expected_caps?.sol_cats?.[scId];
  const hasLlmTarget = !!expansion;

  // Cap-id → caps_index lookup
  const capById = new Map<string, CapEvidence>();
  for (const c of capsIndex) capById.set(c.id, c);

  // ── §1 contributed: caps where this sol cat's Qs are in imda_refs.sources ──
  const contributedQsByCap = new Map<string, string[]>();
  for (const cap of capsIndex) {
    const qs: string[] = [];
    for (const ref of cap.imda_refs || []) {
      if ((ref.sources || []).includes(scId)) qs.push(ref.q_title);
    }
    if (qs.length > 0) contributedQsByCap.set(cap.id, qs);
  }

  const contributed: ContributedCap[] = [];
  for (const [capId, qs] of contributedQsByCap.entries()) {
    const cap = capById.get(capId);
    if (!cap) continue;
    if (!tierPasses(cap.sme_tier, tierFilter)) continue;
    contributed.push({
      cap_id: capId,
      name: cap.name,
      module: cap.module,
      sub_module_name: cap.sub_module_name,
      sme_tier: cap.sme_tier,
      applicability: cap.applicability || [],
      backing_q_titles: qs.slice(0, 5),
    });
  }

  // ── §2 gapsToAdd: LLM canonical_expected ∖ contributed ──
  const contributedIds = new Set(contributed.map(c => c.cap_id));
  const gapsToAdd: GapToAddCap[] = [];
  if (expansion) {
    for (const e of expansion.canonical_expected || []) {
      if (contributedIds.has(e.cap_id)) continue;
      const cap = capById.get(e.cap_id);
      if (!cap) continue;
      if (!tierPasses(cap.sme_tier, tierFilter)) continue;
      gapsToAdd.push({
        cap_id: e.cap_id,
        name: cap.name,
        module: cap.module,
        sub_module_name: cap.sub_module_name,
        sme_tier: cap.sme_tier,
        applicability: cap.applicability || [],
        confidence: e.confidence,
        reason: e.reason,
      });
    }
  }

  // ── §3 beyondCanonical: just pass through LLM list as-is ──
  const beyondCanonical: SolcatExpectedBeyondEntry[] = expansion?.beyond_canonical || [];

  // Sort §1 by tier → module → sub-module → name
  const sortByTierModSm = (
    a: { sme_tier?: string; module: string; sub_module_name?: string | null; name: string },
    b: { sme_tier?: string; module: string; sub_module_name?: string | null; name: string },
  ) => {
    const ta = TIER_RANK[a.sme_tier || "preferred"] ?? 9;
    const tb = TIER_RANK[b.sme_tier || "preferred"] ?? 9;
    if (ta !== tb) return ta - tb;
    if (a.module !== b.module) return a.module.localeCompare(b.module);
    if ((a.sub_module_name || "") !== (b.sub_module_name || "")) {
      return (a.sub_module_name || "").localeCompare(b.sub_module_name || "");
    }
    return a.name.localeCompare(b.name);
  };
  contributed.sort(sortByTierModSm);

  // Sort §2: confidence desc → SME-applicable first → tier/module/sub/name
  gapsToAdd.sort((a, b) => {
    const ca = CONFIDENCE_RANK[a.confidence] ?? 9;
    const cb = CONFIDENCE_RANK[b.confidence] ?? 9;
    if (ca !== cb) return ca - cb;
    const aSme = sizeApplicable(a.applicability);
    const bSme = sizeApplicable(b.applicability);
    if (aSme !== bSme) return aSme ? -1 : 1;
    return sortByTierModSm(a, b);
  });

  return { contributed, gapsToAdd, beyondCanonical, hasLlmTarget };
}
