import { useMemo, useState, useCallback } from "react";

/**
 * Reusable table-sort hook.
 *
 * Pattern (kept deliberately tiny — three lines of state per table):
 *
 *   const { sorted, sortBy, sortDir, setSort } = useTableSort(rows, {
 *     defaultKey: "updated_at",
 *     defaultDir: "desc",
 *     comparators: {
 *       updated_at: (a, b) => a.updated_at.localeCompare(b.updated_at),
 *       author:     (a, b) => (a.author.email || "").localeCompare(b.author.email || ""),
 *     },
 *   });
 *
 * Then in the header cells:
 *   <SortHeader label="Updated" colKey="updated_at" sortBy={sortBy} sortDir={sortDir} onSort={setSort} />
 *
 * Click a column once → asc; click again → desc; click a different column → that
 * column asc (with the previous column's direction reset). Click the active
 * column a third time → returns to the default sort (so users can always get
 * back to the table's natural order).
 */
export type SortDir = "asc" | "desc";

export interface UseTableSortOptions<T, K extends string> {
  defaultKey: K;
  defaultDir?: SortDir;
  /** Per-column ascending comparator. Hook handles desc by negating. */
  comparators: Record<K, (a: T, b: T) => number>;
}

export interface UseTableSortResult<T, K extends string> {
  sorted: T[];
  sortBy: K;
  sortDir: SortDir;
  /** Click handler. Pass the column key the user activated. */
  setSort: (key: K) => void;
  /** True iff (sortBy, sortDir) is the default. Tables can render the
   *  default-state chevron in a muted style. */
  isDefault: boolean;
}

export function useTableSort<T, K extends string>(
  rows: readonly T[],
  options: UseTableSortOptions<T, K>,
): UseTableSortResult<T, K> {
  const { defaultKey, defaultDir = "asc", comparators } = options;
  const [sortBy, setSortBy] = useState<K>(defaultKey);
  const [sortDir, setSortDir] = useState<SortDir>(defaultDir);

  const setSort = useCallback(
    (key: K) => {
      if (key !== sortBy) {
        setSortBy(key);
        setSortDir("asc");
        return;
      }
      // Third click on the active column → reset to default.
      if (sortDir === "desc") {
        setSortBy(defaultKey);
        setSortDir(defaultDir);
        return;
      }
      setSortDir("desc");
    },
    [sortBy, sortDir, defaultKey, defaultDir],
  );

  const sorted = useMemo(() => {
    const cmp = comparators[sortBy];
    if (!cmp) return [...rows];
    const out = [...rows].sort(cmp);
    return sortDir === "desc" ? out.reverse() : out;
  }, [rows, sortBy, sortDir, comparators]);

  const isDefault = sortBy === defaultKey && sortDir === defaultDir;

  return { sorted, sortBy, sortDir, setSort, isDefault };
}
