/** Loader + types for the unified PSG vendor pricing JSON.
 *
 * Source file: `data/external/psg_vendor_pricing.json`, built by
 * `scripts/build_psg_vendor_pricing.py`. Re-runnable, no LLM cost — just
 * aggregates psg-solutions.json + vendor_pricing/extracted/*.yaml +
 * psg_category_crosswalk.yaml.
 *
 * Coverage today (2026-05-12):
 *   - Package-level pricing (totalCost / qualifyingCost / estimatedNetCost):
 *     all 414 PSG vendors, from the GoBusiness directory's raw export.
 *   - Detailed tier + feature breakdown: ~15 benchmark vendors so far
 *     (Haiku-parsed from vendor websites and PSG submission PDFs).
 *   - Non-PSG benchmark vendors (NetSuite, Salesforce, Workday, etc.) are
 *     included under "benchmark:<vendor_id>" IDs for reference comparison.
 *
 * Phase 1-4 expansion: more vendors get detail layer when their PSG PDFs are
 * fetched (`scripts/fetch_psg_pdfs.py`) and parsed (`scripts/parse_psg_pdfs.py`).
 * Re-run the aggregator after either.
 */

const BASE_URL = (import.meta.env.BASE_URL || "/").replace(/\/+$/, "/");

export interface PricingPackage {
  name: string;
  total_cost_raw: string | null;
  total_cost_sgd: number | null;
  qualifying_cost_raw: string | null;
  qualifying_cost_sgd: number | null;
  net_cost_raw: string | null;
  net_cost_sgd: number | null;
  raw: Record<string, unknown>;
}

export interface PricingDetailPlan {
  name?: string;
  price?: {
    amount?: number;
    currency?: string;
    unit?: string;
    source_phrase?: string;
  };
  included_features?: { text: string; source_phrase?: string }[];
  add_on_features?: { text: string; source_phrase?: string }[];
}

export interface PricingDetail {
  vendor_id: string;
  fetched_from: string | null;
  extracted_at: string | null;
  model: string | null;
  plans: PricingDetailPlan[];
  psg_pdf_extracts?: unknown[];
  notes?: string | null;
}

export interface PricingVendor {
  psg_id: string | null;
  benchmark_id?: string;
  vendor_name: string | null;
  solution_name: string | null;
  category: string | null;
  sector: string | null;
  description: string | null;
  psg_url: string | null;
  vendor_url: string | null;
  vendor_phone?: string | null;
  vendor_email?: string | null;
  payment_mode: string | null;
  psg_support_pct_raw: string | null;
  packages: PricingPackage[];
  excluded_from_erp: boolean;
  exclusion_reason: string | null;
  modules: string[];
  families: { module: string; family: string }[];
  detail?: PricingDetail;
  /** Non-PSG benchmark vendors carry vendor_type/tier + pricing_status. */
  vendor_type?: string;
  vendor_tier?: string;
  pricing_status?: string;
  currency?: string;
  notes?: string;
}

export interface PricingCategoryIndex {
  modules: string[];
  families: { module: string; family: string }[];
  excluded: boolean;
  exclusion_reason: string | null;
  vendor_ids: string[];
}

export interface PricingModuleIndex {
  vendor_count: number;
  vendor_ids: string[];
}

export interface PricingPayload {
  _meta: {
    generated_by: string;
    generated_at: string;
    summary_count: number;
    detailed_count: number;
    non_psg_benchmark_count: number;
    total_vendor_entries: number;
    category_count: number;
    module_count: number;
  };
  vendors: Record<string, PricingVendor>;
  by_category: Record<string, PricingCategoryIndex>;
  by_module: Record<string, PricingModuleIndex>;
}

let cache: PricingPayload | null = null;
let inflight: Promise<PricingPayload> | null = null;

export async function loadPricingPayload(): Promise<PricingPayload> {
  if (cache) return cache;
  if (inflight) return inflight;
  const url = `${BASE_URL}psg_vendor_pricing.json`;
  inflight = fetch(url, { cache: "no-store" })
    .then(r => {
      if (!r.ok) throw new Error(`HTTP ${r.status} fetching ${url}`);
      return r.json() as Promise<PricingPayload>;
    })
    .then(d => { cache = d; inflight = null; return d; });
  return inflight;
}

/** Convenience: vendors for a given PSG category (sol-cat-ish bucket).
 *  Falls back to empty list when the category isn't indexed. */
export function vendorsForCategory(
  payload: PricingPayload,
  category: string,
): PricingVendor[] {
  const idx = payload.by_category[category];
  if (!idx) return [];
  return idx.vendor_ids
    .map(id => payload.vendors[id])
    .filter((v): v is PricingVendor => !!v);
}

/** Convenience: vendors for a given canonical module slug. */
export function vendorsForModule(
  payload: PricingPayload,
  moduleSlug: string,
): PricingVendor[] {
  const idx = payload.by_module[moduleSlug];
  if (!idx) return [];
  return idx.vendor_ids
    .map(id => payload.vendors[id])
    .filter((v): v is PricingVendor => !!v);
}

/** Lowest-package total cost in SGD across a vendor's packages.
 *  Returns null when none of the packages have a parseable price. */
export function lowestTotalCostSgd(v: PricingVendor): number | null {
  const prices = v.packages
    .map(p => p.total_cost_sgd)
    .filter((n): n is number => typeof n === "number");
  if (!prices.length) return null;
  return Math.min(...prices);
}

/** Highest-package total cost in SGD across a vendor's packages. */
export function highestTotalCostSgd(v: PricingVendor): number | null {
  const prices = v.packages
    .map(p => p.total_cost_sgd)
    .filter((n): n is number => typeof n === "number");
  if (!prices.length) return null;
  return Math.max(...prices);
}

/** Human-readable module label. Mirrors the labels used in canonical viewers. */
export const MODULE_LABEL: Record<string, string> = {
  financial_management: "Financial Management",
  sales_and_crm: "Sales & CRM",
  human_resources_management: "Human Resources",
  supply_chain_and_inventory: "Supply Chain & Inventory",
  manufacturing_management: "Manufacturing",
  asset_management: "Asset Management",
  field_service_management: "Field Service Management",
  fleet_management: "Fleet Management",
  project_management: "Project Management",
  others: "Platform & Data",
};

export function moduleLabel(slug: string): string {
  return MODULE_LABEL[slug] || slug;
}
